-- Schema for Domain: processing | Business: Mining | Version: v1_mvm
-- Generated on: 2026-05-05 14:20:17

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `mining_ecm`.`processing` COMMENT 'Covers all mineral processing and beneficiation activities from comminution (SAG, HPGR) through separation (DMS, flotation, leaching, SX-EW) to concentrate production. Tracks recovery rates, slurry parameters, reagent consumption, throughput, and product grade against LOM plan targets.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`plant` (
    `plant_id` BIGINT COMMENT 'Unique surrogate identifier for the mineral processing plant facility. Primary key for the processing_plant master register. SSOT for all processing facility master data.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Processing plants are designed and optimized for specific commodities (iron ore, copper, coal). Essential for production planning, capacity allocation, JORC resource reporting, and LOM planning. Domai',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Every processing plant operates under a cost centre for opex tracking, AISC reporting, and variance analysis. processing_plant.opex_cost_centre (plain attr) is denormalized cost_centre_code; replace w',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking to hse.emergency_response_plan. Business justification: Processing plants must maintain site-specific emergency response plans (fire, chemical spill, structural failure) under mining safety legislation. A mining HSE manager expects plant.emergency_response',
    `environmental_permit_id` BIGINT COMMENT 'Foreign key linking to hse.environmental_permit. Business justification: Processing plants operate under environmental permits governing air emissions, water discharge, and tailings management. Regulatory compliance tracking requires direct linkage between plant operations',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Plants send routine process control samples (shift composites, circuit optimization samples) to designated laboratories for analysis. Tracks primary lab relationship for turnaround management and meta',
    `mine_site_id` BIGINT COMMENT 'Reference to the mine site or operational location where this processing plant is physically situated. Links the plant to its geographic and operational context.',
    `profit_centre_id` BIGINT COMMENT 'Foreign key linking to finance.profit_centre. Business justification: Plants are profit-generating entities assigned to profit centres in SAP/ERP for segment P&L reporting, AISC disclosure, and investor reporting. A mining finance expert would expect every plant to have',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Each processing plant is designed and operated to produce a specific saleable product (e.g., copper cathode, iron ore fines). Plant design parameters and production reporting are anchored to the salea',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Each plant is designed and operated to produce output meeting a specific product specification. Plant design parameters (nameplate_recovery_rate_pct, feed_grade_design_pct) are set against a specifica',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Processing plants operate under granted mining licences on specific tenements. Required for regulatory compliance reporting, expenditure commitment tracking, and operational boundary verification. Eve',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Plant capital expenditure is tracked via WBS elements for project accounting and asset capitalization. processing_plant.capex_wbs_element (plain attr) is denormalized WBS code; replace with FK for cap',
    `aisc_benchmark_usd_per_t` DECIMAL(18,2) COMMENT 'The budgeted or benchmark All-In Sustaining Cost (AISC) for processing at this plant expressed in USD per dry metric tonne of ore processed. Used as the financial performance baseline for C1 cash cost reporting and LOM plan economics.',
    `annual_capacity_mt` DECIMAL(18,2) COMMENT 'Nameplate annual throughput capacity expressed in million dry metric tonnes per annum (Mtpa). Derived from design_capacity_tph and planned operating hours but stored as a master data attribute for LOM plan alignment and regulatory resource reporting.',
    `care_maintenance_date` DATE COMMENT 'The date on which the plant was placed into care-and-maintenance status. Null if the plant has never been placed on care-and-maintenance. Used for OPEX tracking, insurance, and regulatory compliance reporting.',
    `comminution_technology` STRING COMMENT 'Primary size-reduction (comminution) technology installed in the plant. SAG (Semi-Autogenous Grinding), HPGR (High Pressure Grinding Rolls), ball mill, rod mill, crusher, AG (Autogenous Grinding), or combined circuit. Drives energy consumption benchmarking and maintenance planning. [ENUM-REF-CANDIDATE: SAG|HPGR|ball_mill|rod_mill|crusher|AG|combined — 7 candidates stripped; promote to reference product]',
    `commissioned_date` DATE COMMENT 'The date on which the processing plant was formally commissioned and accepted into commercial production. Used for asset depreciation calculations (IFRS 16), LOM plan baseline, and regulatory reporting of production commencement.',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code of the jurisdiction in which the processing plant is located (e.g., AUS, CHL, ZAF, CAN). Determines applicable regulatory frameworks (JORC, NI 43-101, SAMREC, MSHA) and environmental reporting obligations.. Valid values are `^[A-Z]{3}$`',
    `decommissioned_date` DATE COMMENT 'The date on which the plant was permanently decommissioned and removed from the active asset register. Null if the plant is still operational or on care-and-maintenance. Triggers mine rehabilitation and closure obligations.',
    `design_capacity_tph` DECIMAL(18,2) COMMENT 'Nameplate design throughput capacity of the plant expressed in dry metric tonnes per hour (tph) of Run of Mine (ROM) feed. Represents the engineering-rated maximum throughput under optimal conditions. Used as the denominator for OEE (Overall Equipment Effectiveness) calculations.',
    `elevation_masl` DECIMAL(18,2) COMMENT 'Elevation of the processing plant site in metres above sea level (mASL). Relevant for water balance modelling, slurry pipeline hydraulics design, and environmental impact assessments.',
    `feed_grade_design_pct` DECIMAL(18,2) COMMENT 'Design ROM feed head grade (percentage of valuable mineral in the feed ore) for which the plant was engineered. Used as the baseline for metallurgical balance calculations, cut-off grade assessments, and LOM plan modelling.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude of the processing plant centroid in decimal degrees (WGS84 datum). Used for GIS (Geographic Information System) mapping, spatial analysis, and environmental impact zone delineation.',
    `lims_plant_code` STRING COMMENT 'The plant identifier used in the LabWare LIMS (Laboratory Information Management System) for sample registration, assay result linkage, and metallurgical accounting. Enables traceability from plant feed to product assay.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude of the processing plant centroid in decimal degrees (WGS84 datum). Used for GIS mapping, spatial analysis, and environmental impact zone delineation.',
    `nameplate_recovery_rate_pct` DECIMAL(18,2) COMMENT 'Design-rated metallurgical recovery rate expressed as a percentage (0–100). Represents the percentage of the target valuable mineral in the feed that is expected to report to the concentrate or product stream under nameplate conditions. Key input to LOM plan financial modelling and JORC/NI 43-101 resource estimation.',
    `number_of_processing_lines` STRING COMMENT 'Total count of parallel processing lines (circuits) within the plant. Each line represents an independent processing train capable of treating ore from feed to product. Drives capacity planning, maintenance scheduling, and redundancy analysis.',
    `operational_status` STRING COMMENT 'Current lifecycle state of the processing plant. active = fully operational; care-and-maintenance = temporarily idle but preserved; decommissioned = permanently closed; commissioning = in start-up phase; suspended = temporarily halted due to regulatory or operational reasons.. Valid values are `active|care-and-maintenance|decommissioned|commissioning|suspended`',
    `ore_type_compatibility` STRING COMMENT 'Comma-separated list of ore/commodity types this plant is designed and certified to process (e.g., iron ore, copper, gold, lithium, nickel, coal, diamonds). Drives feed stream routing and LOM plan alignment. [ENUM-REF-CANDIDATE: iron ore|copper|gold|lithium|nickel|coal|diamonds|zinc|lead|manganese — promote to reference product]',
    `plant_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the processing plant, used across ERP, SCADA, and FMS systems (e.g., PP-PILBARA-01, PROC-CU-02). Unique across the enterprise and referenced in operational reporting.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `plant_description` STRING COMMENT 'Free-text narrative description of the processing plant including key design features, processing circuit configuration, historical context, and any notable operational characteristics. Supports regulatory submissions, investor reports, and technical documentation.',
    `plant_name` STRING COMMENT 'Full human-readable name of the mineral processing plant facility (e.g., Pilbara Iron Ore Processing Plant 1, Olympic Dam Copper Concentrator). Used in reports, dashboards, and regulatory submissions.',
    `plant_type` STRING COMMENT 'High-level classification of the processing plant by metallurgical process family. concentrator = physical separation to produce mineral concentrate; hydrometallurgical = chemical leaching/SX-EW; pyrometallurgical = smelting/roasting; beneficiation = upgrading without full extraction; refinery = final product refining; pelletising = iron ore pellet production.. Valid values are `concentrator|hydrometallurgical|pyrometallurgical|beneficiation|refinery|pelletising`',
    `power_consumption_design_kw` DECIMAL(18,2) COMMENT 'Nameplate design electrical power consumption in kilowatts (kW) at full throughput. Used for energy cost modelling (OPEX), carbon footprint reporting (GRI Mining and Metals Sector Supplement), and grid capacity planning.',
    `primary_processing_method` STRING COMMENT 'The principal mineral processing and beneficiation method employed by this plant. Comminution includes SAG/HPGR milling; flotation covers froth flotation separation; leaching includes heap and tank leaching; SX-EW (Solvent Extraction Electrowinning) for copper cathode production; DMS (Dense Media Separation) for coal/diamonds; gravity and magnetic separation for iron ore. [ENUM-REF-CANDIDATE: comminution|flotation|leaching|SX-EW|DMS|gravity|magnetic — 7 candidates stripped; promote to reference product]',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp when this processing plant master record was first created in the data platform (Silver Layer). Supports data lineage, audit trail, and regulatory record-keeping obligations.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this processing plant master record was last modified in the data platform. Supports change tracking, data quality monitoring, and audit compliance.',
    `sap_functional_location` STRING COMMENT 'The SAP S/4HANA Plant Maintenance (PM) functional location code assigned to this processing plant. Enables linkage to maintenance work orders, preventive maintenance plans, and CAPEX/OPEX cost centre reporting in SAP.',
    `scada_system_code` STRING COMMENT 'The identifier of the SCADA (Supervisory Control and Data Acquisition) system instance or node that monitors and controls this processing plant. Used to link real-time process historian data (OSIsoft PI System) to the plant master record.',
    `state_province` STRING COMMENT 'State, province, or territory in which the processing plant is located (e.g., Western Australia, British Columbia, Antofagasta). Used for jurisdictional regulatory compliance, environmental permitting, and geographic reporting.',
    `tailings_generation_design_tph` DECIMAL(18,2) COMMENT 'Nameplate design rate of tailings (gangue and process residue) generated by the plant in dry metric tonnes per hour. Drives TSF (Tailings Storage Facility) capacity planning, environmental licence conditions, and ICMM tailings governance compliance.',
    `water_consumption_design_m3ph` DECIMAL(18,2) COMMENT 'Nameplate design water consumption rate in cubic metres per hour (m³/h) for the plant under full throughput conditions. Critical for water balance management, environmental licence compliance, and EIS (Environmental Impact Statement) reporting.',
    CONSTRAINT pk_plant PRIMARY KEY(`plant_id`)
) COMMENT 'Master register of all mineral processing plant facilities. Captures plant identity, site location, design capacity (tph), commissioned date, primary processing method (comminution, flotation, leaching, SX-EW, DMS, gravity, magnetic), ore type compatibility (iron ore, copper, gold, lithium, nickel, coal, diamonds), operational status (active, care-and-maintenance, decommissioned), number of processing lines, and nameplate recovery rate. SSOT for all processing facility master data. Parent entity for circuits, feed streams, and all operational records.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`circuit` (
    `circuit_id` BIGINT COMMENT 'Unique surrogate identifier for a processing circuit record within the mineral processing plant. Primary key for the processing_circuit data product.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Circuits are engineered for specific commodities with tailored flowsheets and reagent schemes. Critical for metallurgical accounting, recovery optimization, and circuit performance reporting. Replaces',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Individual processing circuits (rougher, cleaner, leach) are discrete cost objects in mining operations. Circuit-level cost centre assignment enables granular AISC/C1 cost reporting and variance analy',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking to hse.emergency_response_plan. Business justification: Specific circuits (cyanide leach, acid circuits) require dedicated emergency response plans under ICMC and national chemical safety regulations, distinct from the plant-level plan. Mining HSE managers',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: Circuits are maintainable functional locations within plant hierarchy. Maintenance strategies, PM schedules, and work orders are assigned to circuit-level functional locations for granular maintenance',
    `geological_domain_id` BIGINT COMMENT 'Foreign key linking to geology.geological_domain. Business justification: Processing circuits are designed and configured for specific geological domains — oxide circuits differ fundamentally from sulphide circuits in reagent_scheme_code, design_ph_target, and target_recove',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Each processing circuit is assigned a primary laboratory for routine process control assays (head grade, concentrate grade, tailings grade). Metallurgical accounting and circuit performance reporting ',
    `lom_plan_id` BIGINT COMMENT 'Reference to the Life of Mine (LOM) plan under which this circuits design parameters and recovery targets were established. Enables traceability of circuit design basis to the governing mine plan.',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant in which this circuit operates. Links circuit-level data to plant-level operational context.',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Each processing circuit is configured to produce a specific saleable product. Circuit performance reporting, reagent schemes, and design parameters are set based on the saleable product requirements. ',
    `sample_program_id` BIGINT COMMENT 'Foreign key linking to laboratory.sample_program. Business justification: Each processing circuit operates under a defined sample program specifying sampling points, frequency, and analytical suite for metallurgical accounting and process control. This is a fundamental oper',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Each circuit is designed to produce output meeting a specific product specification. Circuit design parameters (target_product_grade_pct, target_recovery_rate_pct) are derived from the specification. ',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Processing circuit design specifies which TSF receives its tailings output — a fundamental environmental permit and water balance requirement. Metallurgical engineers and environmental teams must know',
    `upstream_circuit_id` BIGINT COMMENT 'Self-referencing FK on circuit (upstream_circuit_id)',
    `circuit_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the processing circuit within the plant flowsheet (e.g., PC-SAG-01, FL-RGH-02). Used in P&ID documentation, SCADA tags, and operational reporting.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `circuit_description` STRING COMMENT 'Free-text description of the processing circuit including its role in the plant flowsheet, key equipment, and any notable design features or operational constraints. Supports engineering documentation and onboarding.',
    `circuit_name` STRING COMMENT 'Human-readable descriptive name of the processing circuit (e.g., Primary SAG Mill Circuit, Rougher Flotation Circuit, Leach Circuit 1). Used in operational dashboards and reporting.',
    `circuit_status` STRING COMMENT 'Current operational lifecycle status of the processing circuit. Drives scheduling, maintenance planning, and production reporting inclusion/exclusion.. Valid values are `active|inactive|commissioning|decommissioned|standby`',
    `circuit_type` STRING COMMENT 'Category of mineral processing technology employed in this circuit. Drives applicable KPIs, reagent profiles, and recovery benchmarks. [ENUM-REF-CANDIDATE: comminution|flotation|leaching|gravity_separation|dense_media_separation|sx_ew|thickening|filtration|classification — promote to reference product]',
    `commissioning_date` DATE COMMENT 'Date on which the processing circuit was formally commissioned and accepted into operational service. Used for asset age calculations, warranty tracking, and depreciation under IFRS.',
    `decommissioning_date` DATE COMMENT 'Date on which the processing circuit was or is planned to be permanently decommissioned. Nullable for active circuits. Used for mine closure planning, asset write-off scheduling, and rehabilitation cost provisioning.',
    `design_availability_pct` DECIMAL(18,2) COMMENT 'Design basis mechanical availability of the circuit expressed as a percentage of scheduled operating hours. Used as the denominator in OEE calculations and production planning. Derived from MTBF and MTTR estimates at design stage.',
    `design_feed_size_p80_mm` DECIMAL(18,2) COMMENT 'Design basis P80 particle size of the feed material entering this circuit in millimetres. P80 represents the 80th percentile passing size. Critical for comminution circuit design and mill sizing.',
    `design_ph_target` DECIMAL(18,2) COMMENT 'Design basis target pH value for the circuit process stream. Applicable to flotation (pH control for selectivity), leaching (acid/alkaline conditions), and SX-EW circuits. Drives lime/acid reagent consumption.',
    `design_product_size_p80_mm` DECIMAL(18,2) COMMENT 'Design basis P80 particle size of the product leaving this circuit in millimetres. Defines the target grind size for comminution circuits and classification efficiency for downstream separation circuits.',
    `design_residence_time_min` DECIMAL(18,2) COMMENT 'Design basis residence time of material within the circuit expressed in minutes. Determines tank/vessel sizing and is a key parameter for leach kinetics, flotation recovery, and thickener design.',
    `design_slurry_density_pct` DECIMAL(18,2) COMMENT 'Design basis slurry density expressed as percentage solids by weight for circuits handling slurry streams. Critical for pump sizing, pipe design, and process control setpoints.',
    `design_throughput_mtpa` DECIMAL(18,2) COMMENT 'Annualised nameplate design throughput capacity expressed in million dry metric tonnes per annum (Mtpa). Used for LOM plan alignment, capital project justification, and annual production reporting.',
    `design_throughput_tph` DECIMAL(18,2) COMMENT 'Nameplate design throughput capacity of the circuit expressed in dry metric tonnes per hour (tph). Represents the engineering design basis used for LOM plan benchmarking and OEE calculations.',
    `design_utilisation_pct` DECIMAL(18,2) COMMENT 'Design basis utilisation rate of the circuit expressed as a percentage of available hours actually used for production. Combined with availability to derive OEE. Accounts for planned feed interruptions and scheduled downtime.',
    `design_water_consumption_m3pt` DECIMAL(18,2) COMMENT 'Design basis fresh water consumption rate for this circuit expressed in cubic metres per dry metric tonne of feed processed. Used for water balance modelling, environmental licence compliance, and OPEX planning.',
    `effective_from_date` DATE COMMENT 'Date from which the current circuit configuration, design parameters, and targets are effective. Supports slowly changing dimension (SCD) management and historical performance benchmarking against the correct design basis.',
    `effective_to_date` DATE COMMENT 'Date until which the current circuit configuration and design parameters are effective. Null for the current active version. Enables historical tracking of circuit design changes and target revisions over the LOM.',
    `environmental_permit_number` STRING COMMENT 'Reference number of the environmental operating permit or licence governing this circuits operations (e.g., water use licence, air emission permit). Required for regulatory compliance reporting under ISO 14001 and EIS obligations.',
    `feed_material_type` STRING COMMENT 'Classification of the primary feed material entering this circuit (e.g., ROM Ore for primary comminution, slurry for flotation). Determines applicable feed quality parameters and circuit design basis. [ENUM-REF-CANDIDATE: rom_ore|crushed_ore|ground_ore|concentrate|slurry|leach_solution|tailings|recycled_stream — 8 candidates stripped; promote to reference product]',
    `flowsheet_sequence_order` STRING COMMENT 'Integer position of this circuit within the overall plant processing flowsheet. Defines the order of material flow from feed preparation through to final product, enabling flowsheet visualisation and mass balance calculations.',
    `installed_power_kw` DECIMAL(18,2) COMMENT 'Total installed electrical power capacity of the circuit in kilowatts (kW). Used for energy consumption benchmarking, OPEX modelling, and specific energy intensity calculations (kWh/t).',
    `is_primary_circuit` BOOLEAN COMMENT 'Indicates whether this circuit is the primary (first-pass) processing circuit in the plant flowsheet as opposed to a secondary, scavenger, or retreatment circuit. Used for production reporting hierarchy and mass balance prioritisation.',
    `number_of_units` STRING COMMENT 'Count of parallel processing units (e.g., mills, flotation cells, leach tanks) operating within this circuit. Used for availability calculations, maintenance scheduling, and throughput modelling.',
    `pi_af_element_path` STRING COMMENT 'Full Asset Framework (AF) element path in the OSIsoft PI System for this processing circuit (e.g., ServerPlantMillCircuitSAG01). Enables direct linkage between the data product and real-time process historian data.',
    `reagent_scheme_code` STRING COMMENT 'Code identifying the standard reagent addition scheme applied in this circuit (e.g., collector, frother, pH modifier for flotation; acid type for leaching). Links to reagent consumption planning and OPEX budgeting.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this processing circuit record was first created in the system. Used for audit trail, data lineage, and Silver layer ingestion tracking.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this processing circuit record was last modified. Used for change detection, incremental data loading, and audit compliance in the Databricks Silver layer.',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the process engineer accountable for the design, optimisation, and performance of this circuit. Used for accountability tracking and escalation routing.',
    `scada_tag_prefix` STRING COMMENT 'Root tag prefix used in the SCADA/DCS system (OSIsoft PI) to identify all process data points associated with this circuit (e.g., PLANT1.SAG01). Enables automated data ingestion from the PI historian into the lakehouse.. Valid values are `^[A-Z0-9_.-]{2,30}$`',
    `subtype` STRING COMMENT 'Specific processing sub-type within the circuit type category (e.g., SAG Mill under comminution, Rougher under flotation, CIL under leaching). Enables granular performance benchmarking. [ENUM-REF-CANDIDATE: sag_mill|ball_mill|hpgr|rod_mill|rougher|scavenger|cleaner|recleaner|heap_leach|vat_leach|cil|cip|dms|jig|spiral|electrowinning|solvent_extraction — promote to reference product]',
    `target_feed_grade_pct` DECIMAL(18,2) COMMENT 'LOM plan target head grade of the feed material entering this circuit expressed as a percentage of the primary commodity. Used for cut-off grade optimisation and circuit performance benchmarking.',
    `target_recovery_rate_pct` DECIMAL(18,2) COMMENT 'LOM plan target metallurgical recovery rate for the primary commodity expressed as a percentage (e.g., 87.500 for 87.5%). Represents the expected proportion of valuable mineral extracted relative to feed grade. Basis for reserve reporting under JORC/CIM.',
    CONSTRAINT pk_circuit PRIMARY KEY(`circuit_id`)
) COMMENT 'Defines individual processing circuits within a plant (e.g., primary comminution, secondary grinding, rougher flotation, cleaner flotation, leach circuit, SX-EW circuit). Captures circuit type, feed material, design throughput, target recovery rate, and sequence order within the processing flowsheet. Enables circuit-level performance tracking.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`feed_stream` (
    `feed_stream_id` BIGINT COMMENT 'Unique surrogate identifier for each ore feed stream record entering the processing plant. Primary key for the feed_stream data product.',
    `asset_id` BIGINT COMMENT 'Reference identifier for the primary conveyor or feeder equipment delivering material to this feed stream. Links to the equipment asset register for maintenance scheduling and OEE (Overall Equipment Effectiveness) tracking.',
    `circuit_id` BIGINT COMMENT 'Reference identifier for the specific processing circuit (e.g., SAG/Ball Mill circuit, DMS circuit, flotation circuit) that this feed stream feeds into. Enables circuit-level mass balance and throughput analysis.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Feed streams carry specific commodities from mine to plant. Fundamental for grade control, blending decisions, and feed scheduling. Replaces denormalized commodity text field with proper FK for refere',
    `geological_domain_id` BIGINT COMMENT 'Foreign key linking to geology.geological_domain. Business justification: Feed blend optimisation and metallurgical prediction require knowing which geological domain material is being fed. Metallurgists set head_grade_pct, processing_route, and ore_type targets per geologi',
    `lom_plan_id` BIGINT COMMENT 'Reference identifier for the LOM (Life of Mine) plan version that defines the target feed parameters for this stream. Enables variance analysis between planned and actual feed characteristics for production reconciliation.',
    `ore_reserve_id` BIGINT COMMENT 'Foreign key linking to exploration.ore_reserve. Business justification: Feed stream design parameters (head grade, cut-off grade, ore type, throughput) are directly derived from the ore reserve classification. LOM feed scheduling and mill feed blend optimisation require t',
    `orebody_id` BIGINT COMMENT 'Foreign key linking to geology.orebody. Business justification: Feed streams originate from specific orebodies. Mine-to-mill optimization and metallurgical reconciliation require tracking which orebody supplies each feed stream to correlate geological characterist',
    `plant_id` BIGINT COMMENT 'Reference identifier for the mineral processing plant or facility that this feed stream supplies. Supports multi-plant operations and mass balance reporting at plant level.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Feed streams must reference production schedules to track which mine production periods feed which processing campaigns. Essential for ore type scheduling, blend optimization, and integrated mine-mill',
    `prospect_id` BIGINT COMMENT 'Foreign key linking to exploration.prospect. Business justification: Feed streams originate from specific prospects/orebodies. Critical for mine-to-mill optimization, ore tracking, metallurgical reconciliation, and LOM planning. Real business need: tracking ore source ',
    `rom_stockpile_id` BIGINT COMMENT 'Reference identifier for the specific physical source location (ROM pad, stockpile, crusher station) from which this feed stream originates. Links to the plant location or stockpile master.',
    `sample_program_id` BIGINT COMMENT 'Foreign key linking to laboratory.sample_program. Business justification: Feed streams are sampled under a defined sample program governing sampling protocol, frequency, and analytical suite for metallurgical accounting. Knowing which sample program applies to each feed str',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Feed streams originate from ore extracted from specific tenements. Essential for royalty calculations, grade reconciliation against tenement reserves, and compliance with tenement-specific production ',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Feed streams are configured to meet a target product specification (grade, particle size, moisture). Process engineers reference the specification when setting feed stream design parameters. Metallurg',
    `abrasion_index` DECIMAL(18,2) COMMENT 'Bond Abrasion Index (Ai) of the ore in the feed stream, a dimensionless measure of ore abrasiveness. Drives liner and media wear rate predictions for SAG mills, ball mills, and HPGR (High Pressure Grinding Rolls), informing maintenance scheduling and OPEX forecasting.',
    `bond_work_index_kwh_t` DECIMAL(18,2) COMMENT 'Bond Ball Mill Work Index (BWi) of the ore expressed in kilowatt-hours per tonne (kWh/t). Measures ore hardness and grindability; used to predict mill power requirements, throughput, and energy consumption in comminution circuit design and optimisation.',
    `bulk_density_t_m3` DECIMAL(18,2) COMMENT 'Bulk density of the ore material in the feed stream expressed in tonnes per cubic metre (t/m³). Used to convert volumetric flow measurements to mass flow for mass balance calculations and stockpile volume reconciliation.',
    `commissioned_date` DATE COMMENT 'The date on which this feed stream was formally commissioned and accepted into operational service. Used for asset lifecycle tracking, warranty management, and CAPEX (Capital Expenditure) project closure reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this feed stream record was first created in the system. Provides audit trail for data lineage and record provenance in the Databricks Silver Layer.',
    `cut_off_grade_pct` DECIMAL(18,2) COMMENT 'The minimum economic grade threshold (cut-off grade) applied to material entering this feed stream. Material below cut-off grade is classified as waste and diverted to the waste dump. Defined per LOM plan and commodity economics.',
    `design_capacity_tph` DECIMAL(18,2) COMMENT 'Maximum rated throughput capacity of the feed stream infrastructure (conveyor, feeder, chute) in dry metric tonnes per hour. Used for bottleneck analysis and OEE (Overall Equipment Effectiveness) calculations.',
    `dilution_pct` DECIMAL(18,2) COMMENT 'Percentage of waste material mixed with ore in the feed stream due to mining dilution. Dilution reduces the effective head grade and is tracked for reconciliation between geological resource model grades and actual plant feed grades.',
    `effective_from` DATE COMMENT 'The date from which this feed stream definition and its associated parameters (nominal rate, target grade, processing route) became operationally effective. Supports temporal versioning of feed stream configurations aligned to LOM plan revisions.',
    `effective_until` DATE COMMENT 'The date on which this feed stream definition ceases to be operationally effective. Null indicates the stream is currently active with no planned end date. Supports LOM plan stage transitions and plant reconfiguration tracking.',
    `feed_temperature_c` DECIMAL(18,2) COMMENT 'Temperature of the ore or slurry in the feed stream measured in degrees Celsius. Relevant for leaching circuits (SX-EW), autoclave operations, and cold-climate operations where freezing affects conveyor and crusher performance.',
    `gangue_content_pct` DECIMAL(18,2) COMMENT 'Percentage of waste rock (gangue) minerals in the feed stream material. High gangue content increases dilution, reduces effective head grade, and impacts reagent consumption in flotation and leaching circuits.',
    `head_grade_pct` DECIMAL(18,2) COMMENT 'The assay-determined grade of the primary valuable mineral in the feed stream expressed as a percentage (e.g., % Fe for iron ore, % Cu for copper). Head grade is the key input for recovery rate calculations and production reconciliation against the LOM plan.',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content of the ore in the feed stream expressed as a percentage of total wet mass. Moisture affects conveyor performance, crusher throughput, mill power draw, and dry tonne calculations for mass balance and invoicing.',
    `nominal_feed_rate_tph` DECIMAL(18,2) COMMENT 'The design or nameplate feed rate for this stream expressed in dry metric tonnes per hour (tph). Represents the target throughput capacity used in LOM (Life of Mine) plan scheduling and plant design. Distinct from actual measured feed rate.',
    `ore_type` STRING COMMENT 'Geological ore type classification of the material in this feed stream (e.g., oxide, sulphide, transitional, fresh, weathered). Ore type drives processing route selection, reagent dosing, and expected recovery rates. [ENUM-REF-CANDIDATE: oxide|sulphide|transitional|fresh|weathered|mixed|high_grade|low_grade — promote to reference product]',
    `p50_particle_size_mm` DECIMAL(18,2) COMMENT 'The 50th percentile (median) passing particle size of the feed stream material in millimetres. Complements P80 to characterise the full particle size distribution (PSD) shape, supporting comminution circuit modelling and screen efficiency analysis.',
    `p80_particle_size_mm` DECIMAL(18,2) COMMENT 'The 80th percentile passing particle size of the feed stream material expressed in millimetres (mm). P80 is the industry-standard metric for characterising particle size distribution (PSD) in comminution circuits. Critical input for SAG mill and HPGR (High Pressure Grinding Rolls) performance modelling.',
    `pi_tag_feed_rate` DECIMAL(18,2) COMMENT 'The OSIsoft PI System historian tag name for the real-time feed rate measurement instrument (belt scale or flow meter) associated with this feed stream. Enables direct linkage between the data product and the SCADA/PI process historian for real-time and historical data retrieval.',
    `pi_tag_particle_size` STRING COMMENT 'The OSIsoft PI System historian tag name for the online particle size analyser (PSA) instrument monitoring P80 for this feed stream. Supports real-time comminution circuit control and automated variance alerting.. Valid values are `^[A-Z0-9._-]{3,50}$`',
    `processing_route` STRING COMMENT 'The designated mineral processing route for material in this feed stream (e.g., SAG/Ball Mill comminution, DMS (Dense Media Separation), flotation, leaching, SX-EW (Solvent Extraction Electrowinning)). Determines downstream circuit routing and reagent requirements. [ENUM-REF-CANDIDATE: sag_ball_mill|hpgr|dms|flotation|leaching|sx_ew|gravity|magnetic_separation|cil|cip — promote to reference product]',
    `slurry_density_t_m3` DECIMAL(18,2) COMMENT 'Density of the ore-water slurry mixture in the feed stream expressed in tonnes per cubic metre. Applicable to wet processing circuits (SAG mill discharge, flotation feed). Monitored via OSIsoft PI System for real-time process control.',
    `slurry_solids_pct` DECIMAL(18,2) COMMENT 'Percentage of solids by mass in the slurry feed stream (percent solids). A key process control parameter for wet grinding and flotation circuits; directly affects mill power draw, pump performance, and flotation cell residence time.',
    `source_type` STRING COMMENT 'Classification of the physical origin point from which ore material enters this feed stream. ROM (Run of Mine) pad indicates direct truck tip; stockpile indicates reclaimed material; crusher indicates post-comminution feed. [ENUM-REF-CANDIDATE: rom_pad|primary_crusher|secondary_crusher|tertiary_crusher|stockpile|reclaim_conveyor|direct_tip|sag_discharge — promote to reference product]. Valid values are `rom_pad|primary_crusher|secondary_crusher|stockpile|reclaim_conveyor|direct_tip`',
    `stream_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the feed stream within the processing plant configuration (e.g., FS-ROM-001, FS-CRU-002). Used in mass balance reconciliation and plant P&ID references.. Valid values are `^[A-Z0-9_-]{3,20}$`',
    `stream_name` STRING COMMENT 'Descriptive human-readable name of the feed stream (e.g., Primary ROM Feed, SAG Mill Discharge, Crusher Product Recirculating Load). Used in operational dashboards and reporting.',
    `stream_status` STRING COMMENT 'Current lifecycle status of the feed stream definition within the processing plant. Active streams are currently receiving material; suspended streams are temporarily offline; decommissioned streams are permanently retired from the circuit.. Valid values are `active|inactive|commissioned|decommissioned|suspended`',
    `stream_type` STRING COMMENT 'Classification of the feed stream by its position and role in the comminution circuit. ROM (Run of Mine) feed is direct from the ROM pad; crushed feed is post-primary crusher; recirculating load is material returned for regrinding. [ENUM-REF-CANDIDATE: rom_feed|crushed_feed|recirculating_load|classifier_overflow|classifier_underflow|screen_oversize|sag_discharge|ball_mill_discharge — promote to reference product]. Valid values are `rom_feed|crushed_feed|recirculating_load|classifier_overflow|classifier_underflow|screen_oversize`',
    `target_feed_rate_tph` DECIMAL(18,2) COMMENT 'The planned or scheduled feed rate for this stream in dry metric tonnes per hour as defined in the current production schedule or LOM plan. Distinct from nominal (design) feed rate; used for shift-level production planning and variance reporting.',
    `target_head_grade_pct` DECIMAL(18,2) COMMENT 'The planned head grade of the primary valuable mineral for this feed stream as per the current production schedule or LOM plan. Used for production reconciliation and variance analysis against actual assayed head grade.',
    `target_p80_mm` DECIMAL(18,2) COMMENT 'The planned P80 particle size target for this feed stream in millimetres as specified in the processing plant design or LOM plan. Used to assess crusher and mill performance against design specifications.',
    `top_size_mm` DECIMAL(18,2) COMMENT 'Maximum lump size of material in the feed stream expressed in millimetres. Defines the upper bound of the particle size distribution and is critical for crusher gap settings, conveyor design, and mill liner protection.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this feed stream record was most recently modified. Supports incremental data loading, change data capture (CDC), and audit trail requirements in the Databricks Silver Layer.',
    CONSTRAINT pk_feed_stream PRIMARY KEY(`feed_stream_id`)
) COMMENT 'Defines ore feed streams entering the processing plant including ROM feed, crushed feed, and recirculating loads. Captures stream identity, source (ROM pad, crusher, stockpile), nominal feed rate (tph), particle size distribution (P80), moisture content, and ore type classification. Supports mass balance and throughput tracking.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`shift_production_run` (
    `shift_production_run_id` BIGINT COMMENT 'Unique surrogate identifier for each shift production run record in the processing plant. Primary key for this transactional entity. Entity role: TRANSACTION_HEADER — represents a discrete operational shift event with a clear lifecycle in the mineral processing domain.',
    `circuit_id` BIGINT COMMENT 'Foreign key linking to processing.circuit. Business justification: A shift production run is executed on a specific processing circuit within a plant. The circuit_id FK directly links the shift run to its circuit, enabling circuit-level performance aggregation. The e',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Shift-level production costs (labour, consumables, utilities) are allocated to cost centres for unit cost calculation, AISC reporting, and budget variance analysis. Core mining cost accounting process',
    `geological_domain_id` BIGINT COMMENT 'Foreign key linking to geology.geological_domain. Business justification: Shift reporting and metallurgical reconciliation require tracking which geological domain material was processed each shift. Shift supervisors record feed_blend_oxide_pct and primary_ore_type against ',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Shift samples are dispatched to specific laboratories for analysis. Essential for tracking sample turnaround times, metallurgical accounting, and reconciling lab results with production data for perfo',
    `lom_plan_id` BIGINT COMMENT 'Identifier of the Life of Mine (LOM) plan version against which this shift production run is being reconciled. Enables tracking of actual production performance versus the approved LOM plan targets for throughput, grade, and recovery.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Production runs frequently trigger corrective maintenance work orders when equipment issues or process deviations are detected during shift operations. Links shift performance problems to maintenance ',
    `metallurgical_balance_id` BIGINT COMMENT 'Foreign key linking to processing.metallurgical_balance. Business justification: Each shift production run contributes to a metallurgical accounting period. Linking shift_production_run to its metallurgical_balance period enables direct aggregation of shift-level production data i',
    `orebody_id` BIGINT COMMENT 'Foreign key linking to geology.orebody. Business justification: Shift production runs process ore from specific orebodies. Operational reporting, grade reconciliation, and metallurgical accounting require linking production shifts to source orebody to compare actu',
    `plant_id` BIGINT COMMENT 'Identifier of the mineral processing plant where this shift production run occurred. Links to the plant master reference. Satisfies TRANSACTION_HEADER PARTY_REFERENCE category (resource reference to the processing facility). Used for plant-level production aggregation and benchmarking.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Processing shift runs must align with mine production schedules for integrated mine-to-mill optimization, bottleneck analysis, and shift-level production reconciliation. Essential for real-time produc',
    `rom_stockpile_id` BIGINT COMMENT 'Foreign key linking to mine.rom_stockpile. Business justification: Processing shift runs track feed source from ROM stockpiles for inventory management, feed scheduling, and stockpile depletion tracking. Essential for real-time feed management and stockpile inventory',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Shifts produce specific saleable products (concentrate grades, cathodes). Essential for production reconciliation, inventory management, and linking shift output to sales contracts. Natural business r',
    `shift_report_id` BIGINT COMMENT 'Foreign key linking to mine.shift_report. Business justification: Daily mine-plant shift reconciliation requires aligning the mine shift report (ore mined, tonnes moved) with the processing shift production run (ore processed, recovery) for the same shift period. Mi',
    `shutdown_plan_id` BIGINT COMMENT 'Foreign key linking to maintenance.shutdown_plan. Business justification: Shift production runs that fall within a planned shutdown window must be attributed to the shutdown plan for production-loss accounting and schedule compliance reporting. Mining operations teams expli',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Production runs process ore from specific tenements. Required for royalty payment calculations, tenement-specific statutory production reporting, and reconciliation of tenement reserves against actual',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Each shift production run targets a specific product specification. Shift supervisors and metallurgists assess whether the run met grade, moisture, and impurity limits. This drives shift quality repor',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Every processing shift generates tailings sent to specific TSF. Required for material flow tracking, mass balance reconciliation, TSF capacity planning, and water balance closure. Fundamental operatio',
    `actual_throughput_rate_tph` DECIMAL(18,2) COMMENT 'Actual average processing rate achieved during the shift, expressed in dry tonnes per hour (tph). Calculated as tonnes processed divided by operating hours. Compared against design throughput rate for performance gap analysis.',
    `calendar_hours` DECIMAL(18,2) COMMENT 'Total number of hours in the shift period as defined by the site calendar (typically 12 hours for a standard shift). Used as the denominator for plant utilisation and OEE calculations. Expressed in decimal hours.',
    `circuit_availability_pct` DECIMAL(18,2) COMMENT 'Percentage of calendar hours during which the processing circuit was available for production, calculated as (calendar hours minus planned and unplanned downtime) divided by calendar hours, expressed as a percentage. Key KPI for processing plant performance against LOM plan targets.',
    `concentrate_produced_tonnes` DECIMAL(18,2) COMMENT 'Total dry tonnes of mineral concentrate or final processed product produced during the shift. Used for production accounting, inventory management, and sales dispatch planning. Sourced from product weighbridge or belt scale measurements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this shift production run record was first created in the Silver layer data product. Used for data lineage, audit trail, and SLA monitoring of data ingestion from OSIsoft PI System and MES. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category.',
    `design_throughput_rate_tph` DECIMAL(18,2) COMMENT 'Nameplate or design throughput rate of the processing plant circuit, expressed in dry tonnes per hour (tph), as specified in the LOM plan and plant design documentation. Used as the benchmark for actual throughput performance assessment.',
    `feed_blend_oxide_pct` DECIMAL(18,2) COMMENT 'Percentage of oxide ore type in the ROM feed blend during the shift. Part of the feed blend composition tracking used to predict and explain metallurgical recovery variations and circuit performance. Sourced from grade control block data and ROM stockpile management.',
    `feed_blend_sulphide_pct` DECIMAL(18,2) COMMENT 'Percentage of sulphide ore type in the ROM feed blend during the shift. Used alongside oxide percentage to characterise the feed blend composition for metallurgical performance analysis and reagent dosage optimisation.',
    `feed_grade_element` STRING COMMENT 'Chemical element symbol for which the feed head grade is reported (e.g., Fe for iron ore, Cu for copper, Li for lithium). Enables multi-commodity processing plants to correctly attribute grade measurements to the target mineral. [ENUM-REF-CANDIDATE: Fe|Cu|Au|Ag|Li|Ni|Co|Zn|Pb|Mo — promote to reference product]',
    `feed_head_grade_pct` DECIMAL(18,2) COMMENT 'Assayed head grade of the primary valuable element (e.g., Fe%, Cu%, Li%) in the ROM feed during the shift, expressed as a percentage. Sourced from LabWare LIMS composite sample assay results. Critical input for metallurgical recovery calculations and LOM plan reconciliation.',
    `feed_moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content of the ROM feed expressed as a percentage of wet weight, measured by on-belt moisture analyser or laboratory sample. Used to convert wet tonnes to dry tonnes for metallurgical accounting and mass balance calculations.',
    `metallurgical_recovery_pct` DECIMAL(18,2) COMMENT 'Percentage of the valuable element in the ROM feed that is successfully recovered into the final concentrate or product during the shift. Calculated from feed grade, product grade, and mass balance. Core KPI for processing efficiency and LOM plan reconciliation.',
    `oee_pct` DECIMAL(18,2) COMMENT 'Overall Equipment Effectiveness expressed as a percentage, combining availability, performance, and quality rate for the processing plant during the shift. Industry-standard KPI for processing plant productivity benchmarking against LOM plan targets. Sourced from OSIsoft PI System.',
    `operating_hours` DECIMAL(18,2) COMMENT 'Actual number of hours the processing plant was in productive operation during the shift, excluding planned and unplanned downtime. Used in OEE calculation and throughput rate derivation. Expressed in decimal hours.',
    `planned_downtime_hours` DECIMAL(18,2) COMMENT 'Hours of scheduled downtime during the shift for planned maintenance, inspections, or scheduled shutdowns. Used in circuit availability and OEE calculations. Sourced from Infor EAM work order schedules.',
    `plant_utilisation_pct` DECIMAL(18,2) COMMENT 'Percentage of available hours during which the plant was actively processing ore, calculated as operating hours divided by available hours. Reflects how effectively available plant time is being used for production. Reported in daily production meetings.',
    `primary_ore_type` STRING COMMENT 'Dominant ore type or lithological classification of the ROM feed processed during the shift (e.g., oxide, sulphide, mixed, transitional, fresh). Determines the applicable processing circuit configuration and expected metallurgical recovery. Sourced from Geovia GEMS geological model and grade control data.',
    `product_grade_pct` DECIMAL(18,2) COMMENT 'Assayed grade of the primary valuable element in the final concentrate or product produced during the shift, expressed as a percentage. Sourced from LabWare LIMS product sample assay. Used for product quality certification, sales contract compliance, and metallurgical accounting.',
    `rom_feed_tonnes_dry` DECIMAL(18,2) COMMENT 'Total dry tonnes of Run of Mine (ROM) ore fed to the processing plant during the shift, calculated by applying the measured moisture factor to wet tonnes. Dry tonnes are the standard basis for metallurgical accounting, resource reporting, and LOM plan reconciliation.',
    `rom_feed_tonnes_wet` DECIMAL(18,2) COMMENT 'Total wet tonnes of Run of Mine (ROM) ore fed to the processing plant during the shift, as measured at the feed conveyor belt scale. Wet weight includes moisture content. Used for mass balance and throughput reporting.',
    `run_status` STRING COMMENT 'Current lifecycle state of the shift production run record. open indicates the shift is in progress; completed indicates shift has ended and data is captured; under_review indicates supervisor review pending; approved indicates shift supervisor sign-off complete; cancelled indicates the shift was voided. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category.. Valid values are `open|completed|cancelled|under_review|approved`',
    `shift_date` DATE COMMENT 'Calendar date on which the production shift commenced. Used as the primary date dimension for daily production reporting, reconciliation against LOM plan targets, and regulatory reporting. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category (date-level precision).',
    `shift_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the production shift concluded, sourced from the MES or OSIsoft PI System historian. Used for shift duration calculation, handover documentation, and OEE reporting. ISO 8601 format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `shift_notes` STRING COMMENT 'Free-text operational notes recorded by the shift supervisor covering significant events, process upsets, equipment issues, safety observations, or other contextual information relevant to the shift production run. Supports shift handover communication and exception reporting.',
    `shift_number` STRING COMMENT 'Designates the shift rotation within the calendar day: day (typically 06:00–18:00), night (18:00–06:00), or afternoon (14:00–22:00) depending on site roster configuration. Used for shift-based production reporting and crew scheduling.. Valid values are `day|night|afternoon`',
    `shift_run_number` STRING COMMENT 'Externally-known business identifier for the shift production run, used in daily production reports, shift handover documentation, and reconciliation against LOM plan targets. Format: SPR-YYYY-MM-DD-PLANTCODE-SEQ. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.. Valid values are `^SPR-[0-9]{4}-[0-9]{2}-[0-9]{2}-[A-Z0-9]{4}-[0-9]{3}$`',
    `shift_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the production shift commenced, sourced from the MES or OSIsoft PI System historian. Used for accurate shift duration calculation, OEE computation, and integration with SCADA event logs. ISO 8601 format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `supervisor_signoff_timestamp` TIMESTAMP COMMENT 'Date and time when the shift supervisor formally approved and signed off the shift production run record. Marks the transition from under_review to approved status. Required for daily production reporting and audit compliance.',
    `tonnes_processed` DECIMAL(18,2) COMMENT 'Total dry tonnes of ore that completed the primary processing circuit during the shift. May differ from ROM feed tonnes due to in-circuit inventory changes, spillage, or sampling losses. Used as the primary throughput metric for production reporting. Satisfies TRANSACTION_HEADER QUANTITATIVE_RESULT category.',
    `unplanned_downtime_hours` DECIMAL(18,2) COMMENT 'Hours of unscheduled downtime during the shift due to equipment breakdowns, process upsets, or emergency stoppages. Key input for MTBF and MTTR analysis and OEE degradation reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this shift production run record was last modified, including supervisor sign-off, data corrections, or status transitions. Supports audit trail and change tracking in the Silver layer. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category.',
    `weather_condition` STRING COMMENT 'Prevailing weather condition at the mine site during the shift that may have affected processing plant operations (e.g., extreme heat impacting reagent performance, rain increasing feed moisture, dust storms affecting conveyor operations). Used for operational exception reporting and HSE compliance. [ENUM-REF-CANDIDATE: clear|rain|storm|fog|high_wind|dust_storm|snow|extreme_heat — promote to reference product]',
    `weather_impact_flag` BOOLEAN COMMENT 'Boolean flag indicating whether adverse weather conditions materially impacted processing plant operations or throughput during the shift. Used to qualify production shortfalls in reporting and distinguish weather-related downtime from equipment or process failures.',
    CONSTRAINT pk_shift_production_run PRIMARY KEY(`shift_production_run_id`)
) COMMENT 'Transactional record of each processing plant production shift — the operational heartbeat of the processing domain. Captures shift date, shift number (day/night/afternoon), plant ID, crew ID, tonnes fed (ROM dry and wet), tonnes processed, circuit availability (%), plant utilisation (%), OEE (Overall Equipment Effectiveness), feed grade (head grade by element), operating hours, calendar hours, actual throughput rate (tph), design throughput rate (tph), feed blend composition (ore type percentages), primary ore type, weather conditions affecting operations, and shift supervisor sign-off. Sourced from OSIsoft PI System historian and MES (Manufacturing Execution System). Serves as the single source of truth for shift and daily production reporting against LOM plan targets. All circuit-level process events, reagent consumption, utility consumption, and operational exception records link back to this shift record via FK. Supports daily production meetings, weekly/monthly reporting, and annual reconciliation.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`unit_operation_event` (
    `unit_operation_event_id` BIGINT COMMENT 'Unique surrogate identifier for each unit operation event record in the mineral processing domain. Primary key for the silver-layer lakehouse table.',
    `asset_id` BIGINT COMMENT 'Reference to the primary processing equipment asset (e.g., SAG mill, ball mill, flotation cell, leach tank) involved in this unit operation event.',
    `circuit_id` BIGINT COMMENT 'Reference to the specific processing circuit (e.g., SAG mill circuit, flotation circuit, leach circuit) where this unit operation event occurred. Links to the circuit master.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Unit operations (crushing, grinding, separation) process specific commodities. Required for metallurgical accounting by commodity type, recovery tracking, and operational performance analysis. Core to',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Individual unit operations (mills, flotation cells, leach tanks) are cost-tracked for activity-based costing, energy consumption analysis, and process optimization ROI. Standard process costing practi',
    `feed_stream_id` BIGINT COMMENT 'Foreign key linking to processing.feed_stream. Business justification: Unit operations process specific feed streams. One event processes one feed stream; one feed stream has many events. This links the operation event to the feed stream being processed.',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Unit operation events record feed_grade_pct and product_grade_pct for a specific element. Linking to grade_parameter ensures correct parameter definition is referenced for metallurgical accounting, pr',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Unit operation events (comminution, separation) often generate maintenance work orders when equipment performance degrades or failures occur. Links operational events to maintenance response for equip',
    `plant_id` BIGINT COMMENT 'Foreign key linking to processing.plant. Business justification: unit_operation_event is the unified transactional record for all mineral processing operations. While plant can be derived via circuit.plant_id or shift_production_run.plant_id, a direct plant_id FK i',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Comminution and processing unit operations track throughput and energy consumption against scheduled mine production for bottleneck analysis, cost allocation, and integrated mine-mill performance opti',
    `prospect_id` BIGINT COMMENT 'Foreign key linking to exploration.prospect. Business justification: Unit operations process ore from specific prospects. Required for metallurgical domain modeling, recovery prediction by ore type, and process optimization. Real business need: ore-specific comminution',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.risk_assessment. Business justification: Unit operations (crushing, leaching, SXEW) require task-level risk assessments (HAZOP/JSA) under mining process safety regulations. A mining HSE manager expects each unit operation event to reference ',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Unit operation events contribute to production of a specific saleable product. Production accounting and cost allocation per saleable product requires this link. commodity_id alone is insufficient — c',
    `shift_production_run_id` BIGINT COMMENT 'Reference to the production shift during which this unit operation event was recorded. Enables shift-level metallurgical accounting and performance reporting.',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Comminution/grinding events produce tailings streams directed to specific TSF. Essential for metallurgical accounting, TSF deposition planning, and environmental compliance reporting. Tracks material ',
    `comments` STRING COMMENT 'Free-text field for process operators or metallurgical accountants to record observations, abnormal conditions, equipment issues, or data quality notes associated with this unit operation event. Sourced from MES shift log entries.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this unit operation event record was first captured and written to the silver-layer lakehouse. Supports audit trail and data lineage tracking.',
    `current_density_a_per_m2` DECIMAL(18,2) COMMENT 'Electrical current density applied in electrowinning (EW) cells during SX-EW unit operations, expressed in A/m². Type-specific parameter for electrowinning operations. Controls cathode deposition rate, product purity, and specific energy consumption.',
    `data_source_system` STRING COMMENT 'Identifies the operational system of record from which this unit operation event data was sourced. Supports data lineage, quality assessment, and reconciliation between SCADA historian (OSIsoft PI System), MES, and LabWare LIMS.. Valid values are `pi_system|mes|lims|manual_entry|scada`',
    `event_end_timestamp` TIMESTAMP COMMENT 'The real-world timestamp when this unit operation event concluded, as recorded by the SCADA historian. Null if the event is still active. Used to calculate operating duration and throughput rates.',
    `event_reference_number` STRING COMMENT 'Human-readable externally-known business identifier for this unit operation event, used in metallurgical reports, process control logs, and MES reconciliation. Format: UOE-YYYY-NNNNNN.. Valid values are `^UOE-[0-9]{4}-[0-9]{6}$`',
    `event_start_timestamp` TIMESTAMP COMMENT 'The real-world timestamp when this unit operation event commenced, as recorded by the SCADA historian (OSIsoft PI System). Used as the principal business event time for metallurgical accounting period alignment.',
    `event_status` STRING COMMENT 'Current lifecycle status of the unit operation event record. active indicates the shift event is in progress; completed indicates normal shift closure; aborted indicates unplanned stoppage; suspended indicates planned hold; pending_review indicates metallurgical accountant review required.. Valid values are `active|completed|aborted|suspended|pending_review`',
    `feed_grade_pct` DECIMAL(18,2) COMMENT 'Head grade of the valuable mineral in the feed material expressed as a percentage (e.g., % Cu, % Fe, % Li2O). Sourced from online analysers or composite assay samples. Critical for recovery calculation and LOM plan grade reconciliation.',
    `feed_tonnage_dry_t` DECIMAL(18,2) COMMENT 'Dry metric tonnes of ore or material fed to the unit operation during the event period. Core throughput metric for metallurgical accounting and LOM plan variance analysis. Sourced from belt scale or flow meter readings in OSIsoft PI System.',
    `froth_depth_mm` DECIMAL(18,2) COMMENT 'Depth of the froth layer in flotation cells, expressed in millimetres. Type-specific parameter for flotation unit operations (rougher, scavenger, cleaner). Controlled variable for concentrate grade and recovery optimisation. Sourced from ultrasonic level sensors via OSIsoft PI System.',
    `is_lom_plan_period` BOOLEAN COMMENT 'Indicates whether this unit operation event falls within an active LOM (Life of Mine) plan period with defined targets, enabling filtering of events for plan vs actual variance reporting.',
    `leach_solution_grade_g_per_l` DECIMAL(18,2) COMMENT 'Concentration of the target metal in the pregnant leach solution (PLS), expressed in grams per litre. Type-specific parameter for heap, tank, vat, CIL, and CIP leaching operations. Used in leach circuit mass balance and SX-EW feed quality assessment.',
    `lom_plan_feed_tonnage_t` DECIMAL(18,2) COMMENT 'LOM (Life of Mine) plan target for feed tonnage to this unit operation for the corresponding shift/period. Used for variance analysis between actual and planned throughput. Sourced from Deswik or Hexagon MinePlan scheduling outputs.',
    `lom_plan_recovery_pct` DECIMAL(18,2) COMMENT 'LOM (Life of Mine) plan target metallurgical recovery percentage for this unit operation and period. Used for variance analysis between actual and planned recovery. Sourced from process design basis and LOM plan assumptions.',
    `medium_density_kg_per_m3` DECIMAL(18,2) COMMENT 'Density of the dense medium (ferrosilicon or magnetite suspension) used in Dense Media Separation (DMS) unit operations, expressed in kg/m³. Type-specific parameter for DMS operations. Controls separation cut-point and product quality.',
    `metallurgical_account_period` STRING COMMENT 'The calendar month period (YYYY-MM) to which this unit operation event is assigned for metallurgical accounting and financial reporting purposes. Used to aggregate shift-level events into monthly mass balance reconciliation reports.. Valid values are `^[0-9]{4}-(0[1-9]|1[0-2])$`',
    `operating_hours` DECIMAL(18,2) COMMENT 'Total hours the unit operation was in active production during the event period. Excludes planned and unplanned downtime. Used in OEE (Overall Equipment Effectiveness) calculation and availability reporting.',
    `operation_subtype` STRING COMMENT 'Detailed sub-classification of the unit operation within its type (e.g., SAG mill, ball mill, HPGR, crusher for comminution; rougher, scavenger, cleaner for flotation; heap, tank, vat, CIL, CIP for leaching; solvent extraction, electrowinning for SX-EW; spirals, shaking tables, jigs for gravity). [ENUM-REF-CANDIDATE: sag_mill|ball_mill|hpgr|crusher|rougher|scavenger|cleaner|heap_leach|tank_leach|vat_leach|cil|cip|solvent_extraction|electrowinning|spirals|shaking_tables|jigs|dense_media_separation|magnetic_separation|thickener|filter — promote to reference product]',
    `operation_type` STRING COMMENT 'Type discriminator identifying the class of mineral processing unit operation for this event. Drives which type-specific attribute groups are populated. [ENUM-REF-CANDIDATE: comminution|flotation|leaching|sx_ew|dms|gravity_separation|magnetic_separation|thickening_dewatering — promote to reference product]',
    `p80_feed_microns` DECIMAL(18,2) COMMENT '80th percentile passing size of the feed material in microns (µm). Primary comminution circuit feed size parameter used to characterise ore hardness, set mill operating conditions, and benchmark against design P80. Applicable to comminution operation types (SAG, ball mill, HPGR, crusher).',
    `p80_product_microns` DECIMAL(18,2) COMMENT '80th percentile passing size of the product material in microns (µm) exiting the comminution unit operation. Compared against target grind size to assess liberation efficiency and downstream flotation or leach performance.',
    `plant_area_code` STRING COMMENT 'Alphanumeric code identifying the physical plant area or section within the processing facility where this unit operation is located (e.g., COMM-01 for comminution area 1, FLOT-02 for flotation area 2). Aligns with P&ID area designations.. Valid values are `^[A-Z]{2,6}-[A-Z0-9]{2,8}$`',
    `power_consumption_kwh` DECIMAL(18,2) COMMENT 'Total electrical energy consumed by the unit operation during the event period, expressed in kWh. Used in energy cost allocation, OPEX reporting, and carbon footprint calculations. Sourced from power meters via OSIsoft PI System.',
    `product_grade_pct` DECIMAL(18,2) COMMENT 'Grade of the valuable mineral in the product or concentrate expressed as a percentage. For flotation concentrates this is the concentrate grade; for leach circuits this is the solution grade. Used in metallurgical accounting and concentrate quality reporting.',
    `product_tonnage_dry_t` DECIMAL(18,2) COMMENT 'Dry metric tonnes of product (concentrate, leach solution, or processed material) produced by the unit operation during the event period. Used in metallurgical accounting mass balance calculations.',
    `reagent_dosage_g_per_t` DECIMAL(18,2) COMMENT 'Total reagent addition rate for the primary reagent in the unit operation, expressed in grams per dry metric tonne of feed. Covers collectors, frothers, depressants (flotation), or lixiviants (leaching). Used in reagent cost tracking and process optimisation.',
    `recovery_pct` DECIMAL(18,2) COMMENT 'Percentage of the valuable mineral in the feed that is recovered into the product stream during this unit operation event. Calculated as (product mass × product grade) / (feed mass × feed grade) × 100. Core KPI for process performance and LOM plan variance.',
    `slurry_density_kg_per_m3` DECIMAL(18,2) COMMENT 'Density of the slurry (water and ore mixture) in the unit operation, expressed in kg/m³. Critical process control parameter for flotation, leaching, and thickening circuits. Sourced from nuclear density gauges or Coriolis meters via OSIsoft PI System.',
    `slurry_ph` DECIMAL(18,2) COMMENT 'pH value of the process slurry measured during the unit operation event. Critical for flotation reagent effectiveness, leach chemistry control, and environmental compliance. Sourced from inline pH probes via OSIsoft PI System.',
    `specific_energy_kwh_per_t` DECIMAL(18,2) COMMENT 'Energy consumed per dry metric tonne of feed processed by the unit operation, expressed in kWh/t. Key efficiency metric for comminution circuits (SAG, ball mill, HPGR) and electrowinning. Sourced from power meters via OSIsoft PI System. Used in OPEX analysis and LOM energy cost modelling.',
    `tailings_tonnage_dry_t` DECIMAL(18,2) COMMENT 'Dry metric tonnes of tailings (gangue and waste material) generated by the unit operation during the event period. Used in mass balance reconciliation, TSF (Tailings Storage Facility) capacity planning, and environmental reporting.',
    `throughput_rate_tph` DECIMAL(18,2) COMMENT 'Instantaneous or average throughput rate of the unit operation during the event period, expressed in dry metric tonnes per hour (t/h). Compared against design capacity and LOM plan targets for process control and production reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this unit operation event record was last modified, including metallurgical accountant adjustments, data quality corrections, or status transitions.',
    `water_consumption_m3` DECIMAL(18,2) COMMENT 'Total volume of process water consumed by the unit operation during the event period, expressed in cubic metres. Used in water balance reporting, environmental compliance (EIS), and OPEX cost allocation. Sourced from flow meters via OSIsoft PI System.',
    CONSTRAINT pk_unit_operation_event PRIMARY KEY(`unit_operation_event_id`)
) COMMENT 'Unified transactional record of all mineral processing operations per shift per circuit, using a type discriminator to capture comminution (SAG, ball mill, HPGR, crusher), flotation (rougher, scavenger, cleaner), leaching (heap, tank, vat, CIL/CIP), SX-EW (solvent extraction, electrowinning), DMS (dense media separation), gravity separation (spirals, shaking tables, jigs), magnetic separation, and thickening/dewatering events. Common attributes: circuit ID, shift reference, feed tonnage, product tonnage, recovery (%), specific energy (kWh/t). Type-specific attribute groups capture process-specific parameters (e.g., P80 for comminution, froth depth for flotation, medium density for DMS, current density for SX-EW). Sourced from OSIsoft PI System SCADA historian and MES. Supports metallurgical accounting, process control, and LOM plan variance analysis.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`flotation_event` (
    `flotation_event_id` BIGINT COMMENT 'Unique surrogate identifier for each flotation circuit performance record per shift. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Flotation events occur on specific flotation cell assets. Metallurgical engineers and maintenance teams track cell-level performance (recovery, froth depth, air flow) against asset OEE and maintenance',
    `circuit_id` BIGINT COMMENT 'Reference to the flotation circuit (e.g., rougher, scavenger, cleaner bank) where this event was recorded. Links to the processing circuit master resource. Satisfies TRANSACTION_HEADER PARTY_REFERENCE / resource reference category.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Flotation circuits target specific minerals/commodities (copper, nickel, zinc). Core to recovery tracking, circuit optimization, and metallurgical reporting. Domain experts expect commodity-specific f',
    `feed_stream_id` BIGINT COMMENT 'Foreign key linking to processing.feed_stream. Business justification: Flotation events process specific feed streams. One event processes one feed stream; one feed stream has many events. This links the flotation event to the feed stream being processed.',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Flotation events record feed_grade_pct, concentrate_grade_pct, and tailings_grade_pct for a specific element. Linking to grade_parameter ensures correct parameter definition for metallurgical reportin',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Flotation involves chemical reagents (collectors, frothers, depressants) and mechanical hazards (impellers, agitators). Incidents during flotation operations (chemical spills, equipment failures, expo',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Flotation circuit samples (feed, concentrate, tailings) are sent to designated labs for grade and recovery verification. Critical for process control, circuit optimization, and validating online analy',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Flotation cell mechanical issues (impeller wear, air system failures) during events trigger maintenance work orders. Links flotation performance problems to maintenance interventions for recovery opti',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant or concentrator facility where the flotation circuit operates. Enables plant-level aggregation and benchmarking across sites.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Flotation events track recovery performance against scheduled mine production for metallurgical accounting, ore type performance analysis, and integrated mine-mill optimization. Essential for recovery',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Flotation events occur during a production shift run. One flotation event belongs to one shift run; one shift run has many flotation events. This links the event to the processing domains shift entit',
    `shift_report_id` BIGINT COMMENT 'Reference to the operational shift during which this flotation event was recorded. Enables shift-level metallurgical accounting and performance comparison across day, afternoon, and night shifts.',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Flotation circuit operators target a specific concentrate specification (grade, recovery, impurity limits). Linking enables automated conformance checking of concentrate_grade_target_pct and recovery_',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Flotation circuits generate tailings streams deposited to specific TSF. Critical for metallurgical balance closure, TSF capacity management, and geochemical characterization. Tracks tailings_mass_t de',
    `unit_operation_event_id` BIGINT COMMENT 'Foreign key linking to processing.unit_operation_event. Business justification: unit_operation_event is described as the unified transactional record of all mineral processing operations per shift per circuit, using a type pattern — it is the supertype record. flotation_event i',
    `air_flow_rate_m3_per_min` DECIMAL(18,2) COMMENT 'Volumetric flow rate of air injected into the flotation cells, measured in cubic metres per minute (m³/min). Air flow is a primary control variable affecting bubble generation, froth stability, and mineral recovery. Monitored via OSIsoft PI SCADA integration.',
    `cell_count_operating` STRING COMMENT 'Number of flotation cells actively operating in the circuit during this event period. Cells may be taken offline for maintenance or cleaning. Operating cell count affects residence time and overall circuit capacity. Sourced from Infor EAM work order data.',
    `cell_volume_m3` DECIMAL(18,2) COMMENT 'Total active volume of the flotation cells in operation during this event, measured in cubic metres (m³). Combined with feed rate, determines slurry residence time which is a key flotation kinetics parameter.',
    `circuit_availability_pct` DECIMAL(18,2) COMMENT 'Percentage of the event period during which the flotation circuit was available and operating (not in planned or unplanned downtime). Calculated as operating hours divided by scheduled hours × 100. Contributes to Overall Equipment Effectiveness (OEE) reporting.',
    `circuit_recovery_pct` DECIMAL(18,2) COMMENT 'Percentage of the valuable mineral in the feed that is recovered into the concentrate product for this flotation circuit stage. Calculated as: (concentrate mass × concentrate grade) / (feed mass × feed grade) × 100. Core metallurgical KPI for LOM plan tracking and reagent optimisation. Satisfies TRANSACTION_HEADER QUANTITATIVE_RESULT category.',
    `circuit_stage` STRING COMMENT 'The specific stage of the flotation circuit captured in this event record. Rougher is the primary separation stage; scavenger recovers minerals from rougher tailings; cleaner upgrades rougher concentrate grade; recleaner further upgrades cleaner concentrate. Critical for stage-by-stage metallurgical accounting.. Valid values are `rougher|scavenger|cleaner|recleaner`',
    `collector_dosage_g_per_t` DECIMAL(18,2) COMMENT 'Dosage rate of the collector reagent (e.g., xanthate, dithiophosphate) added to the flotation circuit, expressed in grams per dry metric tonne of feed (g/t). Collector promotes hydrophobicity of target mineral surfaces to enable bubble attachment. Key reagent optimisation variable.',
    `concentrate_grade_pct` DECIMAL(18,2) COMMENT 'Grade of the valuable mineral in the flotation concentrate product, expressed as a percentage (%). Measures the quality of the separation achieved. Higher concentrate grade reduces downstream smelting costs and improves payable metal. Sourced from LabWare LIMS.',
    `concentrate_grade_target_pct` DECIMAL(18,2) COMMENT 'The planned or contractually required concentrate grade for the valuable mineral, expressed as a percentage (%). Used to assess whether the flotation circuit is meeting product quality specifications for offtake agreements and smelter contracts.',
    `concentrate_mass_t` DECIMAL(18,2) COMMENT 'Total dry mass of concentrate produced by the flotation circuit during the event period, measured in dry metric tonnes (t). Used in metallurgical accounting mass balance and payable metal calculations.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this flotation event record was first captured in the system. Used for audit trail and data lineage tracking. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category.',
    `depressant_dosage_g_per_t` DECIMAL(18,2) COMMENT 'Dosage rate of the depressant reagent (e.g., sodium cyanide, zinc sulphate, CMC) added to the flotation circuit, expressed in grams per dry metric tonne of feed (g/t). Depressants selectively prevent flotation of gangue minerals or penalty elements, improving concentrate grade and selectivity.',
    `downtime_reason` STRING COMMENT 'Descriptive reason for any unplanned or planned downtime experienced by the flotation circuit during this event period (e.g., pump failure, cell maintenance, reagent outage, power interruption). Null if no downtime occurred. Used for reliability analysis and maintenance planning in Infor EAM. [ENUM-REF-CANDIDATE: pump_failure|cell_maintenance|reagent_outage|power_interruption|planned_shutdown|instrumentation_fault — promote to reference product]',
    `event_end_timestamp` TIMESTAMP COMMENT 'The real-world timestamp marking the end of the flotation measurement period (typically shift end). Combined with start timestamp to define the measurement window for throughput and reagent consumption calculations.',
    `event_number` STRING COMMENT 'Externally-known business identifier for this flotation event record, formatted as FLT-YYYY-MM-DD-NNNN. Used for cross-system reference, metallurgical accounting reconciliation, and audit trail. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.. Valid values are `^FLT-[0-9]{4}-[0-9]{2}-[0-9]{2}-[0-9]{4}$`',
    `event_start_timestamp` TIMESTAMP COMMENT 'The real-world timestamp marking the start of the flotation measurement period (typically shift start). Used for time-series alignment with OSIsoft PI historian data and SCADA records. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category.',
    `event_status` STRING COMMENT 'Current workflow state of the flotation event record. Draft indicates data entry in progress; confirmed indicates shift data locked; reviewed indicates metallurgist sign-off; approved indicates inclusion in metallurgical balance; voided indicates record invalidated. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category.. Valid values are `draft|confirmed|reviewed|approved|voided`',
    `feed_grade_pct` DECIMAL(18,2) COMMENT 'Head grade of the valuable mineral (e.g., copper, lithium, nickel) in the flotation feed, expressed as a percentage (%). Derived from assay results and used as the denominator in circuit recovery calculations. Sourced from LabWare LIMS assay data.',
    `feed_particle_size_p80_um` DECIMAL(18,2) COMMENT 'The 80th percentile passing particle size (P80) of the flotation feed, measured in micrometres (µm). Particle size is a critical determinant of flotation performance — coarse particles are difficult to float while ultra-fine particles suffer from poor bubble attachment. Sourced from LabWare LIMS particle size analysis.',
    `feed_rate_tph` DECIMAL(18,2) COMMENT 'Mass flow rate of ore slurry fed into the flotation circuit during the event period, measured in dry metric tonnes per hour (t/h). Key throughput metric for metallurgical accounting and LOM plan performance tracking.',
    `froth_depth_mm` DECIMAL(18,2) COMMENT 'Depth of the froth layer maintained in the flotation cell during the event period, measured in millimetres (mm). Froth depth is a critical control parameter influencing concentrate grade and recovery trade-off. Deeper froth generally improves grade at the expense of recovery.',
    `frother_dosage_g_per_t` DECIMAL(18,2) COMMENT 'Dosage rate of the frother reagent (e.g., MIBC, pine oil, polyglycol) added to the flotation circuit, expressed in grams per dry metric tonne of feed (g/t). Frother stabilises the froth layer and controls bubble size distribution. Critical for froth stability and concentrate transport.',
    `impeller_speed_rpm` DECIMAL(18,2) COMMENT 'Average rotational speed of the flotation cell impellers during the event period, measured in revolutions per minute (RPM). Impeller speed controls slurry agitation, air dispersion, and bubble-particle contact. Monitored via OSIsoft PI SCADA.',
    `lime_dosage_kg_per_t` DECIMAL(18,2) COMMENT 'Dosage rate of lime (calcium hydroxide or calcium oxide) added to the flotation circuit for pH control, expressed in kilograms per dry metric tonne of feed (kg/t). Lime is typically the highest-volume reagent in sulphide flotation circuits and a significant OPEX driver.',
    `mass_pull_pct` DECIMAL(18,2) COMMENT 'The ratio of concentrate mass to feed mass expressed as a percentage (%). Indicates the proportion of total feed mass reporting to the concentrate. High mass pull may indicate over-flotation and gangue entrainment; low mass pull may indicate under-recovery. Key flotation control parameter.',
    `mineral_type` STRING COMMENT 'The primary valuable mineral being recovered in this flotation circuit event (e.g., copper, nickel, lithium). Determines the applicable reagent suite, recovery benchmarks, and product specifications. Essential for multi-commodity processing plants. [ENUM-REF-CANDIDATE: copper|nickel|lithium|zinc|lead|molybdenum|gold|silver — 8 candidates stripped; promote to reference product]',
    `ore_type` STRING COMMENT 'Classification of the ore type being processed in the flotation circuit during this event (e.g., sulphide, oxide, mixed, transitional). Ore type significantly influences reagent selection, dosage rates, and achievable recovery. [ENUM-REF-CANDIDATE: sulphide|oxide|mixed|transitional|primary|secondary — promote to reference product]',
    `pulp_density_pct_solids` DECIMAL(18,2) COMMENT 'Solids content of the flotation feed slurry expressed as a percentage by mass (% solids). Pulp density affects reagent effectiveness, bubble-particle collision rates, and overall flotation kinetics. Monitored continuously via OSIsoft PI.',
    `pulp_ph` DECIMAL(18,2) COMMENT 'pH of the flotation pulp during the event period. pH is a critical chemical environment parameter that governs mineral surface chemistry, collector adsorption, and selectivity between valuable minerals and gangue. Typically controlled with lime addition.',
    `recovery_target_pct` DECIMAL(18,2) COMMENT 'The planned or budgeted circuit recovery percentage for this flotation stage as defined in the LOM plan or metallurgical design criteria. Enables variance analysis between actual and target recovery for performance management and LOM plan tracking.',
    `sample_reference` STRING COMMENT 'The LabWare LIMS sample identifier for the assay samples collected during this flotation event (feed, concentrate, and tailings). Enables traceability between the flotation performance record and the underlying laboratory assay results supporting grade data.',
    `slurry_temperature_c` DECIMAL(18,2) COMMENT 'Temperature of the flotation feed slurry during the event period, measured in degrees Celsius (°C). Slurry temperature affects reagent solubility, reaction kinetics, and froth stability. Particularly relevant in cold-climate operations and heated leach-flotation circuits.',
    `tailings_grade_pct` DECIMAL(18,2) COMMENT 'Grade of the valuable mineral remaining in the flotation tailings stream, expressed as a percentage (%). Indicates mineral losses to the Tailings Storage Facility (TSF). Used to calculate circuit recovery and identify optimisation opportunities. Sourced from LabWare LIMS.',
    `tailings_mass_t` DECIMAL(18,2) COMMENT 'Total dry mass of tailings discharged from the flotation circuit during the event period, measured in dry metric tonnes (t). Used in mass balance reconciliation and TSF volumetric planning.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this flotation event record was last modified. Tracks data corrections, metallurgist adjustments, and re-assay updates. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category.',
    `water_addition_m3_per_h` DECIMAL(18,2) COMMENT 'Rate of process water added to the flotation circuit to maintain target pulp density, measured in cubic metres per hour (m³/h). Water consumption is a key environmental and OPEX metric, particularly in water-stressed mining regions subject to ISO 14001 reporting.',
    CONSTRAINT pk_flotation_event PRIMARY KEY(`flotation_event_id`)
) COMMENT 'Transactional record of flotation circuit performance per shift including rougher, scavenger, and cleaner stages. Captures feed grade, concentrate grade, tailings grade, mass pull (%), air flow rate (m³/min), froth depth (mm), reagent dosage rates, and circuit recovery (%). Supports metallurgical accounting and reagent optimisation.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`leach_event` (
    `leach_event_id` BIGINT COMMENT 'Unique surrogate identifier for each leaching operation event record in the silver layer lakehouse. Primary key for the leach_event data product.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Leach events occur in specific leach tanks or heap leach pad assets. Hydromet operations track extraction efficiency and reagent consumption per tank asset to schedule maintenance, manage asset life, ',
    `circuit_id` BIGINT COMMENT 'Reference to the leach circuit or processing unit (heap leach pad, CIL/CIP tank, vat leach vessel) where this event occurred. Links to the processing circuit master.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Leaching extracts specific commodities (copper, gold, nickel, uranium). Fundamental process-commodity link for hydrometallurgical operations. Replaces denormalized commodity text field. Essential for ',
    `feed_stream_id` BIGINT COMMENT 'Foreign key linking to processing.feed_stream. Business justification: Leach events process specific feed streams. One event processes one feed stream; one feed stream has many events. This links the leach event to the feed stream being processed.',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Leach events record feed_grade_pct and residue_grade_pct for a specific element. Linking to grade_parameter ensures correct parameter definition for extraction efficiency reporting, regulatory complia',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Leaching uses hazardous chemicals (cyanide for gold, sulfuric acid for copper). Incidents during leach operations (solution spills, gas releases, exposure events) require direct traceability to leach ',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Leach solution samples (PLS, raffinate, residue) analyzed at specific labs for extraction efficiency monitoring and reagent optimization. Standard hydrometallurgical process control requirement for co',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Leach tank/pad equipment failures (agitators, pumps, solution distribution) during leach events generate maintenance work orders. Links hydrometallurgical process issues to maintenance response for ex',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant or facility where the leach event occurred. Supports multi-site reporting and plant-level performance benchmarking.',
    `process_sample_id` BIGINT COMMENT 'Identifier of the representative leach solution or residue sample submitted to the laboratory for assay analysis during this event. Links to LabWare LIMS sample management records for quality control and mass balance verification.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Leach events must reference production schedules for heap leach ore tracking, metal recovery forecasting, and ore type extraction performance analysis. Critical for heap leach operations and long-term',
    `prospect_id` BIGINT COMMENT 'Foreign key linking to exploration.prospect. Business justification: Leach performance is ore-source dependent. Essential for heap leach/tank leach optimization, resource model metallurgical assumptions validation. Real business need: extraction efficiency tracking by ',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Leach events occur during a production shift run. One leach event belongs to one shift run; one shift run has many leach events. This links the event to the processing domains shift entity.',
    `shift_report_id` BIGINT COMMENT 'Reference to the operational shift during which this leach event was recorded. Enables shift-based production reporting and reconciliation.',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Leach residues/tailings deposited to specific TSF. Required for geochemical risk management (ARD assessment), TSF design compliance, and environmental monitoring. Tracks ore_feed_mass_t minus recovere',
    `unit_operation_event_id` BIGINT COMMENT 'Foreign key linking to processing.unit_operation_event. Business justification: leach_event is a specialized subtype of unit_operation_event for heap/tank/vat leaching operations. Linking leach_event to its parent unit_operation_event enables the supertype/subtype pattern for uni',
    `batch_number` STRING COMMENT 'Operational batch or lot number assigned to the ore charge or solution batch processed in this leach event. Used for traceability from ROM feed through to final concentrate or pregnant leach solution (PLS). Sourced from LabWare LIMS or SCADA batch management.',
    `comments` STRING COMMENT 'Free-text operational comments or notes recorded by the process operator or metallurgist for this leach event. May include observations on solution colour, foam, equipment behaviour, or other qualitative process indicators not captured by structured fields.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this leach event record was first captured and persisted in the data platform. Audit trail field for data lineage and silver layer ingestion tracking.',
    `data_source` STRING COMMENT 'Identifies the originating operational system from which this leach event record was sourced. Supports data lineage, quality assessment, and reconciliation between automated sensor data (OSIsoft PI, SCADA) and manually entered or LIMS-derived records.. Valid values are `pi_system|scada|lims|manual|mes`',
    `dissolved_metal_concentration_ppm` DECIMAL(18,2) COMMENT 'Concentration of the target dissolved metal in the pregnant leach solution (PLS) or leachate, measured in parts per million (ppm). Primary indicator of leaching effectiveness and solution grade. Sourced from LabWare LIMS assay results or inline OSIsoft PI analyser tags.',
    `dissolved_oxygen_mg_l` DECIMAL(18,2) COMMENT 'Concentration of dissolved oxygen in the leach solution, measured in milligrams per litre (mg/L). Dissolved oxygen is a critical parameter for cyanide leaching of gold and silver, directly influencing metal dissolution rates. Monitored via OSIsoft PI DO analysers.',
    `event_end_timestamp` TIMESTAMP COMMENT 'The actual date and time when the leaching operation concluded for this event or batch. Used in conjunction with event_start_timestamp to derive leach cycle duration.',
    `event_number` STRING COMMENT 'Externally-known business identifier for the leach event, typically sourced from the OSIsoft PI System or SCADA batch/event log. Used for cross-system traceability and operational reporting (e.g., LE-2024-00123).',
    `event_start_timestamp` TIMESTAMP COMMENT 'The actual date and time when the leaching operation commenced for this event or batch. Principal real-world event time used for duration calculations, shift allocation, and production scheduling alignment.',
    `event_status` STRING COMMENT 'Current lifecycle status of the leach event. Indicates whether the leaching operation is actively running, has completed normally, was aborted due to process upset, is on hold, or is pending quality review before finalisation.. Valid values are `in_progress|completed|aborted|on_hold|pending_review`',
    `extraction_efficiency_pct` DECIMAL(18,2) COMMENT 'Percentage of the target metal extracted from the ore feed into solution during this leach event, calculated as (metal dissolved / metal in feed) × 100. Key performance indicator for process optimisation, LOM plan reconciliation, and recovery rate reporting. Sourced from LabWare LIMS mass balance.',
    `feed_grade_pct` DECIMAL(18,2) COMMENT 'Head grade of the ore feed entering the leach circuit, expressed as a percentage (%) for base metals or g/t equivalent converted to percentage for precious metals. Sourced from assay results in LabWare LIMS. Critical input for extraction efficiency and recovery rate calculations.',
    `leach_duration_hrs` DECIMAL(18,2) COMMENT 'Total elapsed time of the leaching operation for this event, measured in hours. Represents the actual leach time from solution application/charge to drain/discharge. Used for cycle time optimisation, throughput modelling, and LOM plan variance analysis.',
    `leach_type` STRING COMMENT 'Classification of the leaching method applied in this event. Distinguishes between heap leach (copper, gold), tank leach (CIL/CIP for gold), vat leach, and agitation leach configurations. Drives process parameter benchmarking and recovery rate analysis. [ENUM-REF-CANDIDATE: heap_leach|tank_leach|vat_leach|cil|cip|agitation_leach — promote to reference product]. Valid values are `heap_leach|tank_leach|vat_leach|cil|cip|agitation_leach`',
    `ore_feed_mass_t` DECIMAL(18,2) COMMENT 'Total dry mass of ore charged to the leach circuit for this event, measured in metric tonnes. Represents the principal quantitative input for recovery rate calculation and throughput reporting against Life of Mine (LOM) plan targets.',
    `ore_type` STRING COMMENT 'Mineralogical classification of the ore processed in this leach event. Ore type significantly influences leaching chemistry, reagent selection, and achievable recovery rates. Sourced from Geovia GEMS geological model and grade control assay data.. Valid values are `oxide|sulphide|mixed|transitional|laterite`',
    `oxidation_reduction_potential_mv` DECIMAL(18,2) COMMENT 'Oxidation-reduction potential (ORP) of the leach solution measured in millivolts (mV). Critical electrochemical parameter for monitoring leaching conditions, particularly in cyanide leach (gold) and SX-EW (copper) circuits. Sourced from OSIsoft PI inline analysers.',
    `pi_tag_reference` STRING COMMENT 'The OSIsoft PI System tag name or event frame reference associated with this leach event. Enables direct traceability back to the process historian for raw time-series data retrieval, audit, and re-processing. Applicable when data_source is pi_system or scada.',
    `process_upset_flag` BOOLEAN COMMENT 'Indicates whether a process upset or abnormal operating condition occurred during this leach event (True = upset occurred, False = normal operation). Process upsets may include pH excursions, reagent dosing failures, pump trips, or temperature deviations. Triggers investigation and corrective action workflows in IsoMetrix.',
    `reagent_concentration_g_l` DECIMAL(18,2) COMMENT 'Concentration of the primary leaching reagent (e.g., cyanide for gold CIL/CIP, sulphuric acid for copper heap leach, caustic soda for lithium leach) in the leach solution, measured in grams per litre (g/L). Key process control parameter for optimising extraction efficiency and reagent cost (OPEX).',
    `reagent_consumption_kg` DECIMAL(18,2) COMMENT 'Total mass of primary leaching reagent consumed during this leach event, measured in kilograms. Used for OPEX tracking, reagent cost allocation, and environmental reporting of chemical usage. Sourced from Pronto Xi inventory consumption records and SCADA flow meters.',
    `reagent_type` STRING COMMENT 'Type of primary leaching reagent used in this event. Determines applicable safety, environmental, and regulatory requirements. Examples include sodium cyanide (gold CIL/CIP), sulphuric acid (copper heap leach), and caustic soda (lithium leach circuits). [ENUM-REF-CANDIDATE: cyanide|sulphuric_acid|caustic_soda|ammonia|chlorine|hydrochloric_acid — promote to reference product]. Valid values are `cyanide|sulphuric_acid|caustic_soda|ammonia|chlorine|hydrochloric_acid`',
    `residue_grade_pct` DECIMAL(18,2) COMMENT 'Grade of the target metal remaining in the leach residue (tailings) after the leaching event, expressed as a percentage. Used to calculate actual metal recovery and identify process losses. Sourced from LabWare LIMS assay results on residue samples.',
    `slurry_density_g_cm3` DECIMAL(18,2) COMMENT 'Density of the ore-solution slurry (water and ore mixture) in the leach circuit, measured in grams per cubic centimetre (g/cm³). Applicable to tank leach and CIL/CIP circuits. Monitored via OSIsoft PI density instruments. Affects mass transfer and reagent efficiency.',
    `solution_flow_rate_m3_hr` DECIMAL(18,2) COMMENT 'Volumetric flow rate of leach solution through the circuit during this event, measured in cubic metres per hour (m³/hr). Monitored via OSIsoft PI flow instrumentation. Influences reagent distribution, contact time, and overall leaching kinetics.',
    `solution_ph` DECIMAL(18,2) COMMENT 'Measured pH of the leach solution at the time of this event or at the representative sampling point within the event window. Critical process control parameter for reagent efficiency, metal dissolution kinetics, and environmental compliance (acid mine drainage prevention).',
    `solution_temperature_c` DECIMAL(18,2) COMMENT 'Temperature of the leach solution in degrees Celsius (°C) measured during this event. Temperature directly influences leaching kinetics, reagent consumption rates, and metal dissolution efficiency. Monitored via OSIsoft PI System instrumentation.',
    `solution_volume_m3` DECIMAL(18,2) COMMENT 'Total volume of leach solution applied or circulated during this event, measured in cubic metres (m³). Used for water balance reporting, reagent dosing calculations, and environmental water management compliance.',
    `tank_pad_reference` STRING COMMENT 'Operational identifier of the specific leach tank, leach pad cell, or vat vessel used in this event (e.g., TANK-03, PAD-CELL-7B). Sourced from the OSIsoft PI asset hierarchy or SCADA tag configuration. Enables equipment-level performance tracking.',
    `target_extraction_efficiency_pct` DECIMAL(18,2) COMMENT 'Planned or budgeted extraction efficiency percentage for this leach event type and ore type, as defined in the Life of Mine (LOM) plan or metallurgical test work. Enables variance analysis between actual and planned recovery performance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this leach event record was last modified or updated in the data platform. Supports change detection, incremental processing, and audit compliance.',
    `upset_description` STRING COMMENT 'Free-text description of the process upset or abnormal condition that occurred during this leach event, if applicable. Populated when process_upset_flag is True. Captures the nature of the deviation for root cause analysis and corrective action tracking.',
    CONSTRAINT pk_leach_event PRIMARY KEY(`leach_event_id`)
) COMMENT 'Transactional record of leaching operations (heap leach, tank leach, vat leach) per shift or batch. Captures leach tank/pad ID, solution pH, temperature (°C), reagent concentration (g/L), leach time (hrs), dissolved metal concentration (ppm), and extraction efficiency (%). Applicable to gold CIL/CIP, copper heap leach, and lithium leach circuits.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`sxew_event` (
    `sxew_event_id` BIGINT COMMENT 'Unique surrogate identifier for each SX-EW operational event record in the silver layer lakehouse. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: SX/EW events occur on specific electrowinning cell or mixer-settler assets. Copper refineries track cathode production, current efficiency, and cell voltage per asset for OEE reporting, maintenance sc',
    `circuit_id` BIGINT COMMENT 'Reference to the specific SX-EW processing circuit (tankhouse or extraction circuit) where this event occurred. Links to the processing circuit master resource.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: SX-EW produces specific commodities (copper cathode). Direct production link essential for cathode quality tracking, production reporting, and linking hydrometallurgical output to saleable products. S',
    `feed_stream_id` BIGINT COMMENT 'Foreign key linking to processing.feed_stream. Business justification: SX-EW events process specific feed streams (PLS feed). One event processes one feed stream; one feed stream has many events. This links the SX-EW event to the feed stream being processed.',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: SX-EW events record cathode_grade_pct and aqueous_feed_grade_gl for specific elements. Linking to grade_parameter ensures correct parameter definition for cathode quality reporting, LME grade complian',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: SXEW involves high-voltage electrical systems (electrowinning cells) and corrosive solutions (sulfuric acid electrolyte). Incidents during SXEW operations (electrical faults, acid spills, cathode hand',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Electrolyte and cathode samples from SX-EW circuits sent to designated labs for copper grade, impurity analysis, and cathode quality verification. Essential for product quality control and sales contr',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: SX-EW circuit equipment issues (rectifier failures, cell short circuits, organic pumps) during production events trigger maintenance work orders. Links cathode production problems to maintenance inter',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant or hydrometallurgical facility where the SX-EW circuit operates. Enables multi-site reporting and plant-level performance aggregation.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: SX-EW events track cathode production against scheduled mine production for integrated copper production planning, metal accounting, and sales contract fulfillment. Essential for copper operations wit',
    `shift_production_run_id` BIGINT COMMENT 'Reference to the operational shift during which this SX-EW event was recorded. Each SX-EW event is captured per shift as the primary reporting cadence.',
    `unit_operation_event_id` BIGINT COMMENT 'Foreign key linking to processing.unit_operation_event. Business justification: sxew_event is a specialized subtype of unit_operation_event for Solvent Extraction Electrowinning operations. Linking sxew_event to its parent unit_operation_event enables unified hydrometallurgical p',
    `acid_concentration_gl` DECIMAL(18,2) COMMENT 'Sulphuric acid concentration in the electrowinning electrolyte, measured in grams per litre (g/L). Acid balance is critical for cathode quality, current efficiency, and prevention of anode corrosion in the EW tankhouse.',
    `aqueous_feed_grade_gl` DECIMAL(18,2) COMMENT 'Copper concentration in the aqueous feed (pregnant leach solution, PLS) entering the solvent extraction circuit, measured in grams per litre (g/L). Determines the extraction circuit loading and directly influences cathode production output.',
    `cathode_grade_pct` DECIMAL(18,2) COMMENT 'Purity of the copper cathode produced, expressed as a percentage of copper content. LME Grade A copper cathode requires ≥99.99% Cu. Used for product quality certification, sales contract compliance, and LME registration eligibility.',
    `cathode_production_kg` DECIMAL(18,2) COMMENT 'Total mass of copper cathode produced during the shift, measured in kilograms. The primary production output metric for the SX-EW circuit, used for daily production reporting, LOM plan reconciliation, and sales volume tracking.',
    `cathode_quality_grade` STRING COMMENT 'Quality classification of copper cathode produced during the shift. LME_Grade_A indicates product meets London Metal Exchange Grade A specification (≥99.99% Cu); off_spec indicates product below LME standard but saleable; rejected indicates product not suitable for sale.. Valid values are `LME_Grade_A|off_spec|rejected`',
    `cathodes_harvested` STRING COMMENT 'Number of individual copper cathode sheets harvested (stripped) from the electrowinning cells during the shift. Used for tankhouse productivity tracking, cathode cycle time management, and inventory reconciliation.',
    `cell_voltage_v` DECIMAL(18,2) COMMENT 'Average operating voltage across the electrowinning cells during the shift, measured in volts (V). Used to monitor energy efficiency, detect anode/cathode fouling, and calculate specific energy consumption per tonne of copper produced.',
    `cells_operating` STRING COMMENT 'Number of electrowinning cells in active operation during the shift. Used to calculate effective circuit capacity, monitor cell availability, and assess impact of cell outages on production.',
    `cells_total` STRING COMMENT 'Total number of electrowinning cells installed in the circuit (nameplate capacity). Used as the denominator for cell availability calculations and Overall Equipment Effectiveness (OEE) reporting.',
    `circuit_downtime_min` STRING COMMENT 'Total unplanned and planned downtime for the SX-EW circuit during the shift, measured in minutes. Used for Overall Equipment Effectiveness (OEE) calculation, maintenance planning via Infor EAM, and production loss reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this SX-EW event record was first created in the data platform. Used for data lineage, audit trail, and silver layer ingestion tracking. Populated automatically at record insertion.',
    `current_density_am2` DECIMAL(18,2) COMMENT 'Electrical current density applied across the electrowinning cathode surface, measured in amperes per square metre (A/m²). A primary electrowinning process control parameter governing copper deposition rate, cathode quality, and energy consumption.',
    `current_efficiency_pct` DECIMAL(18,2) COMMENT 'Ratio of actual copper deposited to the theoretical copper that should have been deposited based on Faradays Law, expressed as a percentage. A key electrowinning performance indicator; values below target indicate short-circuiting, impurity effects, or electrolyte imbalance.',
    `downtime_reason` STRING COMMENT 'Primary reason code for circuit downtime recorded during the shift. Used for root cause analysis, maintenance prioritisation, and production loss categorisation. [ENUM-REF-CANDIDATE: planned_maintenance|unplanned_breakdown|process_upset|reagent_shortage|power_outage|other — promote to reference product if additional codes required]. Valid values are `planned_maintenance|unplanned_breakdown|process_upset|reagent_shortage|power_outage|other`',
    `electrolyte_temperature_c` DECIMAL(18,2) COMMENT 'Operating temperature of the electrowinning electrolyte during the shift, measured in degrees Celsius (°C). Temperature affects copper ion mobility, current efficiency, and cathode surface quality. Monitored via OSIsoft PI System.',
    `event_number` STRING COMMENT 'Human-readable business identifier for the SX-EW shift event, formatted as SXEW-{YYYY}-{NNNNNN}. Used for cross-referencing with OSIsoft PI System historian records, lab assay reports, and production reconciliation.. Valid values are `^SXEW-[0-9]{4}-[0-9]{6}$`',
    `event_status` STRING COMMENT 'Lifecycle status of the SX-EW event record. draft indicates data entry in progress; confirmed indicates shift data locked; reviewed indicates metallurgist review complete; approved indicates management sign-off; voided indicates record invalidated.. Valid values are `draft|confirmed|reviewed|approved|voided`',
    `extraction_efficiency_pct` DECIMAL(18,2) COMMENT 'Percentage of copper extracted from the aqueous feed (PLS) into the organic phase during the solvent extraction stage, calculated as (PLS grade – raffinate grade) / PLS grade × 100. A key metallurgical recovery indicator for the SX circuit.',
    `impurity_fe_mgl` DECIMAL(18,2) COMMENT 'Concentration of iron (Fe) impurity in the electrowinning electrolyte, measured in milligrams per litre (mg/L). Elevated iron levels reduce current efficiency and degrade cathode surface quality. Monitored via LabWare LIMS shift samples.',
    `impurity_mn_mgl` DECIMAL(18,2) COMMENT 'Concentration of manganese (Mn) impurity in the electrowinning electrolyte, measured in milligrams per litre (mg/L). Manganese causes anode passivation and cathode surface defects. Tracked via LabWare LIMS for electrolyte bleed management.',
    `lom_plan_cathode_kg` DECIMAL(18,2) COMMENT 'Planned cathode copper production target for the shift as defined in the Life of Mine (LOM) plan or short-term production schedule. Used for variance analysis between actual and planned production, and for LOM plan tracking.',
    `organic_cu_concentration_gl` DECIMAL(18,2) COMMENT 'Concentration of copper in the organic (solvent) phase of the solvent extraction circuit, measured in grams per litre (g/L). A key process control parameter indicating the loading efficiency of the organic extractant (e.g., LIX reagent). Sourced from OSIsoft PI System online analysers or LabWare LIMS shift samples.',
    `organic_flow_rate_m3h` DECIMAL(18,2) COMMENT 'Volumetric flow rate of the organic solvent phase circulating through the solvent extraction mixer-settlers, measured in cubic metres per hour (m³/h). Used to control the aqueous-to-organic (A:O) ratio and optimise copper extraction efficiency.',
    `pls_flow_rate_m3h` DECIMAL(18,2) COMMENT 'Volumetric flow rate of the pregnant leach solution (PLS) entering the solvent extraction circuit, measured in cubic metres per hour (m³/h). Controls the aqueous-to-organic (A:O) ratio and extraction circuit residence time.',
    `production_date` DATE COMMENT 'Calendar date on which the SX-EW production event occurred. Used for daily production reporting, reconciliation against Life of Mine (LOM) plan targets, and regulatory disclosure.',
    `raffinate_grade_gl` DECIMAL(18,2) COMMENT 'Copper concentration in the raffinate (barren aqueous solution) exiting the solvent extraction circuit after copper has been extracted, measured in grams per litre (g/L). Used to calculate extraction efficiency and monitor copper losses to raffinate.',
    `reagent_consumption_lm3` DECIMAL(18,2) COMMENT 'Volume of organic extractant reagent (e.g., LIX 984N or equivalent) consumed per cubic metre of pregnant leach solution processed, measured in litres per cubic metre (L/m³). Used for reagent cost tracking, OPEX reporting, and supply chain planning via Pronto Xi.',
    `shift_end_timestamp` TIMESTAMP COMMENT 'The actual date and time the operational shift ended for this SX-EW event. Used to calculate shift duration and align with production reporting periods.',
    `shift_start_timestamp` TIMESTAMP COMMENT 'The actual date and time the operational shift commenced for this SX-EW event. Principal business event timestamp used for time-series analysis, production scheduling alignment, and OSIsoft PI historian correlation.',
    `shift_type` STRING COMMENT 'Classification of the shift period: day, afternoon, or night. Used for shift-pattern analysis, fatigue risk management, and production performance benchmarking across shift rotations.. Valid values are `day|afternoon|night`',
    `source_system` STRING COMMENT 'Originating operational system from which this SX-EW event record was sourced. Supports data lineage, reconciliation between systems, and data quality root cause analysis in the lakehouse silver layer.. Valid values are `OSIsoft_PI|LabWare_LIMS|SAP_S4HANA|manual_entry`',
    `specific_energy_kwh_t` DECIMAL(18,2) COMMENT 'Electrical energy consumed per tonne of copper cathode produced, measured in kilowatt-hours per tonne (kWh/t Cu). A key OPEX and sustainability metric for the electrowinning circuit, used for energy cost allocation and carbon footprint reporting.',
    `spent_electrolyte_grade_gl` DECIMAL(18,2) COMMENT 'Copper concentration in the spent electrolyte returning from the electrowinning cells to the stripping circuit, measured in grams per litre (g/L). The difference between strip solution grade and spent electrolyte grade represents the copper deposited per pass.',
    `strip_solution_grade_gl` DECIMAL(18,2) COMMENT 'Copper concentration in the electrolyte strip solution (advance electrolyte) fed to the electrowinning tankhouse, measured in grams per litre (g/L). Directly controls cathode deposition rate and current efficiency in the EW circuit.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this SX-EW event record was last modified in the data platform. Used for change data capture (CDC), audit trail, and data quality monitoring in the Databricks silver layer.',
    CONSTRAINT pk_sxew_event PRIMARY KEY(`sxew_event_id`)
) COMMENT 'Transactional record of Solvent Extraction Electrowinning (SX-EW) operations per shift. Captures organic phase copper concentration (g/L), aqueous feed grade, strip solution grade, current density (A/m²), cell voltage (V), cathode production (kg/shift), and current efficiency (%). Specific to copper SX-EW processing circuits.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`reagent_consumption` (
    `reagent_consumption_id` BIGINT COMMENT 'Unique surrogate identifier for each reagent consumption record in the mineral processing circuit. Primary key for this transactional entity.',
    `chemical_register_id` BIGINT COMMENT 'Foreign key linking to hse.chemical_register. Business justification: Reagents consumed in processing must be registered chemicals with SDS, GHS classification, and handling procedures. Links consumption records to chemical hazard data for regulatory compliance (thresho',
    `circuit_id` BIGINT COMMENT 'Reference to the mineral processing circuit (e.g., flotation, leaching, SX-EW, DMS) where the reagent was applied. Enables circuit-level OPEX analysis.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Reagent costs are material opex components (often 10-30% of processing costs) allocated to cost centres for AISC calculation and budget control. reagent_consumption.cost_centre_code (plain attr) is de',
    `general_ledger_account_id` BIGINT COMMENT 'Foreign key linking to finance.general_ledger_account. Business justification: Reagent costs (cyanide, lime, collectors) are posted to specific GL accounts for AISC C1 cost reporting. reagent_consumption already has cost_centre but lacks GL account reference needed for automated',
    `goods_issue_id` BIGINT COMMENT 'Foreign key linking to procurement.goods_issue. Business justification: In mining ERP, reagent consumption triggers a goods issue (SAP movement type 201/261) from warehouse stock. Linking reagent_consumption to goods_issue enables material document reconciliation, invento',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Reagent quality samples (collectors, frothers, flocculants) analyzed at specific labs for specification compliance and batch acceptance testing. Supply chain quality control requirement to ensure reag',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant or facility where the reagent was consumed. Supports multi-site OPEX reporting and benchmarking.',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.risk_assessment. Business justification: Reagent handling activities (cyanide dosing, acid addition, xanthate use) require specific task-level risk assessments beyond the chemical register entry. Mining HSE systems link reagent consumption r',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Reagent consumption is recorded per shift run. One consumption record belongs to one shift run; one shift run has many consumption records. This links the consumption to the processing domains shift ',
    `shift_report_id` BIGINT COMMENT 'Reference to the operational shift during which the reagent was consumed. Links to the shift master for date, crew, and time-of-day context.',
    `material_master_id` BIGINT COMMENT 'Reference to the reagent master record identifying the specific chemical reagent (collector, frother, flocculant, lime, cyanide, acid, solvent, etc.) consumed.',
    `unit_operation_event_id` BIGINT COMMENT 'Foreign key linking to processing.unit_operation_event. Business justification: Reagent consumption occurs during specific unit operations (flotation, leaching, etc.). Linking reagent_consumption to unit_operation_event provides granular traceability of reagent use to the specifi',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Reagent consumption during maintenance activities (pump repairs, system flushes, reagent line maintenance) is costed against the work order for AISC and opex allocation. Mining cost accountants requir',
    `batch_lot_number` STRING COMMENT 'Supplier batch or lot number of the reagent consumed. Enables traceability for quality incidents, reagent performance investigations, and environmental compliance audits.',
    `consumption_record_number` STRING COMMENT 'Externally-visible business identifier for this consumption record, formatted as RC-YYYY-MM-NNNNNN. Used for cross-referencing with SAP material documents, LIMS records, and environmental compliance reports.. Valid values are `^RC-[0-9]{4}-[0-9]{2}-[0-9]{6}$`',
    `consumption_status` STRING COMMENT 'Current lifecycle status of the reagent consumption record. Draft records are pending operator confirmation; confirmed records are locked for OPEX reporting; adjusted records have been corrected post-shift; cancelled records are voided.. Valid values are `draft|confirmed|adjusted|cancelled`',
    `consumption_timestamp` TIMESTAMP COMMENT 'The principal real-world date and time at which the reagent consumption event occurred or was recorded by the process control system (OSIsoft PI / SCADA). Distinct from record audit timestamps.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this reagent consumption record was first created in the system. Supports audit trail, data lineage, and Silver layer ingestion tracking.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the unit cost and total cost fields (e.g., AUD, USD, ZAR). Required for multi-currency OPEX reporting and financial consolidation.. Valid values are `^[A-Z]{3}$`',
    `data_source` STRING COMMENT 'Origin of the reagent consumption data: SCADA/OSIsoft PI automated reading, manual operator entry, LabWare LIMS import, SAP ERP goods issue, or estimated value. Critical for data quality assessment and audit trail.. Valid values are `scada|manual|lims|erp|estimated`',
    `dosage_rate` DECIMAL(18,2) COMMENT 'Rate at which the reagent was dosed into the circuit, expressed in grams per tonne (g/t) of ore processed or kilograms per hour (kg/hr) depending on the reagent type and circuit. Core metric for reagent optimisation and benchmarking against LOM plan targets.',
    `dosage_rate_unit` STRING COMMENT 'Unit of measure for the reagent dosage rate field. Common units include grams per tonne (g/t) for solid reagents dosed relative to ore throughput, and kilograms per hour (kg/hr) for liquid reagents dosed by flow rate.. Valid values are `g/t|kg/hr|kg/t|L/hr|mL/t`',
    `environmental_report_required` BOOLEAN COMMENT 'Indicates whether this reagent consumption event requires mandatory environmental compliance reporting (e.g., cyanide usage under ICMC, acid consumption under EIS conditions). Drives automated compliance workflow in IsoMetrix.',
    `feed_grade_percent` DECIMAL(18,2) COMMENT 'Head grade (percentage) of the valuable mineral in the ore feed to the circuit during the shift. Contextualises reagent dosage decisions — higher feed grades may require adjusted reagent rates for optimal recovery.',
    `is_hazardous` BOOLEAN COMMENT 'Indicates whether the reagent is classified as hazardous under applicable environmental and safety regulations (e.g., cyanide, sulphuric acid). Triggers mandatory environmental compliance reporting and PPE requirements per ISO 14001 and ISO 45001.',
    `notes` STRING COMMENT 'Free-text field for operator or supervisor notes regarding the reagent consumption event, such as reasons for deviation from planned dosage, equipment issues affecting dosing, or reagent quality observations.',
    `ore_throughput_t` DECIMAL(18,2) COMMENT 'Total dry metric tonnes of ore processed through the circuit during the shift. Used as the denominator for calculating specific reagent consumption (g/t) and benchmarking against LOM plan targets.',
    `plan_dosage_rate` DECIMAL(18,2) COMMENT 'Life of Mine (LOM) plan target dosage rate for this reagent in this circuit, in the same unit as dosage_rate. Enables variance analysis between actual and planned reagent consumption for process optimisation.',
    `plan_quantity_kg` DECIMAL(18,2) COMMENT 'Life of Mine (LOM) plan target quantity of reagent for this shift and circuit in kilograms. Used for budget variance reporting and OPEX performance management against the approved mine plan.',
    `purchase_order_number` STRING COMMENT 'SAP or Pronto Xi purchase order number under which the reagent batch was procured. Enables three-way matching (PO, goods receipt, invoice) and links consumption to procurement contracts for OPEX tracking.',
    `quantity_consumed_kg` DECIMAL(18,2) COMMENT 'Total mass of reagent consumed during the shift in kilograms. Primary quantity field for OPEX cost calculation, reagent inventory reconciliation, and environmental compliance reporting of chemical usage volumes.',
    `quantity_unit` STRING COMMENT 'Unit of measure for the quantity consumed field. Defaults to kilograms (kg) for solid reagents; litres (L) for liquid reagents. Enables multi-reagent reporting with consistent unit handling.. Valid values are `kg|L|t|g`',
    `recovery_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of the valuable mineral recovered from the feed ore during the shift in this circuit. Key process performance indicator correlated with reagent dosage to assess reagent effectiveness and optimise consumption.',
    `shift_date` DATE COMMENT 'Calendar date of the shift during which the reagent was consumed. Used for daily and monthly OPEX roll-up reporting and LOM plan variance analysis.',
    `shift_type` STRING COMMENT 'Classification of the operational shift (day, night, or afternoon) during which the reagent was consumed. Supports shift-level performance analysis and reagent usage pattern identification.. Valid values are `day|night|afternoon`',
    `slurry_density_g_per_cm3` DECIMAL(18,2) COMMENT 'Density of the slurry in grams per cubic centimetre at the time of reagent consumption. Influences reagent dispersion and effectiveness; monitored via OSIsoft PI System for process control and optimisation.',
    `slurry_ph` DECIMAL(18,2) COMMENT 'pH level of the slurry (water and ore mixture) in the circuit at the time of reagent consumption. Critical process parameter for reagent effectiveness — lime and acid dosage directly controls pH for flotation and leaching circuits.',
    `specific_consumption_g_per_t` DECIMAL(18,2) COMMENT 'Reagent consumption normalised per dry metric tonne of ore processed (grams per tonne). Calculated as quantity_consumed_kg × 1000 / ore_throughput_t. Key OPEX optimisation metric and LOM plan variance indicator.',
    `supplier_name` STRING COMMENT 'Name of the supplier who provided the reagent batch consumed. Used for supplier performance management, procurement analysis, and reagent quality investigations.',
    `total_cost` DECIMAL(18,2) COMMENT 'Total Operating Expenditure (OPEX) cost of reagent consumed during the shift, calculated as quantity_consumed_kg multiplied by unit_cost. Primary financial metric for reagent OPEX tracking, budget variance, and All-In Sustaining Cost (AISC) reporting.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Cost per kilogram (or applicable unit) of the reagent at the time of consumption, sourced from the SAP purchase order or standard cost. Used for shift-level OPEX calculation and reagent cost variance analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this reagent consumption record was last modified (e.g., post-shift adjustment, supervisor confirmation). Supports change tracking and data quality monitoring in the Databricks Silver layer.',
    CONSTRAINT pk_reagent_consumption PRIMARY KEY(`reagent_consumption_id`)
) COMMENT 'Transactional record of reagent consumption per shift per circuit. Captures reagent type (collector, frother, flocculant, lime, cyanide, acid, solvent), dosage rate (g/t or kg/hr), total quantity consumed (kg), unit cost, batch lot number, and circuit applied. Supports reagent cost tracking (OPEX), optimisation, and environmental compliance reporting.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`slurry_measurement` (
    `slurry_measurement_id` BIGINT COMMENT 'Unique surrogate identifier for each slurry measurement record in the Silver Layer lakehouse. Primary key for this time-series observation table. Entity role: EVENT_LOG — append-only stream of immutable slurry parameter observations captured from OSIsoft PI System via OPC-UA at key mineral processing points.',
    `asset_id` BIGINT COMMENT 'Reference to the physical instrument or sensor asset record in the asset management system (Infor EAM) that generated this measurement. Enables traceability from measurement data to instrument maintenance history, calibration records, and asset lifecycle management. Supports instrument drift detection and predictive maintenance analytics.',
    `measurement_point_id` BIGINT COMMENT 'Reference to the process measurement point (instrument tag location) where the slurry parameters were captured. Corresponds to the PI tag source location in the OSIsoft PI System, identifying the physical sensor or instrument node in the mineral processing circuit (e.g., SAG mill discharge, flotation feed, leach feed).',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant or facility where the slurry measurement was recorded. Enables multi-site reporting and benchmarking across processing facilities within the mining operation.',
    `circuit_id` BIGINT COMMENT 'Reference to the specific processing circuit (e.g., comminution, flotation, leaching, SX-EW) within the plant where the measurement was taken. Supports circuit-level mass balance and metallurgical accounting.',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Slurry measurements are taken during a production shift run. One measurement belongs to one shift run; one shift run has many measurements. This links the measurement to the processing domains shift ',
    `shift_report_id` BIGINT COMMENT 'Reference to the operational shift during which this slurry measurement was recorded. Enables shift-level aggregation and reporting of process performance, throughput, and data quality statistics. Links to the shift schedule maintained in SAP S/4HANA HR or the mine operations shift management system.',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Slurry measurements at the plant tailings outlet (density, flow rate, pH, solids content) are used for TSF deposition planning and tailings characterisation. Linking measurement points to the receivin',
    `alarm_high_limit` DECIMAL(18,2) COMMENT 'The configured upper alarm threshold for this measurement point in the SCADA/DCS system. When the measured value exceeds this limit, an automated high alarm is generated for operator response. Expressed in the same engineering unit as the measurement. Used for automated alarm generation and process safety management.',
    `alarm_low_limit` DECIMAL(18,2) COMMENT 'The configured lower alarm threshold for this measurement point in the SCADA/DCS system. When the measured value falls below this limit, an automated low alarm is generated for operator response. Expressed in the same engineering unit as the measurement. Used for automated alarm generation and process safety management.',
    `calibration_date` DATE COMMENT 'The date of the most recent calibration performed on the instrument or sensor that generated this measurement, in yyyy-MM-dd format. Used to assess measurement reliability, identify instruments due for recalibration, and support data quality investigations. Instruments with expired calibration may have their measurements flagged as suspect in the data quality flag.',
    `conductivity_ms_cm` DECIMAL(18,2) COMMENT 'Electrical conductivity of the slurry at the measurement point, expressed in millisiemens per centimetre (mS/cm). Indicator of dissolved ion concentration, relevant for process water quality management, reagent dosing control in flotation, and environmental monitoring of process water circuits.',
    `data_quality_flag` STRING COMMENT 'OSIsoft PI System data quality status flag for this measurement record, indicating the reliability of the captured value. good = valid measurement within instrument range; suspect = value outside expected range or instrument drift detected; bad = sensor fault or communication failure; substituted = value replaced by manual entry or interpolation. Critical for downstream metallurgical mass balance calculations and automated alarm generation. Aligns with OPC-UA quality codes.. Valid values are `good|suspect|bad|substituted`',
    `deviation_from_setpoint` DECIMAL(18,2) COMMENT 'The arithmetic difference between the actual measured value and the configured process setpoint value (measured_value minus setpoint_value), expressed in the same engineering unit. A non-derived operational field captured directly from the PI System control deviation tag. Positive values indicate measurement above setpoint; negative values indicate below setpoint. Used for process control performance monitoring and alarm root cause analysis.',
    `engineering_unit` STRING COMMENT 'The unit of measurement associated with the primary measurement value for this PI tag (e.g., t/m³, %w/w, m³/hr, pH, °C, cP, mS/cm, µm). Sourced from the PI tag engineering unit configuration. Supports dynamic unit-aware analytics and cross-tag comparisons in the metallurgical historian.',
    `flow_rate_m3_hr` DECIMAL(18,2) COMMENT 'Volumetric flow rate of the slurry stream at the measurement point, expressed in cubic metres per hour (m³/hr). Measured by electromagnetic or Coriolis flow meter. Used in metallurgical mass balance, throughput calculations, and pump performance monitoring. Fundamental input for recovery rate and concentrate production calculations.',
    `ingestion_timestamp` TIMESTAMP COMMENT 'The date and time (UTC) at which this measurement record was ingested into the Databricks Lakehouse Silver Layer from the OSIsoft PI System source. Distinct from the measurement_timestamp (when the physical measurement occurred). Used for data pipeline latency monitoring, SLA tracking, and identifying late-arriving data in streaming ingestion pipelines.',
    `is_alarm_active` BOOLEAN COMMENT 'Boolean flag indicating whether an active process alarm condition existed at this measurement point at the time of measurement (True = alarm active; False = no alarm). Sourced from the SCADA/DCS alarm management system via OSIsoft PI System event frames. Enables alarm frequency analysis, process stability assessment, and operator response time reporting.',
    `is_in_control` BOOLEAN COMMENT 'Boolean flag indicating whether the measurement value was within the defined process control limits (alarm_low_limit to alarm_high_limit) at the time of measurement (True = in control; False = out of control). Supports Statistical Process Control (SPC) analysis, process stability KPIs, and automated metallurgical mass balance quality gates.',
    `mass_flow_rate_t_hr` DECIMAL(18,2) COMMENT 'Mass flow rate of dry solids in the slurry stream, expressed in dry metric tonnes per hour (t/hr). Calculated from volumetric flow rate and slurry density adjusted for percent solids. Primary throughput metric for metallurgical accounting, LOM (Life of Mine) plan tracking, and production reporting against targets.',
    `measurement_point_description` STRING COMMENT 'Human-readable description of the physical location and purpose of the measurement point within the processing circuit (e.g., SAG Mill 01 Discharge Slurry, Flotation Feed Box, CIL Tank 3 Overflow). Supports operator interpretation and alarm investigation.',
    `measurement_timestamp` TIMESTAMP COMMENT 'The precise date and time (UTC) at which the slurry parameter observation was recorded by the OSIsoft PI System historian. This is the principal event time for the measurement, distinct from record ingestion timestamps. Conforms to ISO 8601 format yyyy-MM-ddTHH:mm:ss.SSSXXX. Critical for time-series trending, process control, and metallurgical mass balance calculations.',
    `measurement_type` STRING COMMENT 'Classification of the physical parameter being measured at this process point. Identifies which slurry property this record represents, enabling filtering and aggregation by parameter type across the processing circuit. Aligns with PI tag attribute classification in the OSIsoft PI System. [ENUM-REF-CANDIDATE: density|percent_solids|flow_rate|ph|temperature|viscosity|conductivity|particle_size|mass_flow — 9 candidates stripped; promote to reference product]',
    `next_calibration_date` DATE COMMENT 'The scheduled date for the next calibration of the instrument or sensor, in yyyy-MM-dd format. Used to proactively manage instrument maintenance schedules via Infor EAM and to flag measurements from instruments approaching or past their calibration due date. Supports data quality governance and regulatory compliance for measurement traceability.',
    `opc_ua_node_reference` STRING COMMENT 'The OPC-UA (OPC Unified Architecture) node identifier for the data source that feeds this measurement into the OSIsoft PI System. Provides the source system address for data lineage, integration troubleshooting, and SCADA connectivity management. Format follows OPC-UA NodeId specification (e.g., ns=2;s=SITE.AREA.UNIT.TAG).',
    `particle_size_p80_um` DECIMAL(18,2) COMMENT 'The 80th percentile passing particle size of the solid fraction in the slurry, expressed in micrometres (µm). Key comminution performance indicator for SAG mill and HPGR circuits. P80 is the industry-standard metric for grind size control, directly impacting downstream flotation and leaching recovery rates.',
    `percent_solids` DECIMAL(18,2) COMMENT 'Weight percentage of solid material in the slurry, expressed as percent weight-by-weight (%w/w). Derived from slurry density and known ore specific gravity. A key process control parameter for comminution (SAG, HPGR), flotation, and leaching circuits. Typical operating range: 20–75 %w/w depending on circuit type.',
    `ph_value` DECIMAL(18,2) COMMENT 'Measured pH of the slurry at the measurement point on the standard pH scale (0–14). Critical process control parameter for flotation (reagent effectiveness), leaching (acid/alkaline conditions), and cyanide destruction circuits. Monitored continuously to ensure optimal mineral recovery and environmental compliance. Typical operating range varies by circuit: flotation 8–11, acid leach 1.5–2.5.',
    `pi_tag_name` STRING COMMENT 'The OSIsoft PI System tag identifier (instrument tag name) associated with this measurement point. Serves as the source system natural key enabling traceability back to the PI historian tag configuration and SCADA/OPC-UA data source. Format follows site-specific PI tag naming conventions (e.g., SITE.AREA.UNIT.PARAMETER).',
    `process_area_code` STRING COMMENT 'Alphanumeric code identifying the functional process area within the mineral processing plant where the measurement was taken (e.g., COMM for comminution, FLOT for flotation, LEACH for leaching, SXEW for SX-EW, THCK for thickening). Supports area-level operational reporting and alarm management.',
    `raw_value` DECIMAL(18,2) COMMENT 'The unprocessed, unvalidated measurement value as received directly from the OSIsoft PI System historian before any quality filtering, engineering unit conversion, or substitution is applied. Preserved for audit, instrument calibration verification, and data quality investigation. Enables comparison between raw and processed values to detect instrument drift.',
    `sample_interval_seconds` STRING COMMENT 'The configured sampling or scan interval for this PI tag in seconds, indicating how frequently the OSIsoft PI System captures a new measurement value (e.g., 1, 5, 10, 30, 60 seconds). Used to assess data density, identify gaps in time-series data, and configure alarm thresholds appropriately.',
    `sensor_status_code` STRING COMMENT 'Instrument or sensor status code as reported by the SCADA/OPC-UA system at the time of measurement. Provides granular diagnostic information beyond the data quality flag, including specific fault codes (e.g., COMM_FAIL, RANGE_HI, RANGE_LO, CAL_DUE, OFFLINE, NORMAL). Used for instrument maintenance scheduling via Infor EAM and sensor fault detection analytics. [ENUM-REF-CANDIDATE: NORMAL|COMM_FAIL|RANGE_HI|RANGE_LO|CAL_DUE|OFFLINE|FROZEN|DRIFT — promote to reference product]',
    `setpoint_value` DECIMAL(18,2) COMMENT 'The target or desired setpoint value for this measurement parameter as configured in the DCS/SCADA process control system. Expressed in the same engineering unit as the measurement. Enables deviation analysis between actual measured values and process control targets, supporting process optimisation and LOM plan performance tracking.',
    `slurry_density_t_m3` DECIMAL(18,2) COMMENT 'Measured density of the slurry (water and ore mixture) at the measurement point, expressed in tonnes per cubic metre (t/m³). Captured from nuclear density gauge or Coriolis flow meter via OPC-UA. Critical parameter for metallurgical mass balance calculations, pump sizing, and process control. Typical range for mineral processing slurries: 1.0–2.2 t/m³.',
    `source_system_record_reference` STRING COMMENT 'The natural key or record identifier from the OSIsoft PI System historian for this specific measurement event (e.g., PI event frame ID or compressed archive record reference). Enables exact traceability back to the source historian record for data lineage, audit, and reconciliation purposes in the Silver Layer lakehouse.',
    `substitution_reason` STRING COMMENT 'Reason code explaining why a measurement value was substituted when data_quality_flag = substituted. Values: manual_entry = operator manually entered value; interpolated = value interpolated from adjacent timestamps; last_known_good = previous valid value carried forward; calculated = derived from related measurements; not_applicable = no substitution occurred. Required for metallurgical mass balance audit trail and data governance compliance.. Valid values are `manual_entry|interpolated|last_known_good|calculated|not_applicable`',
    `temperature_c` DECIMAL(18,2) COMMENT 'Measured temperature of the slurry at the measurement point, expressed in degrees Celsius (°C). Relevant for leaching kinetics (heap leach, pressure oxidation), reagent reaction rates, and viscosity calculations. Monitored for process optimisation and equipment protection (e.g., pump seal integrity).',
    `viscosity_cp` DECIMAL(18,2) COMMENT 'Dynamic viscosity of the slurry at the measurement point, expressed in centipoise (cP). Affects pump performance, pipeline transport efficiency, and flotation cell hydrodynamics. Elevated viscosity can indicate high clay content or incorrect percent solids, impacting comminution and separation efficiency.',
    CONSTRAINT pk_slurry_measurement PRIMARY KEY(`slurry_measurement_id`)
) COMMENT 'Time-series measurement record of slurry parameters at key process points captured from OSIsoft PI System via OPC-UA. Captures measurement point ID, timestamp, slurry density (t/m³), percent solids (%w/w), flow rate (m³/hr), pH, temperature (°C), viscosity (cP), data quality flag (good/suspect/bad/substituted), and sensor status code. Data quality flags enable detection of sensor faults, instrument drift, and substituted values for downstream metallurgical mass balance calculations. Enables real-time process control, historian trending, and automated alarm generation.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`concentrate_batch` (
    `concentrate_batch_id` BIGINT COMMENT 'Unique surrogate identifier for each concentrate production batch record in the processing plant. Primary key for the concentrate_batch data product.',
    `assay_result_id` BIGINT COMMENT 'Foreign key linking to laboratory.assay_result. Business justification: Concentrate batches require certified assay results for commercial settlement — payable metal calculation, penalty element determination, and quality certificate issuance all depend on this link. The ',
    `cargo_shipment_id` BIGINT COMMENT 'Foreign key linking to sales.cargo_shipment. Business justification: Concentrate batches are physically loaded onto vessels for export shipment. Sales invoicing, quality certification, and revenue recognition all require traceability from production batch to specific c',
    `circuit_id` BIGINT COMMENT 'Foreign key linking to processing.circuit. Business justification: Concentrate batches are produced by specific circuits. One batch produced by one circuit; one circuit produces many batches. This links the batch to the specific circuit that produced it. The plant_id',
    `commodity_order_id` BIGINT COMMENT 'Foreign key linking to sales.commodity_order. Business justification: Batch-to-order allocation is a core mining sales process: the sales team allocates each concentrate batch to a specific commodity order for dispatch and invoicing. A domain expert expects concentrate_',
    `concentrate_stockpile_id` BIGINT COMMENT 'Foreign key linking to processing.concentrate_stockpile. Business justification: Concentrate batches are added to stockpiles. One batch is stored in one stockpile; one stockpile receives many batches. This is a standard parent FK. The storage_location_code string attribute becomes',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Concentrate batches are costed for inventory valuation (IAS 2), COGS calculation upon sale, and product-level profitability analysis. Links production output to financial inventory and revenue recogni',
    `counterparty_id` BIGINT COMMENT 'Foreign key linking to customer.counterparty. Business justification: Concentrate batches in Mining are produced for specific smelters/traders (counterparties). Commercial teams track which buyer each batch is destined for to manage offtake contracts, quality compliance',
    `delivery_destination_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_destination. Business justification: Concentrate batches are dispatched to specific delivery destinations (smelter ports, refineries). Logistics and commercial teams require this link to generate shipping instructions, quality certificat',
    `feed_stream_id` BIGINT COMMENT 'Foreign key linking to processing.feed_stream. Business justification: Concentrate batches are produced from specific feed streams. One batch from one feed stream; one feed stream produces many batches. This links the batch to the feed stream that was processed. The ore_',
    `freight_order_id` BIGINT COMMENT 'Foreign key linking to procurement.freight_order. Business justification: Concentrate batches are physically transported via freight orders. Linking concentrate_batch to freight_order enables logistics cost allocation per batch (freight cost per DMT), demurrage tracking, an',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Concentrate batches record concentrate_grade_pct and head_grade_pct for a specific element. Linking to grade_parameter enables automated bonus/penalty calculation via grade_limit and supports quality ',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Concentrate handling (dust generation, moisture control, loading/transport) can trigger environmental incidents (dust emissions) or safety incidents (slips, equipment failures). Batch-level traceabili',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to laboratory.laboratory. Business justification: Concentrate samples sent to designated labs (often umpire labs) for final grade determination, moisture content, and penalty element analysis. Critical for sales contract settlement, invoicing, and co',
    `letter_of_credit_id` BIGINT COMMENT 'Foreign key linking to customer.letter_of_credit. Business justification: In Mining concentrate sales, individual batches/shipments are covered by specific Letters of Credit issued by the buyers bank. Finance and commercial teams must link each batch to its governing LC fo',
    `lom_plan_id` BIGINT COMMENT 'Reference to the Life of Mine (LOM) plan against which this batch production is tracked and reconciled for long-term planning purposes.',
    `metallurgical_balance_id` BIGINT COMMENT 'Foreign key linking to processing.metallurgical_balance. Business justification: Each concentrate batch is produced within a metallurgical accounting period and contributes to the metallurgical balance reconciliation. Linking concentrate_batch to its metallurgical_balance period e',
    `orebody_id` BIGINT COMMENT 'Foreign key linking to geology.orebody. Business justification: Concentrate batches are traced to source orebody for product provenance, quality control, and customer specifications. Required for sales contract compliance, penalty element tracking, and demonstrati',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant where this concentrate batch was produced. Links to the plant master record.',
    `pricing_basis_id` BIGINT COMMENT 'Foreign key linking to product.pricing_basis. Business justification: Each concentrate batch is priced according to a specific pricing basis (provisional pricing percentage, quotational period, TC/RC applicability). This is a core commercial process — the pricing_basis ',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Concentrate production must be reconciled against mine production schedules for metal accounting, LOM plan tracking, and mine-to-mill optimization. Critical for integrated production reporting and fin',
    `profit_centre_id` BIGINT COMMENT 'Foreign key linking to finance.profit_centre. Business justification: Concentrate batches are the primary revenue-generating production output. Profit centre assignment on each batch enables product-level revenue recognition, period-end inventory valuation, and segment ',
    `quality_certificate_id` BIGINT COMMENT 'Foreign key linking to sales.quality_certificate. Business justification: A quality certificate is issued per concentrate batch certifying grade and composition for buyer acceptance and invoice settlement. The direct batch-to-certificate link is required for provisional-to-',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Concentrate quality issues (off-spec grade, high impurities) may trace to equipment maintenance needs (screen wear, cyclone apex wear, flotation cell condition). Links product quality problems to main',
    `royalty_obligation_id` BIGINT COMMENT 'Foreign key linking to finance.royalty_obligation. Business justification: Mining royalties are calculated on concentrate production volumes and grades per batch. Linking concentrate_batch to royalty_obligation enables automated royalty accrual per production batch — a core ',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Concentrate batches are instances of saleable products and must reference the product master for specification compliance, pricing basis, and quality parameters. The current product_type (string) shou',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Concentrate batches are produced during a production shift run. One batch belongs to one shift run; one shift run produces many batches. This links the batch to the processing domains shift entity.',
    `shift_report_id` BIGINT COMMENT 'Reference to the production shift during which this concentrate batch was produced. Used for shift-level production reporting and reconciliation.',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Concentrate batches must be traced to source tenements for royalty payment calculations based on production value, regulatory reporting by tenement, and sales contract compliance requiring origin cert',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.product_specification. Business justification: Concentrate batches must meet contractual specifications for grade, moisture, impurities. Critical for quality control, sales contract compliance, and penalty/bonus calculations. Complements existing ',
    `waste_rock_dump_id` BIGINT COMMENT 'Foreign key linking to tailings.waste_rock_dump. Business justification: Some concentrate production processes generate waste rock co-products (e.g., gravity separation rejects) sent to waste rock dumps. Material tracking requirement for inventory reconciliation and waste ',
    `batch_number` STRING COMMENT 'Externally-known alphanumeric identifier for the concentrate batch, used across sales, logistics, and laboratory systems. Format: commodity prefix, year, and sequential number (e.g., CU-2024-000123). Sourced from LabWare LIMS batch numbering.. Valid values are `^[A-Z]{2,6}-[0-9]{4}-[0-9]{6}$`',
    `batch_status` STRING COMMENT 'Current lifecycle status of the concentrate batch through the production-to-dispatch workflow: in_progress (being produced), sampled (sample taken for assay), assayed (lab results received), approved (quality approved for sale), dispatched (shipped to customer), rejected (failed quality control). Sourced from LabWare LIMS.. Valid values are `in_progress|sampled|assayed|approved|dispatched|rejected`',
    `commodity_type` STRING COMMENT 'The primary commodity contained in this concentrate batch (e.g., copper, iron ore, lithium, nickel, coal). Drives downstream sales, logistics, and regulatory reporting classification.. Valid values are `copper|iron_ore|lithium|nickel|coal`',
    `concentrate_grade_pct` DECIMAL(18,2) COMMENT 'The grade of the primary commodity in the final concentrate product for this batch, expressed as a percentage (% Cu, % Fe, % Li, % Ni). The key product quality metric used in sales contracts and customer specifications. Sourced from LabWare LIMS assay results.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this concentrate batch record was first created in the system. Audit trail field for data lineage and governance compliance.',
    `dispatch_mode` STRING COMMENT 'The primary transport mode used to dispatch this concentrate batch from the processing plant to the port or customer (e.g., rail, road, ship, pipeline, conveyor). Determines logistics cost allocation and supply chain planning.. Valid values are `rail|road|ship|pipeline|conveyor`',
    `dry_weight_dmt` DECIMAL(18,2) COMMENT 'Dry weight of the concentrate batch in dry metric tonnes (DMT), calculated after moisture correction. The primary commercial weight measure used for sales contracts, invoicing, and production reporting. Key SSOT field for concentrate production output.',
    `energy_consumption_kwh_t` DECIMAL(18,2) COMMENT 'Electrical energy consumed per tonne of ore processed for this concentrate batch, expressed in kilowatt-hours per tonne (kWh/t). Sourced from OSIsoft PI System. Key OPEX and sustainability metric tracked against LOM plan targets.',
    `feed_tonnes` DECIMAL(18,2) COMMENT 'Total dry metric tonnes of Run of Mine (ROM) ore fed into the processing circuit to produce this concentrate batch. Used as the denominator in recovery rate and yield calculations.',
    `head_grade_pct` DECIMAL(18,2) COMMENT 'The grade of the primary commodity in the feed ore (Run of Mine (ROM)) entering the processing circuit for this batch, expressed as a percentage (%). Represents the input quality before beneficiation. Used for recovery rate calculation and reconciliation.',
    `impurity_silica_pct` DECIMAL(18,2) COMMENT 'Silica (SiO2) content in the concentrate batch expressed as a percentage (%). A key gangue impurity that affects product quality, smelter penalties, and customer acceptance. Sourced from LabWare LIMS assay results.',
    `impurity_sulfur_pct` DECIMAL(18,2) COMMENT 'Sulfur (S) content in the concentrate batch expressed as a percentage (%). A critical impurity for smelter operations and environmental compliance. High sulfur levels may attract penalties or rejection. Sourced from LabWare LIMS.',
    `is_quality_approved` BOOLEAN COMMENT 'Indicates whether this concentrate batch has passed quality control review and been formally approved for sale or dispatch. True = approved; False = pending or rejected. Set by the metallurgist or quality manager in LabWare LIMS.',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content of the concentrate batch expressed as a percentage (%) of wet weight. Determined by laboratory analysis per ISO 3087. Critical for DMT calculation and product quality compliance.',
    `particle_size_p80_um` DECIMAL(18,2) COMMENT 'The P80 particle size of the concentrate batch in micrometres (µm), representing the sieve size through which 80% of the material passes. Critical comminution (size reduction) quality parameter affecting downstream processing efficiency and product specification compliance.',
    `process_route` STRING COMMENT 'The mineral processing route used to produce this concentrate batch (e.g., flotation, leaching, Dense Media Separation (DMS), Solvent Extraction Electrowinning (SX-EW), High Pressure Grinding Rolls (HPGR), Semi-Autogenous Grinding (SAG)). Determines applicable quality standards and reagent profiles. [ENUM-REF-CANDIDATE: flotation|leaching|DMS|SX-EW|HPGR|SAG|gravity|magnetic_separation — promote to reference product]',
    `production_date` DATE COMMENT 'Calendar date on which this concentrate batch was produced at the processing plant. Used for daily production reporting and reconciliation against the production schedule.',
    `production_timestamp` TIMESTAMP COMMENT 'Precise date and time when the concentrate batch production was completed and the batch was sealed/finalised at the processing plant. Sourced from OSIsoft PI System historian.',
    `provisional_price_usd_dmt` DECIMAL(18,2) COMMENT 'The provisional sale price per dry metric tonne (DMT) in US dollars (USD) agreed at the time of dispatch, subject to final price adjustment based on quotation period commodity prices. Used for initial revenue recognition under IFRS 15.',
    `quality_approved_timestamp` TIMESTAMP COMMENT 'Date and time when the concentrate batch was formally approved for sale following quality control review. Represents a key lifecycle milestone in the batch workflow. Sourced from LabWare LIMS.',
    `quality_grade` STRING COMMENT 'The quality classification assigned to this concentrate batch based on assay results and product specification compliance. Grade A = premium specification met; Grade B = standard specification met; Grade C = marginal specification; off_spec = outside specification but saleable; rejected = failed quality control and cannot be sold.. Valid values are `A|B|C|off_spec|rejected`',
    `reagent_consumption_kg_t` DECIMAL(18,2) COMMENT 'Total reagent consumption per tonne of ore processed for this concentrate batch, expressed in kilograms per tonne (kg/t). Aggregates all flotation, leaching, or other process reagents. Used for operating expenditure (OPEX) tracking and process efficiency analysis.',
    `recovery_rate_pct` DECIMAL(18,2) COMMENT 'The percentage of the valuable mineral in the feed ore that is successfully recovered into the concentrate product for this batch. Calculated as (concentrate grade × DMT) / (head grade × feed tonnes) × 100. Key processing efficiency KPI tracked against LOM plan targets.',
    `sample_date` DATE COMMENT 'The date on which the representative sample was taken from this concentrate batch for laboratory assay analysis. Used for sample chain-of-custody tracking and quality control compliance.',
    `slurry_density_gcm3` DECIMAL(18,2) COMMENT 'The density of the concentrate slurry (water and ore mixture) in grams per cubic centimetre (g/cm³) at the point of batch finalisation. Monitored via OSIsoft PI System SCADA. Used for process control and dewatering circuit optimisation.',
    `throughput_tph` DECIMAL(18,2) COMMENT 'The average ore processing throughput rate in tonnes per hour (tph) achieved during the production of this concentrate batch. Sourced from OSIsoft PI System SCADA historian. Used for Overall Equipment Effectiveness (OEE) and capacity utilisation analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this concentrate batch record was last modified. Audit trail field used for change tracking, data lineage, and Silver Layer incremental processing in the Databricks Lakehouse.',
    `water_consumption_m3_t` DECIMAL(18,2) COMMENT 'Process water consumed per tonne of ore processed for this concentrate batch, expressed in cubic metres per tonne (m³/t). Critical environmental compliance metric reported under ISO 14001 and GRI Mining and Metals Sector Supplement.',
    `wet_weight_t` DECIMAL(18,2) COMMENT 'Total wet weight of the concentrate batch in metric tonnes (t) as measured at the processing plant prior to moisture correction. Used as the basis for moisture content calculation.',
    `yield_pct` DECIMAL(18,2) COMMENT 'The mass yield of concentrate produced as a percentage of the total ore feed for this batch (DMT concentrate / feed tonnes × 100). Indicates the ratio of product output to ore input and is used for process efficiency benchmarking.',
    CONSTRAINT pk_concentrate_batch PRIMARY KEY(`concentrate_batch_id`)
) COMMENT 'Master record of each concentrate production batch produced at the processing plant. Captures batch number, commodity type (copper concentrate, iron ore fines, lithium hydroxide), production date, dry weight (dmt), moisture content (%), head grade, concentrate grade (% Cu, % Fe, % Li), and recovery rate (%). SSOT for concentrate production output linked to sales and product domains.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`metallurgical_balance` (
    `metallurgical_balance_id` BIGINT COMMENT 'Unique surrogate identifier for each metallurgical balance record in the processing domain. Primary key for the metallurgical_balance data product.',
    `block_model_id` BIGINT COMMENT 'Foreign key linking to geology.block_model. Business justification: Mine-to-mill reconciliation compares metallurgical_balance feed_grade and feed_tonnes_dry against block model grade and tonnage predictions. This is a mandatory reconciliation process for JORC reserve',
    `circuit_id` BIGINT COMMENT 'Reference to the specific processing circuit (e.g., SAG mill circuit, flotation circuit, leach circuit, SX-EW circuit) within the plant for which this balance applies.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Metallurgical balances are commodity-specific for mass/metal accounting. Essential for JORC compliance, resource reconciliation, and ore reserve reporting. Replaces denormalized commodity text field. ',
    `competent_person_id` BIGINT COMMENT 'Reference to the qualified competent person responsible for signing off this metallurgical balance, as required under JORC, NI 43-101, or SAMREC reporting standards.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Metallurgical accounting periods reconcile metal production to cost centres for financial reporting, variance analysis, and AISC calculation. Core mining finance process linking technical metallurgica',
    `geological_domain_id` BIGINT COMMENT 'Foreign key linking to geology.geological_domain. Business justification: Metallurgical balance reconciliation benchmarks measured_recovery_pct and theoretical_recovery_pct against geological domain predictions. Mine-to-mill reconciliation reports are structured by geologic',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Metallurgical balance records feed_grade and concentrate_grade for a specific element/parameter. Linking to grade_parameter ensures the balance references the correct parameter definition and unit for',
    `lom_plan_id` BIGINT COMMENT 'Reference to the Life of Mine (LOM) plan version against which this metallurgical balance is being reconciled. Enables tracking of actual performance versus long-term plan targets.',
    `mining_block_id` BIGINT COMMENT 'Foreign key linking to mine.mining_block. Business justification: Metallurgical balances reconcile processing performance against mining block model predictions for resource model updates, F1/F2/F3 factor calculation, and geological domain recovery characterization.',
    `ore_reserve_id` BIGINT COMMENT 'Foreign key linking to exploration.ore_reserve. Business justification: Mine-to-mill reconciliation compares actual metallurgical balance outcomes against ore reserve predictions. This is a mandatory practice for reserve confidence reporting and investor disclosure. The b',
    `orebody_id` BIGINT COMMENT 'Foreign key linking to geology.orebody. Business justification: Metallurgical balances are calculated per orebody to track recovery performance by ore source. Essential for resource-to-reserve conversion, mine planning optimization, and validating geological model',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant or circuit where this metallurgical balance was recorded. Links to the plant master in the processing domain.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Metallurgical balances reconcile processing performance against scheduled mine production for period-based metal accounting, recovery variance analysis, and integrated mine-mill performance reporting ',
    `profit_centre_id` BIGINT COMMENT 'Foreign key linking to finance.profit_centre. Business justification: Metallurgical balance is the authoritative period-end production reconciliation document used for financial reporting, royalty calculations, and segment disclosure. Profit centre linkage enables the b',
    `resource_estimate_id` BIGINT COMMENT 'Foreign key linking to exploration.resource_estimate. Business justification: Metallurgical balances validate resource estimate recovery assumptions. Required for reserve conversion, competent person sign-off, and JORC/NI 43-101 compliance. Real business need: resource-to-reser',
    `rom_stockpile_id` BIGINT COMMENT 'Foreign key linking to mine.rom_stockpile. Business justification: Metallurgical balances are routinely prepared per ROM stockpile source to quantify grade contribution and recovery by ore source. This is a standard mine-to-mill accounting requirement — metallurgists',
    `royalty_obligation_id` BIGINT COMMENT 'Foreign key linking to finance.royalty_obligation. Business justification: Metallurgical balance provides the reconciled production figures (tonnes, grade, metal units) used as the basis for period royalty calculations submitted to government. Direct link to royalty_obligati',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Metallurgical balance periods are reconciled per saleable product for financial reporting and production accounting. commodity_id alone is insufficient — a plant producing both copper cathode and copp',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Metallurgical balances reconcile production against tenement reserves and are required for statutory reporting by tenement to regulatory authorities. Essential for reserve depletion tracking and compl',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Metallurgical balance periods must reconcile tailings_tonnes_dry sent to specific TSF. Fundamental accounting control for mass balance closure, regulatory reporting, and TSF capacity verification. Lin',
    `accounting_period_end` DATE COMMENT 'End date of the metallurgical accounting period covered by this balance record. Together with accounting_period_start defines the reconciliation window.',
    `accounting_period_start` DATE COMMENT 'Start date of the metallurgical accounting period covered by this balance record (daily, weekly, or monthly). Aligns with the financial reporting calendar.',
    `adjustment_authoriser` STRING COMMENT 'Name or employee identifier of the competent person or authorised metallurgist who approved the adjustment or restatement of this balance record. Required for JORC-compliant audit trail and regulatory sign-off.',
    `adjustment_reason` STRING COMMENT 'Free-text description of the reason for any adjustment or restatement applied to this version of the metallurgical balance (e.g., assay rerun, sampling error correction, instrument calibration update, stockpile reweigh). Required for audit trail and competent person sign-off.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this metallurgical balance record was formally approved and signed off by the competent person. Marks the transition to approved status in the balance workflow.',
    `balance_reference` STRING COMMENT 'Externally-known business identifier for the metallurgical balance record, used in reports, sign-off documentation, and regulatory submissions. Format: METBAL-YYYY-MM-NNNNNN.. Valid values are `^METBAL-[0-9]{4}-[0-9]{2}-[0-9]{6}$`',
    `balance_status` STRING COMMENT 'Current workflow status of the metallurgical balance record: draft (in preparation), submitted (awaiting review), under_review (being assessed by competent person), approved (signed off), or rejected (returned for correction).. Valid values are `draft|submitted|under_review|approved|rejected`',
    `concentrate_grade` DECIMAL(18,2) COMMENT 'Assayed grade of the concentrate product expressed in the same unit as feed_grade_unit. Determines the commercial value and smelter payability of the concentrate.',
    `concentrate_tonnes_dry` DECIMAL(18,2) COMMENT 'Total dry metric tonnes of concentrate product produced during the accounting period. Represents the valuable mineral product output from the processing circuit.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this metallurgical balance record was first created in the system. Audit trail field for data lineage and Silver layer ingestion tracking.',
    `dilution_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of waste rock (gangue) dilution in the feed material, representing the proportion of non-ore material included during mining and haulage. Impacts feed grade and recovery.',
    `energy_consumption_kwh` DECIMAL(18,2) COMMENT 'Total electrical energy consumed by the processing circuit during the accounting period in kilowatt hours. Key OPEX component and sustainability metric reported under GRI and ICMM frameworks.',
    `feed_grade` DECIMAL(18,2) COMMENT 'Assayed head grade of the feed material expressed as percentage (%) for base metals or grams per tonne (g/t) for precious metals. Determined by LabWare LIMS assay results on feed samples.',
    `feed_grade_unit` STRING COMMENT 'Unit of measure for the feed head grade value: pct (percentage), g_per_t (grams per tonne), kg_per_t (kilograms per tonne), or ppm (parts per million). Varies by commodity.. Valid values are `pct|g_per_t|kg_per_t|ppm`',
    `feed_moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content of the feed material as a percentage of wet weight. Used to convert wet tonnes to dry tonnes for metallurgical accounting purposes.',
    `feed_tonnes_dry` DECIMAL(18,2) COMMENT 'Total dry metric tonnes of Run of Mine (ROM) ore fed to the processing circuit during the accounting period. Dry weight basis is the standard for metallurgical accounting.',
    `is_current_version` BOOLEAN COMMENT 'Indicates whether this record is the current (latest approved) version of the metallurgical balance for the given period and circuit. True = current version; False = superseded version retained for audit trail.',
    `mass_balance_closure_pct` DECIMAL(18,2) COMMENT 'Mass balance closure expressed as a percentage: (concentrate_tonnes_dry + tailings_tonnes_dry) / feed_tonnes_dry × 100. Values outside 98–102% typically trigger investigation and adjustment.',
    `measured_recovery_pct` DECIMAL(18,2) COMMENT 'Actual metallurgical recovery percentage calculated from assayed feed, concentrate, and tailings grades and tonnes using the standard two-product formula. Represents the proportion of valuable mineral recovered into concentrate.',
    `metal_units_feed` DECIMAL(18,2) COMMENT 'Total contained metal units in the feed stream for the period, calculated as feed_tonnes_dry × feed_grade. Expressed in tonnes of metal or troy ounces depending on commodity. Key input to JORC resource-to-reserve reconciliation.',
    `metal_units_recovered` DECIMAL(18,2) COMMENT 'Total contained metal units recovered into concentrate for the period, calculated as concentrate_tonnes_dry × concentrate_grade. Used in LOM plan tracking and sales reconciliation.',
    `ore_type` STRING COMMENT 'Geological ore type classification of the feed material processed during the period (e.g., oxide, sulphide, transitional, fresh, weathered). Ore type significantly influences metallurgical recovery and reagent consumption.',
    `period_type` STRING COMMENT 'Granularity of the metallurgical accounting period: daily, weekly, monthly, quarterly, or annual. Determines the reporting frequency and aggregation level for LOM plan tracking.. Valid values are `daily|weekly|monthly|quarterly|annual`',
    `plant_availability_pct` DECIMAL(18,2) COMMENT 'Percentage of the accounting period during which the processing plant was available for production (scheduled hours minus planned and unplanned downtime). Component of Overall Equipment Effectiveness (OEE).',
    `reagent_consumption_kg_per_t` DECIMAL(18,2) COMMENT 'Total reagent consumption per dry metric tonne of feed processed during the period, aggregated across all reagents (collectors, frothers, pH modifiers, leach reagents). Key OPEX driver for processing cost reporting.',
    `recovery_variance_pct` DECIMAL(18,2) COMMENT 'Difference between measured_recovery_pct and theoretical_recovery_pct (measured minus theoretical). Positive value indicates outperformance; negative indicates underperformance against LOM plan.',
    `tailings_grade` DECIMAL(18,2) COMMENT 'Assayed grade of the tailings stream expressed in the same unit as feed_grade_unit. Indicates the residual valuable mineral content lost to tailings; key input to recovery calculation and environmental reporting.',
    `tailings_tonnes_dry` DECIMAL(18,2) COMMENT 'Total dry metric tonnes of tailings (gangue and process waste) discharged to the Tailings Storage Facility (TSF) during the accounting period. Used in mass balance closure and TSF capacity planning.',
    `theoretical_recovery_pct` DECIMAL(18,2) COMMENT 'Theoretical or planned recovery percentage for the period based on LOM plan targets, ore type characterisation, and process design parameters. Used as the benchmark for variance analysis.',
    `throughput_rate_tph` DECIMAL(18,2) COMMENT 'Average processing throughput rate in dry metric tonnes per hour during the accounting period. Key operational KPI for plant performance against design capacity and LOM plan.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this metallurgical balance record was last modified. Updated on every version increment, adjustment, or status change. Supports audit trail requirements.',
    `version_number` STRING COMMENT 'Sequential version number of this metallurgical balance record for the given period and circuit. Increments with each adjustment or restatement, supporting full audit trail and competent person sign-off requirements.',
    `water_consumption_m3` DECIMAL(18,2) COMMENT 'Total fresh water consumed by the processing circuit during the accounting period in cubic metres. Reported for environmental compliance under ISO 14001 and GRI Mining and Metals Sector Supplement.',
    CONSTRAINT pk_metallurgical_balance PRIMARY KEY(`metallurgical_balance_id`)
) COMMENT 'Periodic (daily/weekly/monthly) metallurgical accounting reconciliation record for a processing circuit or plant. Captures accounting period, feed tonnes, feed grade, concentrate tonnes, concentrate grade, tailings tonnes, tailings grade, calculated recovery (%), theoretical recovery, reconciliation variance, adjustment reason, adjustment authoriser, and version number for audit trail. Supports JORC-compliant resource-to-reserve reconciliation, LOM plan tracking, and regulatory reporting. Versioned records with adjustment metadata provide the audit trail required for metallurgical balance sign-off by competent persons.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`recovery_target` (
    `recovery_target_id` BIGINT COMMENT 'Unique surrogate identifier for each recovery target record in the LOM plan-derived processing circuit performance baseline.',
    `block_model_id` BIGINT COMMENT 'Foreign key linking to geology.block_model. Business justification: Recovery targets are derived from block model grade distributions and metallurgical domain assignments during LOM planning. Mine planners use block model data to set target_recovery_pct and target_hea',
    `circuit_id` BIGINT COMMENT 'Reference to the mineral processing circuit (e.g., SAG mill circuit, flotation circuit, SX-EW circuit, DMS circuit) for which this recovery target applies.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Recovery targets are set per commodity in LOM plans and feasibility studies. Core to mine planning, economic modeling, and performance tracking. Replaces denormalized commodity text field with proper ',
    `geological_domain_id` BIGINT COMMENT 'Foreign key linking to geology.geological_domain. Business justification: Recovery targets are set per geological domain because oxide, sulphide, and transitional domains have fundamentally different metallurgical recovery characteristics. Mine planners set target_recovery_',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Recovery targets are set per grade parameter — Cu recovery target differs from Au recovery target even in the same circuit. LOM planning requires recovery targets to reference the specific grade param',
    `lom_plan_id` BIGINT COMMENT 'Reference to the Life of Mine (LOM) plan version from which this recovery target is derived. Enables traceability of targets back to the authorised planning document.',
    `metallurgical_test_id` BIGINT COMMENT 'Foreign key linking to laboratory.metallurgical_test. Business justification: Recovery targets are derived from and must be traceable to specific metallurgical test results (flotation kinetics, leach extraction curves, grind-recovery relationships). The feasibility_study_ref pl',
    `mining_block_id` BIGINT COMMENT 'Foreign key linking to mine.mining_block. Business justification: Recovery targets vary by mining block ore type, grade, and metallurgical domain for domain-based planning, ore type scheduling, and metallurgical performance forecasting. Critical for LOM planning wit',
    `ore_reserve_id` BIGINT COMMENT 'Foreign key linking to exploration.ore_reserve. Business justification: Recovery targets are modifying factors applied to ore reserves under JORC/NI43-101 reporting standards. Metallurgists set recovery targets directly from ore reserve grade and mineralogy assumptions. C',
    `orebody_id` BIGINT COMMENT 'Foreign key linking to geology.orebody. Business justification: Recovery targets are set per orebody based on geological characteristics, mineralogy, and metallurgical testwork. Life-of-mine planning requires orebody-specific recovery assumptions to accurately for',
    `plant_id` BIGINT COMMENT 'Reference to the mineral processing plant or facility where the circuit operates. Supports multi-site recovery target management.',
    `profit_centre_id` BIGINT COMMENT 'Foreign key linking to finance.profit_centre. Business justification: Processing recovery targets are set during budget and LOM planning at profit centre level. Linking enables variance reporting between budgeted recovery targets and actual metallurgical balance results',
    `prospect_id` BIGINT COMMENT 'Foreign key linking to exploration.prospect. Business justification: Recovery targets are set per ore source/prospect because different prospects have distinct metallurgical characteristics (mineralogy, hardness, grade variability). Plants processing ore from multiple ',
    `regulatory_condition_id` BIGINT COMMENT 'Foreign key linking to tenement.regulatory_condition. Business justification: Mining licences frequently impose minimum metallurgical recovery conditions on tenement holders. Processing recovery targets are set to comply with these regulatory conditions. Compliance reporting re',
    `resource_estimate_id` BIGINT COMMENT 'Foreign key linking to exploration.resource_estimate. Business justification: Recovery targets are derived from resource estimate metallurgical assumptions. Critical for LOM planning, economic modeling, and feasibility study validation. Real business need: linking processing ta',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Recovery targets are set per saleable product — copper cathode recovery targets differ from copper concentrate targets even from the same ore. LOM planning and feasibility studies set recovery targets',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Recovery targets are set in the context of a specific product specification — the target grade and impurity limits define the required recovery percentage. LOM planning and feasibility studies explici',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Recovery targets are set per tenement because ore characteristics and LOM economics are tenement-specific. Feasibility studies and LOM planning require recovery targets attributed to the tenement from',
    `volume_plan_id` BIGINT COMMENT 'Foreign key linking to sales.volume_plan. Business justification: Production-to-sales volume planning alignment is a core mining commercial process: the sales volume plan is built directly from processing recovery targets (planned throughput, recovery rate, concentr',
    `approved_by` STRING COMMENT 'Name or identifier of the Competent Person or authorised technical authority who approved this recovery target for use in LOM planning and variance reporting. Required for JORC/NI 43-101 traceability.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this recovery target was formally approved by the authorised Competent Person or planning authority. Provides audit trail for regulatory and governance compliance.',
    `basis_type` STRING COMMENT 'Classification of the technical study or planning document type that forms the basis for this recovery target (e.g., LOM plan, definitive feasibility study, pre-feasibility study, scoping study, annual budget). Indicates the confidence level and authority of the target.. Valid values are `lom_plan|feasibility_study|pre_feasibility|scoping_study|budget`',
    `concentrate_grade_unit` STRING COMMENT 'Unit of measure for the target concentrate grade value (e.g., pct for percentage, g_per_t for grams per tonne). Ensures correct interpretation of the concentrate quality specification.. Valid values are `pct|g_per_t|ppm|kg_per_t`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this recovery target record was first created in the data platform. Provides audit trail for data lineage and governance.',
    `effective_from` DATE COMMENT 'Date from which this recovery target version becomes the active baseline for variance analysis and performance reporting. Supports Slowly Changing Dimension (SCD) Type 2 versioning of LOM plan targets.',
    `effective_until` DATE COMMENT 'Date on which this recovery target version ceases to be the active baseline, typically when superseded by a revised LOM plan. Null indicates the record is currently active. Supports SCD Type 2 versioning.',
    `feasibility_study_ref` STRING COMMENT 'Document reference number or title of the feasibility study, pre-feasibility study (PFS), or definitive feasibility study (DFS) from which this recovery target is derived. Provides audit traceability to the authorised technical study.',
    `head_grade_unit` STRING COMMENT 'Unit of measure for the target head grade value (e.g., pct for percentage, g_per_t for grams per tonne, ppm for parts per million). Ensures correct interpretation of the grade figure across different commodities.. Valid values are `pct|g_per_t|ppm|kg_per_t`',
    `is_current_version` BOOLEAN COMMENT 'Indicates whether this record represents the current active version of the recovery target for the given circuit, commodity, ore type, and period. Supports efficient querying of the latest approved targets without filtering on version history.',
    `lom_plan_version` STRING COMMENT 'Version identifier of the LOM plan from which this target is derived (e.g., LOM-2024-v3.1). Enables tracking of target changes across successive LOM plan revisions and supports variance analysis against the correct plan baseline.',
    `metal_units_unit` STRING COMMENT 'Unit of measure for the target contained metal units (e.g., t for metric tonnes, oz for troy ounces, lb for pounds). Ensures correct interpretation across different commodity reporting conventions.. Valid values are `t|kt|oz|koz|lb|klb`',
    `notes` STRING COMMENT 'Free-text field for recording planning assumptions, metallurgical test work caveats, ore type blending assumptions, or other contextual information relevant to the interpretation of this recovery target.',
    `ore_type` STRING COMMENT 'Classification of the ore type or metallurgical domain for which this target applies (e.g., oxide, sulphide, transitional, mixed, fresh). Ore type significantly influences achievable recovery rates and processing parameters.',
    `processing_route` STRING COMMENT 'The primary mineral processing method or beneficiation route for which this target applies (e.g., flotation, Dense Media Separation (DMS), leaching, Solvent Extraction Electrowinning (SX-EW), High Pressure Grinding Rolls (HPGR), Semi-Autogenous Grinding (SAG)). [ENUM-REF-CANDIDATE: flotation|leaching|dms|sxew|gravity|magnetic_separation|hpgr|sag|cil|cip|other — promote to reference product]',
    `target_concentrate_grade` DECIMAL(18,2) COMMENT 'Planned grade of the final concentrate or product output from the processing circuit during the target period, expressed in the unit defined by concentrate_grade_unit. Represents the quality specification for the saleable product.',
    `target_concentrate_kt` DECIMAL(18,2) COMMENT 'Planned total dry metric tonnes of concentrate (in kilotonnes) to be produced during the target period. Supports sales planning, logistics scheduling, and LOM revenue forecasting.',
    `target_energy_consumption_kwh` DECIMAL(18,2) COMMENT 'Planned total electrical energy consumption in kilowatt-hours for the processing circuit during the target period. Used for energy cost budgeting, carbon footprint reporting, and OPEX modelling.',
    `target_feed_moisture_pct` DECIMAL(18,2) COMMENT 'Planned moisture content of the Run of Mine (ROM) feed entering the processing circuit, expressed as a percentage. Affects dry tonne calculations, throughput, and reagent dosing. Derived from ore characterisation in the feasibility study.',
    `target_head_grade` DECIMAL(18,2) COMMENT 'Planned feed grade (head grade) of the ore entering the processing circuit during the target period, expressed in the unit defined by head_grade_unit. Derived from the mine plan and geological resource model.',
    `target_mass_pull_pct` DECIMAL(18,2) COMMENT 'Planned mass pull percentage — the proportion of feed mass reporting to the concentrate stream. A key flotation circuit design parameter that balances recovery against concentrate grade. Derived from metallurgical test work in the feasibility study.',
    `target_metal_units` DECIMAL(18,2) COMMENT 'Planned quantity of contained metal units to be recovered during the target period, expressed in the unit defined by metal_units_unit (e.g., tonnes of copper, ounces of gold). Core metric for LOM production target and revenue planning.',
    `target_period_end` DATE COMMENT 'End date of the planning period to which this recovery target applies. Defines the upper boundary of the target window for performance measurement and LOM plan variance reporting.',
    `target_period_start` DATE COMMENT 'Start date of the planning period to which this recovery target applies. Combined with target_period_end to define the exact window for variance analysis against actual metallurgical balance results.',
    `target_period_type` STRING COMMENT 'Granularity of the planning period for which this recovery target is defined: monthly, quarterly, annual, or full Life of Mine (LOM). Determines the temporal resolution of variance analysis.. Valid values are `monthly|quarterly|annual|lom`',
    `target_plant_availability_pct` DECIMAL(18,2) COMMENT 'Planned plant availability percentage for the processing circuit during the target period, representing the proportion of scheduled time the plant is available for production. Used in conjunction with throughput targets to derive planned production volumes.',
    `target_reagent_consumption` DECIMAL(18,2) COMMENT 'Planned total reagent consumption rate in kilograms per dry metric tonne of ore processed. Aggregated across all reagents for the circuit. Used for OPEX budgeting and reagent procurement planning.',
    `target_recovery_pct` DECIMAL(18,2) COMMENT 'Planned metallurgical recovery rate expressed as a percentage of valuable mineral recovered from feed to final product (concentrate or cathode). Derived from LOM plan or feasibility study metallurgical test work. Core KPI for processing performance variance analysis.',
    `target_reference` STRING COMMENT 'Externally-known business identifier for this recovery target record, used in planning documents, feasibility studies, and variance reporting (e.g., RT-CU-FL-202401).. Valid values are `^RT-[A-Z0-9]{3,10}-[0-9]{4,8}$`',
    `target_status` STRING COMMENT 'Current lifecycle status of this recovery target record: draft (under preparation), approved (authorised for use in variance reporting), superseded (replaced by a newer version), or archived (no longer active).. Valid values are `draft|approved|superseded|archived`',
    `target_throughput_kt` DECIMAL(18,2) COMMENT 'Total planned dry metric tonnes (in kilotonnes) to be processed through the circuit during the target period. Complements the rate-based tph target for period-level production planning and LOM schedule adherence.',
    `target_throughput_tph` DECIMAL(18,2) COMMENT 'Planned processing throughput rate in dry metric tonnes per hour (tph) for the circuit during the target period. Used to assess whether actual mill throughput meets LOM plan expectations.',
    `target_utilisation_pct` DECIMAL(18,2) COMMENT 'Planned plant utilisation percentage — the proportion of available time the plant is actually operating and processing ore. Distinct from availability; utilisation reflects operational efficiency within available time.',
    `target_water_consumption_m3` DECIMAL(18,2) COMMENT 'Planned total water consumption in cubic metres for the processing circuit during the target period. Supports water balance management, environmental licence compliance, and sustainability reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this recovery target record was last modified in the data platform. Supports change tracking and data quality monitoring.',
    CONSTRAINT pk_recovery_target PRIMARY KEY(`recovery_target_id`)
) COMMENT 'LOM plan-derived recovery rate targets per processing circuit, commodity, and ore type. Captures target period (month/quarter/year), circuit ID, ore type, target recovery (%), target throughput (tph), target head grade, target concentrate grade, and basis (LOM plan version, feasibility study reference). Enables variance analysis between actual and planned recovery performance.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`operational_exception` (
    `operational_exception_id` BIGINT COMMENT 'Primary key for operational_exception',
    `asset_id` BIGINT COMMENT 'Identifier of the primary piece of equipment directly involved in or causing the operational exception. Links to the equipment asset register.',
    `blast_execution_id` BIGINT COMMENT 'Foreign key linking to mine.blast_execution. Business justification: Processing upsets (crusher blockages, mill overloads, poor fragmentation) are frequently caused by blast quality issues. Linking operational exceptions to the originating blast enables blast-to-plant ',
    `circuit_id` BIGINT COMMENT 'Identifier of the specific processing circuit affected by the exception (e.g., SAG mill circuit, flotation circuit, leach circuit, SX-EW circuit, DMS circuit). Links to the circuit master.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Operational exceptions (unplanned downtime, process upsets) cause production losses that must be costed and reported against cost centres for variance analysis, insurance claims, and OEE cost impact r',
    `downtime_event_id` BIGINT COMMENT 'Foreign key linking to equipment.downtime_event. Business justification: Processing operational exceptions (circuit trips, process upsets) are directly caused by or cause equipment downtime events. Linking them supports cross-domain root cause analysis, OEE loss categorisa',
    `failure_report_id` BIGINT COMMENT 'Foreign key linking to maintenance.failure_report. Business justification: Processing operational exceptions (mill trips, pump failures, process upsets) directly generate maintenance failure reports for the same event. Mining operations use this cross-domain link for integra',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: Operational exceptions (downtime, process upsets) occur at specific functional locations. Links exceptions to maintenance functional location hierarchy for root cause analysis, maintenance planning, a',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Processing plant downtime events that trigger HSE incidents must reference the formal incident record for compliance reporting and root cause analysis. The current hse_incident_reference (string) shou',
    `lom_plan_id` BIGINT COMMENT 'Identifier of the Life of Mine (LOM) plan version against which production loss from this exception is measured. Enables variance reporting between actual downtime impact and LOM plan targets.',
    `plant_id` BIGINT COMMENT 'Identifier of the mineral processing plant where the operational exception occurred. Links to the plant master record.',
    `regulatory_condition_id` BIGINT COMMENT 'Foreign key linking to tenement.regulatory_condition. Business justification: Process upsets and environmental exceedances at a plant may constitute breaches of tenement regulatory conditions, triggering mandatory regulatory reporting. Regulators require that each notifiable op',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.risk_assessment. Business justification: Operational exceptions (process upsets, control deviations) are reviewed against the governing risk assessment to determine if critical controls were breached. Mining process safety management require',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Operational exceptions occur during a production shift run. One exception belongs to one shift run; one shift run has many exceptions. This links the exception to the processing domains shift entity.',
    `shift_report_id` BIGINT COMMENT 'Identifier of the shift report during which this operational exception was recorded. Links to the mine or plant shift report.',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Processing plant operational exceptions are frequently caused by TSF constraints — tailings line blockages, TSF freeboard limits forcing throughput curtailment, or TSF pump failures. Linking exception',
    `unit_operation_event_id` BIGINT COMMENT 'Foreign key linking to processing.unit_operation_event. Business justification: Operational exceptions (unplanned downtime, process upsets, alarm events) occur during specific unit operation events. Linking operational_exception to unit_operation_event provides direct traceabilit',
    `work_order_id` BIGINT COMMENT 'Identifier of the maintenance work order raised in response to this operational exception. Enables linkage to the maintenance domain for corrective or emergency work orders.',
    `actual_value` DECIMAL(18,2) COMMENT 'The measured actual value of the process parameter at the time of the deviation or alarm event. Compared against setpoint_value to determine deviation magnitude and against alarm limits for threshold breach analysis.',
    `alarm_limit_high` DECIMAL(18,2) COMMENT 'The configured high alarm threshold for the process parameter at the time of the event. Used to contextualise whether the actual_value breached the high alarm boundary and to support alarm rationalisation analysis.',
    `alarm_limit_low` DECIMAL(18,2) COMMENT 'The configured low alarm threshold for the process parameter at the time of the event. Used to contextualise whether the actual_value breached the low alarm boundary.',
    `corrective_action` STRING COMMENT 'Description of the corrective action taken by the operator or maintenance team to resolve the operational exception and restore normal plant operations. Feeds maintenance knowledge base and SOP review processes.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this operational exception record was first created in the system. Audit trail field for data lineage and record provenance in the Databricks Silver Layer.',
    `detection_method` STRING COMMENT 'Method by which the operational exception was first detected: scada_alarm (automated SCADA/PLC alarm), operator_observation (manual observation by plant operator), dcs_alert (Distributed Control System alert), lab_result (assay or process sample result), inspection (physical inspection finding), predictive_alert (predictive maintenance or process analytics alert).. Valid values are `scada_alarm|operator_observation|dcs_alert|lab_result|inspection|predictive_alert`',
    `deviation_magnitude` DECIMAL(18,2) COMMENT 'Absolute difference between actual_value and setpoint_value at the time of the exception. Stored as a business field to support process control quality analysis and trend reporting without requiring arithmetic on raw values.',
    `duration_minutes` DECIMAL(18,2) COMMENT 'Total elapsed duration of the operational exception in minutes, calculated from event_start_timestamp to event_end_timestamp. Stored as a business field to support OEE (Overall Equipment Effectiveness) availability loss reporting without requiring real-time timestamp arithmetic.',
    `event_category` STRING COMMENT 'Operational category of the exception cause: mechanical (equipment failure), electrical (power or instrumentation fault), process (reagent, slurry, or chemistry issue), planned_maintenance (scheduled shutdown), feed_shortage (insufficient ROM feed), or parameter_exceedance (process variable breach). Drives OEE loss categorisation and maintenance domain routing.. Valid values are `mechanical|electrical|process|planned_maintenance|feed_shortage|parameter_exceedance`',
    `event_end_timestamp` TIMESTAMP COMMENT 'Date and time when the operational exception event was resolved and normal operations resumed. Null if the event is still active. Used with event_start_timestamp to calculate event duration.',
    `event_reference` STRING COMMENT 'Human-readable business identifier for the operational exception event, used for cross-referencing with maintenance work orders, shift reports, and process control logs. Format: OE-{YYYY}-{NNNNNN}.. Valid values are `^OE-[0-9]{4}-[0-9]{6}$`',
    `event_start_timestamp` TIMESTAMP COMMENT 'Date and time when the operational exception event commenced, as recorded by the SCADA/PLC system or operator. This is the principal real-world event time used for duration calculation and OEE loss attribution.',
    `event_status` STRING COMMENT 'Current lifecycle status of the operational exception record: open (event active, investigation pending), in_progress (corrective action underway), resolved (root cause identified and corrective action completed), closed (verified and signed off), cancelled (duplicate or incorrectly raised).. Valid values are `open|in_progress|resolved|closed|cancelled`',
    `event_type` STRING COMMENT 'Classification of the operational exception by its fundamental nature: downtime (equipment or circuit stoppage), parameter_deviation (process variable outside set-point tolerance), alarm (SCADA/PLC alarm triggered), near_miss (safety or process near-miss), or process_upset (uncontrolled process condition). [ENUM-REF-CANDIDATE: downtime|parameter_deviation|alarm|near_miss|process_upset — promote to reference product if additional types are required]. Valid values are `downtime|parameter_deviation|alarm|near_miss|process_upset`',
    `hse_incident_raised` BOOLEAN COMMENT 'Indicates whether this operational exception also triggered a formal HSE incident report in the IsoMetrix system (True) or not (False). Enables cross-domain linkage between process exceptions and HSE incident management.',
    `immediate_action` STRING COMMENT 'Description of the immediate containment action taken at the time of the exception to prevent further production loss, equipment damage, or safety risk, prior to full corrective action. Distinct from corrective_action which addresses root cause.',
    `is_planned` BOOLEAN COMMENT 'Indicates whether the downtime or exception event was planned (True) or unplanned (False). Planned events include scheduled maintenance shutdowns and planned feed stoppages. Used to segregate planned vs unplanned downtime in OEE calculations.',
    `oee_loss_category` STRING COMMENT 'OEE loss category to which this exception is attributed for OEE calculation purposes: availability (equipment or circuit not running), performance (running below rated throughput), or quality (product not meeting grade specification). Aligns with ISO 22400 OEE decomposition.. Valid values are `availability|performance|quality`',
    `parameter_description` STRING COMMENT 'Human-readable description of the process parameter that deviated, providing context beyond the SCADA tag code. Examples: SAG Mill Feed Rate (tph), Flotation Cell Level (%), Leach Tank pH.',
    `parameter_tag` STRING COMMENT 'The OSIsoft PI System or SCADA tag identifier for the process parameter that deviated from its set-point. Applicable only for event_type = parameter_deviation or alarm. Examples: SAG_MILL_FEED_TPH, FLOTATION_CELL_LEVEL_PCT, LEACH_TANK_PH.',
    `parameter_unit` STRING COMMENT 'Engineering unit of measure for the process parameter set-point and actual values. Examples: tph (tonnes per hour), %, pH, m3/h, kPa, degC, g/L. Ensures correct interpretation of setpoint_value and actual_value.',
    `production_loss_tonnes` DECIMAL(18,2) COMMENT 'Estimated ore or concentrate production lost in dry metric tonnes as a direct consequence of this operational exception. Used for OEE production loss attribution, LOM plan variance reporting, and OPEX impact quantification.',
    `root_cause_code` STRING COMMENT 'Standardised code classifying the root cause of the exception per the plants failure taxonomy (e.g., ISO 14224 cause codes). Enables structured root cause analysis and trend reporting across events.',
    `root_cause_description` STRING COMMENT 'Detailed narrative description of the identified root cause of the operational exception, as determined through investigation. Supports root cause analysis (RCA), recurring failure identification, and process improvement initiatives.',
    `setpoint_value` DECIMAL(18,2) COMMENT 'The target or set-point value for the process parameter at the time of the deviation event. Used in conjunction with actual_value to quantify the magnitude of the deviation. Applicable for event_type = parameter_deviation.',
    `severity` STRING COMMENT 'Severity rating of the operational exception indicating its impact on plant throughput, safety, and production targets. Critical: full circuit or plant stoppage; High: significant throughput reduction; Medium: partial degradation; Low: minor deviation with negligible production impact.. Valid values are `critical|high|medium|low`',
    `shift_date` DATE COMMENT 'Calendar date of the shift during which the operational exception commenced. Used for daily and shift-level production reporting and exception trend analysis.',
    `shift_type` STRING COMMENT 'Type of shift during which the operational exception occurred: day, night, or afternoon. Supports shift-level performance analysis and identification of shift-specific exception patterns.. Valid values are `day|night|afternoon`',
    `throughput_loss_tph` DECIMAL(18,2) COMMENT 'Estimated reduction in processing throughput rate in tonnes per hour (tph) attributable to this exception event. Supports OEE rate loss analysis and process bottleneck identification.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this operational exception record was most recently modified, such as when root cause, corrective action, or resolution details were updated. Supports audit trail and data currency tracking.',
    CONSTRAINT pk_operational_exception PRIMARY KEY(`operational_exception_id`)
) COMMENT 'Transactional record of operational exceptions within the processing plant including unplanned/planned downtime events and process parameter deviations from set-point targets. Captures event type (downtime, parameter_deviation, alarm), start/end timestamps, duration, affected circuit, category (mechanical, electrical, process, planned maintenance, feed shortage, parameter exceedance), severity, set-point vs actual values for deviations, root cause description, corrective action taken, responsible operator, and production loss (tonnes). Feeds OEE calculation, process control quality analysis, root cause investigation, and maintenance domain work order linkage.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`concentrate_stockpile` (
    `concentrate_stockpile_id` BIGINT COMMENT 'Unique surrogate identifier for each concentrate stockpile inventory record in the processing domain. Primary key for this entity.',
    `assay_result_id` BIGINT COMMENT 'Foreign key linking to laboratory.assay_result. Business justification: Concentrate stockpile inventory management requires certified assay results for grade tracking, blending decisions, and shipment nomination. The last_assay_date plain attribute signals this dependency',
    `blend_id` BIGINT COMMENT 'Foreign key linking to product.blend. Business justification: Concentrate stockpiles are built to achieve a specific blend specification before shipment. The blend product defines target grade and component ratios for the stockpile. blend_target_grade is a denor',
    `cargo_shipment_id` BIGINT COMMENT 'Foreign key linking to sales.cargo_shipment. Business justification: Cargo shipments draw concentrate from stockpiles for vessel loading. Inventory reconciliation, demurrage management, and loading rate optimization require tracking which stockpile feeds each shipment.',
    `circuit_id` BIGINT COMMENT 'Foreign key linking to processing.circuit. Business justification: Concentrate stockpiles receive product from specific processing circuits (e.g., flotation circuit, SX-EW circuit). Linking concentrate_stockpile to circuit enables circuit-level inventory tracking and',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Stockpiles hold specific commodities (iron ore concentrate, copper concentrate). Fundamental for inventory management, blending decisions, and production reconciliation. Replaces denormalized commodit',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Stockpile inventory is valued and tracked against cost centres for balance sheet reporting (IAS 2 inventory), NRV testing, and working capital management. Links physical inventory to financial asset a',
    `lom_plan_id` BIGINT COMMENT 'Reference to the Life of Mine (LOM) plan against which this stockpile inventory is tracked for production target reconciliation.',
    `offtake_schedule_id` BIGINT COMMENT 'Foreign key linking to sales.offtake_schedule. Business justification: Stockpile readiness management is a named mining logistics process: concentrate stockpiles are built and managed against specific offtake schedule liftings. Port and logistics teams need to know which',
    `plant_id` BIGINT COMMENT 'Reference to the processing plant or facility that produced or holds this concentrate stockpile. Links to the plant master record.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Concentrate stockpiles track inventory against scheduled production for shipment planning, metal accounting, and working capital management. Critical for sales contract fulfillment and financial repor',
    `profit_centre_id` BIGINT COMMENT 'Foreign key linking to finance.profit_centre. Business justification: Concentrate stockpiles represent finished goods inventory on the balance sheet. Profit centre assignment is required for period-end inventory valuation, IFRS inventory reporting, and segment asset dis',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Stockpiles contain specific saleable products awaiting dispatch. Essential for sales order fulfillment, inventory valuation, and linking physical inventory to sales contracts. Standard in mining logis',
    `shipment_nomination_id` BIGINT COMMENT 'Foreign key linking to sales.shipment_nomination. Business justification: Shipment nominations allocate specific stockpile inventory to customer orders and vessel schedules. Logistics planning, inventory management, and customer delivery commitments depend on linking nomina',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Royalty accrual and regulatory reporting require concentrate stockpile inventory to be attributed to the source tenement. Royalty obligations are calculated per tenement; stockpile records without ten',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Concentrate stockpiles are managed to meet a specific product specification before shipment nomination. Blending and inventory decisions are driven by specification limits. min_grade_spec and max_mois',
    `warehouse_location_id` BIGINT COMMENT 'Foreign key linking to procurement.warehouse_location. Business justification: Concentrate stockpiles are physical storage locations requiring warehouse management for inventory reconciliation, site access control, environmental compliance, and security. Links processing output ',
    `additions_dmt` DECIMAL(18,2) COMMENT 'Cumulative dry metric tonnes of concentrate added to this stockpile from production since the last inventory reconciliation period. Represents inflows from the processing circuit (e.g., flotation, leaching, SX-EW). Used in mass balance and inventory reconciliation.',
    `concentrate_type` STRING COMMENT 'Mineralogical classification of the concentrate product in this stockpile. Determines applicable processing routes, smelter penalty elements, and sales contract terms. E.g., sulphide concentrate from flotation vs oxide concentrate from leaching/SX-EW.. Valid values are `sulphide|oxide|mixed|hydroxide|carbonate|other`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this concentrate stockpile record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for record provenance and data lineage.',
    `dust_suppression_applied` BOOLEAN COMMENT 'Indicates whether dust suppression measures (e.g., water sprays, chemical binders, covers) are currently applied to this stockpile. Relevant for environmental compliance, HSE reporting, and community impact management.',
    `grade_element` STRING COMMENT 'Chemical element or compound symbol for which the product_grade is reported (e.g., Cu for copper, Fe for iron, Li2O for lithium oxide, Ni for nickel). Ensures unambiguous interpretation of the grade value across commodities.. Valid values are `^[A-Za-z0-9]{1,10}$`',
    `inventory_dmt` DECIMAL(18,2) COMMENT 'Current physical inventory of concentrate in the stockpile expressed as dry metric tonnes (DMT), adjusted for moisture content. This is the primary inventory quantity used for sales nominations, shipping calculations, and inventory reconciliation. Updated after each survey event.',
    `inventory_wmt` DECIMAL(18,2) COMMENT 'Current physical inventory of concentrate in the stockpile expressed as wet metric tonnes (WMT), inclusive of moisture. Used for physical handling, transport weight calculations, and logistics planning. Distinct from DMT which is the commercial quantity.',
    `is_shipment_nominated` BOOLEAN COMMENT 'Indicates whether this stockpile inventory has been nominated against an active shipment or vessel loading schedule. True = nominated for an upcoming shipment; False = available for future nomination. Supports logistics scheduling and sales operations.',
    `is_under_environmental_hold` BOOLEAN COMMENT 'Indicates whether this stockpile is subject to an environmental hold that restricts movement or shipment of material (e.g., pending EIS review, acid rock drainage concern, or regulatory compliance investigation). True = hold in place; False = no environmental restriction.',
    `last_assay_date` DATE COMMENT 'Date of the most recent laboratory assay used to determine the current product grade and moisture content of the stockpile. Used to assess grade data currency for sales nominations and blend optimisation.',
    `last_survey_date` DATE COMMENT 'Date of the most recent physical survey or measurement used to determine the current stockpile inventory volume and tonnage. Critical for assessing inventory data currency and triggering re-survey workflows when data is stale.',
    `lom_inventory_target_dmt` DECIMAL(18,2) COMMENT 'Target concentrate inventory level in dry metric tonnes as specified in the Life of Mine (LOM) plan for the current period. Used to assess inventory performance against plan and trigger production rate adjustments.',
    `max_capacity_dmt` DECIMAL(18,2) COMMENT 'Engineered maximum storage capacity of the stockpile expressed in dry metric tonnes (DMT). Used for capacity planning, logistics scheduling, and triggering production rate adjustments when inventory approaches capacity limits.',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Current moisture content of the concentrate stockpile expressed as a percentage of wet weight. Used to convert between WMT and DMT, assess handleability, and ensure compliance with shipping moisture limits (e.g., transportable moisture limit for bulk cargo under IMSBC Code).',
    `nominated_shipment_dmt` DECIMAL(18,2) COMMENT 'Quantity of concentrate in dry metric tonnes nominated against an active shipment or vessel loading schedule from this stockpile. Enables available-to-nominate calculation (inventory_dmt minus nominated_shipment_dmt) for logistics planning.',
    `opening_inventory_dmt` DECIMAL(18,2) COMMENT 'Dry metric tonne inventory at the start of the current reconciliation period. Together with additions_dmt and removals_dmt, enables closing inventory calculation and mass balance closure verification.',
    `penalty_element_flags` STRING COMMENT 'Comma-separated list of penalty elements detected in the concentrate above contractual threshold levels (e.g., As,Pb,Bi). Penalty elements attract price deductions in smelter contracts and may trigger quarantine or blending requirements. Sourced from LabWare LIMS assay results.',
    `product_grade` DECIMAL(18,2) COMMENT 'Current assay-derived grade of the valuable mineral in the concentrate stockpile, expressed as a percentage (%). Represents the weighted average grade of all material currently in the stockpile based on the most recent survey or assay. Critical for sales nomination and blend optimisation.',
    `reconciliation_period_end` DATE COMMENT 'End date of the current inventory reconciliation period for which additions_dmt and removals_dmt are accumulated. Nullable if the period is still open.',
    `reconciliation_period_start` DATE COMMENT 'Start date of the current inventory reconciliation period for which additions_dmt and removals_dmt are accumulated. Aligns with metallurgical balance accounting periods for mass balance closure.',
    `removals_dmt` DECIMAL(18,2) COMMENT 'Cumulative dry metric tonnes of concentrate removed from this stockpile for shipment, blending, or transfer since the last inventory reconciliation period. Represents outflows to logistics, port, or downstream processing. Used in mass balance and inventory reconciliation.',
    `stockpile_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this stockpile location, used in logistics scheduling, sales nominations, and inventory reconciliation reports. Sourced from SAP MM material document or plant layout register.. Valid values are `^[A-Z0-9_-]{3,20}$`',
    `stockpile_name` STRING COMMENT 'Human-readable descriptive name of the concentrate stockpile (e.g., Plant Pad A — Copper Concentrate, Port Shed 3 — Iron Ore Fines). Used in operational dashboards and logistics communications.',
    `stockpile_notes` STRING COMMENT 'Free-text operational notes recorded by the metallurgist or inventory controller regarding this stockpile, such as quality observations, blending instructions, survey anomalies, or logistics constraints. Supports operational decision-making and audit trail.',
    `stockpile_status` STRING COMMENT 'Current operational lifecycle status of the stockpile. active = receiving or dispatching material; inactive = temporarily not in use; full = at maximum capacity; quarantine = material held pending quality resolution; closed = permanently decommissioned.. Valid values are `active|inactive|full|quarantine|closed`',
    `survey_method` STRING COMMENT 'Method used to measure the current stockpile volume and derive inventory tonnage. Determines accuracy and frequency of inventory updates. Values: drone_lidar (aerial LiDAR scan), drone_photogrammetry (aerial photogrammetric survey), manual_survey (ground-based manual measurement), belt_scale (continuous belt weigher), weightometer (in-line weightometer), laser_scan (fixed laser scanner).. Valid values are `drone_lidar|drone_photogrammetry|manual_survey|belt_scale|weightometer|laser_scan`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this concentrate stockpile record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change tracking, data freshness monitoring, and incremental ETL processing in the Databricks Silver layer.',
    CONSTRAINT pk_concentrate_stockpile PRIMARY KEY(`concentrate_stockpile_id`)
) COMMENT 'Inventory record of concentrate stockpiles at processing plant pad and port storage facilities — the processing-domain view of physical inventory. Captures stockpile ID, location (plant pad, port shed, rail siding), commodity type, current inventory (dmt), grade (%), moisture (%), date of last survey (drone/LIDAR/manual), maximum capacity (dmt), and stockpile movement history (additions from production, removals for shipment). Supports logistics scheduling, sales nomination, blend optimisation, and inventory reconciliation. Note: this product owns the physical/operational stockpile state; commercial inventory positions, title transfer, and financial valuation are managed in the product and sales domains.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`process_sample` (
    `process_sample_id` BIGINT COMMENT 'Unique surrogate identifier for each process sample record in the processing plant metallurgical accounting system.',
    `ard_assessment_id` BIGINT COMMENT 'Foreign key linking to tailings.ard_assessment. Business justification: Process samples from tailings streams are the primary input to ARD (Acid Rock Drainage) assessments — a mandatory environmental compliance requirement. Regulators require traceability from the process',
    `blast_execution_id` BIGINT COMMENT 'Foreign key linking to mine.blast_execution. Business justification: Mine-to-mill reconciliation (F1/F2/F3 factors) requires tracing process samples back to the originating blast event. This is a standard mining industry practice — metallurgists and mine planners use b',
    `circuit_id` BIGINT COMMENT 'Reference to the specific processing circuit (e.g., SAG mill circuit, flotation circuit, leach circuit) within the plant from which the sample was collected.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Process samples assay specific commodities for grade control and metallurgical accounting. Core to quality control, mass balance reconciliation, and production reporting. Domain experts expect commodi',
    `concentrate_batch_id` BIGINT COMMENT 'Foreign key linking to processing.concentrate_batch. Business justification: Process samples are collected from concentrate batches for quality assurance and grade verification. Linking process_sample to concentrate_batch enables direct traceability from quality samples to the',
    `exploration_sample_id` BIGINT COMMENT 'Foreign key linking to exploration.exploration_sample. Business justification: Mine-to-mill reconciliation explicitly compares process plant samples against exploration samples from the same ore source to validate grade prediction accuracy. Metallurgical reconciliation reports a',
    `feed_stream_id` BIGINT COMMENT 'Foreign key linking to processing.feed_stream. Business justification: Process samples are collected at defined sampling points within the processing plant, including feed stream sampling points (ROM feed, crushed feed, recirculating loads). Linking process_sample to fee',
    `geological_domain_id` BIGINT COMMENT 'Foreign key linking to geology.geological_domain. Business justification: Process samples are collected and characterised by ore_type for metallurgical accounting. Reconciling process sample head_grade against geological domain grade predictions is a core metallurgical acco',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Each process sample is analyzed for a specific grade parameter (Cu%, Fe%, SiO2%). Linking enables LIMS integration and ensures samples reference the correct parameter definition, unit of measure, and ',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Sampling activities involve exposure risks (dust inhalation, chemical contact, confined space entry). Incidents during sampling (exposure events, equipment failures, sample spills) need direct linkage',
    `lom_plan_id` BIGINT COMMENT 'Reference to the Life of Mine (LOM) plan against which this samples grade and recovery data is reconciled, supporting JORC-compliant resource and reserve reporting.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Process samples collected during maintenance activities (oil analysis, wear liner sampling, post-repair metallurgical checks) must be linked to the triggering work order for traceability and cost allo',
    `metallurgical_balance_id` BIGINT COMMENT 'Reference to the metallurgical balance period to which this sample contributes, supporting JORC-compliant mass balance closure and reconciliation.',
    `mining_block_id` BIGINT COMMENT 'Foreign key linking to mine.mining_block. Business justification: Process samples reconcile against mining block model grades for resource model validation and geological domain characterization. Essential for F1/F2/F3 factor calculation and continuous improvement o',
    `orebody_id` BIGINT COMMENT 'Foreign key linking to geology.orebody. Business justification: Process samples are linked to source orebody for metallurgical accounting and grade reconciliation. Fundamental to mine-to-mill value chain tracking, validating geological models against actual proces',
    `plant_id` BIGINT COMMENT 'Reference to the processing plant facility where the sample was collected. Links to the plant master record.',
    `rom_stockpile_id` BIGINT COMMENT 'Foreign key linking to mine.rom_stockpile. Business justification: Process samples validate ROM stockpile grade estimates for feed blending, grade control, and stockpile inventory reconciliation. Essential for closing the loop between stockpile survey grades and actu',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Process samples are collected during a production shift run. One sample belongs to one shift run; one shift run has many samples. This links the sample to the processing domains shift entity.',
    `shift_report_id` BIGINT COMMENT 'Reference to the production shift during which the sample was collected, enabling shift-level metallurgical accounting and reconciliation.',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: Process samples are collected and analyzed against a target product specification to determine conformance for dispatch approval. QAQC and quality hold decisions depend on whether the sample meets the',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Tailings samples (stream_type=tailings) collected from specific TSF for quality control and environmental monitoring. QA/QC requirement for TSF geochemical characterization, ARD assessment, and regu',
    `unit_operation_event_id` BIGINT COMMENT 'Foreign key linking to processing.unit_operation_event. Business justification: Process samples are collected at defined sampling points during specific unit operations (e.g., flotation feed sample, leach discharge sample). Linking process_sample to unit_operation_event provides ',
    `collection_timestamp` TIMESTAMP COMMENT 'Date and time at which the process sample was physically collected at the sampling point. This is the principal real-world event time used for time-series analysis and metallurgical accounting period assignment.',
    `composite_end_timestamp` TIMESTAMP COMMENT 'End time of the compositing period for composite samples, defining the close of the time window over which increments were collected. Null for grab or incremental samples.',
    `composite_start_timestamp` TIMESTAMP COMMENT 'Start time of the compositing period for composite samples, defining the beginning of the time window over which increments were collected. Null for grab or incremental samples.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time at which this process sample record was first created in the system, providing the audit trail creation marker for data lineage and compliance.',
    `dispatch_status` STRING COMMENT 'Current dispatch status of the prepared sample to the analytical laboratory, tracking the chain of custody from plant to laboratory.. Valid values are `pending|dispatched|in_transit|received_by_lab|cancelled`',
    `dispatch_timestamp` TIMESTAMP COMMENT 'Date and time at which the prepared sample was physically dispatched to the analytical laboratory. Null if not yet dispatched.',
    `head_grade` DECIMAL(18,2) COMMENT 'Assayed grade of the primary element in the sample, expressed in the unit defined by head_grade_unit. For feed samples this is the head grade; for concentrate or tailings samples this is the stream grade. Populated after laboratory analysis.',
    `head_grade_unit` STRING COMMENT 'Unit of measure for the head_grade value: pct = percentage (%), g_per_t = grams per tonne, ppm = parts per million, ppb = parts per billion, kg_per_t = kilograms per tonne.. Valid values are `pct|g_per_t|ppm|ppb|kg_per_t`',
    `increment_count` STRING COMMENT 'Number of individual increments combined to form a composite sample. Used to assess sampling representativeness per Theory of Sampling (TOS). Null for grab samples.',
    `is_representative` BOOLEAN COMMENT 'Indicates whether the sample has been assessed as representative of the process stream for metallurgical accounting purposes. False samples are excluded from mass balance calculations.',
    `mass_dry_g` DECIMAL(18,2) COMMENT 'Dry mass of the sample in grams after moisture removal during preparation. Used for dry-basis grade calculations and metallurgical accounting.',
    `mass_wet_g` DECIMAL(18,2) COMMENT 'Total wet mass of the collected sample in grams as weighed at the sampling point prior to preparation. Used for mass balance calculations and sample representativeness assessment.',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content of the sample expressed as a percentage of wet mass, determined during sample preparation. Critical for converting wet-basis to dry-basis metallurgical accounting figures.',
    `ore_type` STRING COMMENT 'Mineralogical classification of the ore represented by the sample, used for metallurgical performance benchmarking and LOM plan reconciliation. Oxide, sulphide, mixed, transitional, and fresh rock types exhibit different processing behaviour.. Valid values are `oxide|sulphide|mixed|transitional|fresh`',
    `particle_size_p80_um` DECIMAL(18,2) COMMENT '80th percentile passing particle size of the sample in micrometres (P80), characterising the grind size at the sampling point. Key comminution performance indicator for SAG and ball mill circuit control.',
    `preparation_method` STRING COMMENT 'Laboratory preparation method applied to the sample prior to assay, defining the comminution and splitting protocol. [ENUM-REF-CANDIDATE: crush_split|riffle_split|rotary_split|pulverise|filter_dry|evaporate|none — promote to reference product if additional methods required]',
    `preparation_timestamp` TIMESTAMP COMMENT 'Date and time at which sample preparation was completed in the sample preparation facility, marking readiness for dispatch to the laboratory.',
    `pulp_density_pct_solids` DECIMAL(18,2) COMMENT 'Percentage solids by mass of the slurry at the sampling point, measured at time of collection. Relevant for slurry and pulp samples; null for dry ore samples.',
    `qaqc_flag` STRING COMMENT 'Quality Assurance and Quality Control (QAQC) classification of the sample: routine = standard production sample; blank = contamination check; standard = certified reference material for accuracy check; duplicate = laboratory duplicate for precision check; field_duplicate = field duplicate for sampling precision.. Valid values are `routine|blank|standard|duplicate|field_duplicate`',
    `rejection_reason` STRING COMMENT 'Free-text description of the reason a sample was rejected or flagged as non-representative, such as contamination, insufficient mass, sampler malfunction, or chain of custody breach. Null if sample is valid.',
    `sample_medium` STRING COMMENT 'Physical state or medium of the sample at the point of collection, distinguishing between slurry (wet ore/water mixture), dry ore, concentrate, leach solution (PLS), or pulp.. Valid values are `slurry|dry_ore|concentrate|solution|pulp`',
    `sample_notes` STRING COMMENT 'Free-text field for additional observations recorded by the sampler or metallurgist at the time of collection or preparation, such as unusual process conditions, equipment anomalies, or visual observations.',
    `sample_number` STRING COMMENT 'Externally-known, human-readable unique sample identifier assigned at collection, used for tracking through preparation, dispatch, and laboratory assay. Corresponds to the sample barcode or label number in LabWare LIMS.',
    `sample_status` STRING COMMENT 'Current lifecycle status of the process sample tracking its workflow from collection through laboratory analysis. [ENUM-REF-CANDIDATE: collected|prepared|dispatched|received|analysed|rejected — promote to reference product if additional statuses required]. Valid values are `collected|prepared|dispatched|received|analysed|rejected`',
    `sample_type` STRING COMMENT 'Method by which the sample was collected: Composite = time or mass-proportional blend of multiple increments; Grab = single point-in-time collection; Incremental = single cut from a cross-stream sampler; Automatic = collected by automated sampler; Manual = collected by operator.. Valid values are `composite|grab|incremental|automatic|manual`',
    `sampler_type` STRING COMMENT 'Type of sampling device or method used to collect the sample: manual (operator-collected), automatic (automated cross-stream sampler), cross_belt, vezin (rotary cutter), or pipe_cross_cut. Affects representativeness assessment per TOS.. Valid values are `manual|automatic|cross_belt|vezin|pipe_cross_cut`',
    `sampling_point_code` STRING COMMENT 'Standardised code identifying the defined sampling point within the processing plant where the sample was collected (e.g., SAG_FEED, FLOAT_CONC, FLOAT_TAIL, CIL_FEED, LEACH_PLS). Corresponds to OSIsoft PI tag location.',
    `sampling_point_description` STRING COMMENT 'Human-readable description of the sampling point location within the processing circuit (e.g., SAG Mill Discharge Screen Oversize, Rougher Flotation Concentrate Launder).',
    `stream_type` STRING COMMENT 'Classification of the process stream from which the sample was collected, indicating its position in the beneficiation flowsheet. Feed = ROM or circuit input; Concentrate = upgraded product stream; Tailings = waste stream; Intermediate = mid-circuit stream; Product = final saleable product; Recycle = recirculating load.. Valid values are `feed|concentrate|tailings|intermediate|product|recycle`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time at which this process sample record was last modified, supporting data lineage, audit trail, and change tracking requirements.',
    CONSTRAINT pk_process_sample PRIMARY KEY(`process_sample_id`)
) COMMENT 'Record of process samples collected at defined sampling points within the processing plant for metallurgical accounting, quality control, and grade reconciliation. Captures sample ID, sampling point (feed, concentrate, tailings, intermediate stream), collection timestamp, sample type (composite, grab, incremental), mass (g), preparation method, and dispatch status to laboratory. Links to laboratory domain for assay results via sample ID. Supports JORC-compliant metallurgical accounting and process control.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`plant_utility_consumption` (
    `plant_utility_consumption_id` BIGINT COMMENT 'Primary key for plant_utility_consumption',
    `circuit_id` BIGINT COMMENT 'Identifier of the specific processing circuit (e.g., SAG mill, flotation, leaching, SX-EW) for which utility consumption is recorded. Enables circuit-level OPEX benchmarking.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Electricity, water, and gas consumption are major opex line items in processing. Cost centre assignment on each utility consumption record is required for GL posting, AISC energy cost component report',
    `environmental_permit_id` BIGINT COMMENT 'Foreign key linking to hse.environmental_permit. Business justification: Water and energy consumption records must be reconciled against environmental permit licence limits for regulatory compliance reporting. The denormalized water_licence_limit_m3 and water_licence_compl',
    `general_ledger_account_id` BIGINT COMMENT 'Foreign key linking to finance.general_ledger_account. Business justification: Utility costs (power, water, gas) are posted to specific GL accounts for financial reporting. Direct GL account reference on utility consumption records enables automated journal posting, cost element',
    `lom_plan_id` BIGINT COMMENT 'Reference to the Life of Mine (LOM) plan version against which utility consumption targets and budgets are benchmarked. Supports variance analysis against LOM plan targets.',
    `metallurgical_balance_id` BIGINT COMMENT 'Foreign key linking to processing.metallurgical_balance. Business justification: Plant utility consumption (electricity, water, compressed air) is recorded per circuit per shift and feeds into the metallurgical balance for energy and water intensity calculations. Linking plant_uti',
    `plant_id` BIGINT COMMENT 'Identifier of the mineral processing plant where utility consumption was recorded. Links to the plant master record.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Utility consumption must be tracked against production schedules for cost allocation, energy intensity benchmarking, and carbon accounting. Essential for AISC calculation and Scope 1/2 emissions repor',
    `regulatory_condition_id` BIGINT COMMENT 'Foreign key linking to tenement.regulatory_condition. Business justification: Water licence limits and environmental conditions on tenements directly govern plant utility consumption. plant_utility_consumption already tracks water_licence_compliance_flag and water_licence_limit',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Utility consumption is recorded per shift run. One consumption record belongs to one shift run; one shift run has many consumption records. This links the utility consumption to the processing domain',
    `shift_report_id` BIGINT COMMENT 'Identifier of the production shift during which this utility consumption was recorded. Links to the shift production run record for operational context.',
    `shutdown_plan_id` BIGINT COMMENT 'Foreign key linking to maintenance.shutdown_plan. Business justification: Plant utility consumption (electricity, water, compressed air) during planned shutdowns must be attributed to the shutdown plan for AISC cost reporting and energy benchmarking. Mining finance and oper',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Plant utility consumption records track water drawn from and returned to the TSF. Water licence compliance requires reconciling plant water use (fresh_water_intake_m3, recycled_water_m3) against the T',
    `water_balance_id` BIGINT COMMENT 'Foreign key linking to tailings.water_balance. Business justification: Plant water consumption records must be reconciled against the TSF water balance for water licence compliance reporting. A direct FK enables automated reconciliation of plant-side water use (process_w',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the utility consumption record was approved by the authorised employee. Marks the record as locked for OPEX cost posting and environmental compliance reporting.',
    `carbon_budget_target_co2e_t` DECIMAL(18,2) COMMENT 'Approved carbon budget allocation for this circuit and period in tonnes of CO₂ equivalent (tCO₂e), derived from the LOM plan carbon budget. Used to calculate emissions variance and compliance status.',
    `compressed_air_consumption_m3` DECIMAL(18,2) COMMENT 'Volume of compressed air consumed by the circuit during the period in standard cubic metres (Sm³). Used for flotation cell aeration, instrumentation, and pneumatic equipment. Contributes to energy OPEX.',
    `consumption_reference` STRING COMMENT 'Externally-known business reference number for this utility consumption record, used for cross-referencing with SAP S/4HANA CO cost postings and OPEX reporting. Format: UC-YYYY-MM-NNNNNN.. Valid values are `^UC-[0-9]{4}-[0-9]{2}-[0-9]{6}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this utility consumption record was first created in the system, sourced from OSIsoft PI System historian ingestion or manual entry. Supports audit trail and data lineage.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary cost fields in this record (e.g., AUD, USD, ZAR). Ensures consistent currency context for OPEX reporting and financial consolidation.. Valid values are `^[A-Z]{3}$`',
    `data_source` STRING COMMENT 'Origin system or method by which utility consumption data was captured. PI System and SCADA sources are automated and high-confidence; manual_entry and estimated records require additional validation before use in regulatory reporting.. Valid values are `pi_system|scada|manual_entry|smart_meter|estimated`',
    `electricity_consumption_kwh` DECIMAL(18,2) COMMENT 'Total electrical energy consumed by the circuit during the period in kilowatt-hours (kWh), sourced from OSIsoft PI System metering data. Primary input for energy OPEX calculation and carbon footprint reporting.',
    `electricity_cost_total` DECIMAL(18,2) COMMENT 'Total monetary cost of electricity consumed during the period in the reporting currency, calculated as electricity_consumption_kwh multiplied by electricity_unit_cost plus applicable demand charges. Posted to SAP S/4HANA CO cost centre.',
    `electricity_unit_cost` DECIMAL(18,2) COMMENT 'Contracted or metered unit cost of electricity per kilowatt-hour ($/kWh) applicable to this period. Confidential commercial rate used for OPEX cost allocation and energy cost benchmarking.',
    `energy_target_kwh` DECIMAL(18,2) COMMENT 'Planned electrical energy consumption target for this circuit and period in kilowatt-hours (kWh), derived from the LOM plan energy budget. Used to calculate energy consumption variance for OPEX performance reporting.',
    `evaporation_loss_m3` DECIMAL(18,2) COMMENT 'Estimated volume of water lost to evaporation from open process vessels, ponds, and the TSF during the period in cubic metres (m³). Required for water balance closure and environmental reporting.',
    `fresh_water_intake_m3` DECIMAL(18,2) COMMENT 'Volume of fresh water drawn from licensed water sources (rivers, bores, municipal supply) into the processing plant during the period in cubic metres (m³). Reported against water licence limits for regulatory compliance.',
    `meter_reading_reference` STRING COMMENT 'Reference identifier for the physical or virtual meter reading(s) underpinning this consumption record, as recorded in OSIsoft PI System or the utility provider invoice. Supports audit trail and data lineage for regulatory submissions.',
    `natural_gas_consumption_gj` DECIMAL(18,2) COMMENT 'Volume of natural gas consumed by the circuit during the period in gigajoules (GJ), used for drying, heating, or on-site power generation. Input for Scope 1 greenhouse gas emissions calculation.',
    `notes` STRING COMMENT 'Free-text field for recording operational context, anomalies, meter faults, estimation methodology, or adjustment reasons relevant to this utility consumption record. Supports audit review and regulatory submissions.',
    `peak_demand_kw` DECIMAL(18,2) COMMENT 'Maximum instantaneous electrical power demand recorded during the period in kilowatts (kW). Used for utility tariff management, demand charge optimisation, and grid capacity planning.',
    `period_end_timestamp` TIMESTAMP COMMENT 'The real-world end date and time of the utility consumption measurement period. Used with period_start_timestamp to calculate duration and validate completeness of the consumption record.',
    `period_start_timestamp` TIMESTAMP COMMENT 'The real-world start date and time of the utility consumption measurement period. For shift records this aligns with shift start; for monthly records this is the first instant of the accounting month.',
    `period_type` STRING COMMENT 'Granularity of the consumption accounting period. Shift-level records are sourced from OSIsoft PI System historian; monthly records align with SAP S/4HANA CO accounting periods for OPEX reporting.. Valid values are `shift|daily|weekly|monthly`',
    `power_factor` DECIMAL(18,2) COMMENT 'Average power factor (ratio of real power to apparent power, dimensionless 0–1) for the circuit during the period. Low power factor incurs utility penalty charges and indicates reactive power inefficiency.',
    `process_water_consumption_m3` DECIMAL(18,2) COMMENT 'Total process water consumed within the circuit during the period (fresh intake plus recycled, minus discharge) in cubic metres (m³). Net water balance input for environmental reporting and water licence compliance.',
    `record_status` STRING COMMENT 'Current workflow lifecycle status of the utility consumption record. Draft records are pending submission; approved records are locked for OPEX and environmental reporting.. Valid values are `draft|submitted|approved|rejected|superseded`',
    `recycled_water_m3` DECIMAL(18,2) COMMENT 'Volume of process water recycled from the Tailings Storage Facility (TSF) and other internal sources back into the processing circuit during the period in cubic metres (m³). Supports water stewardship reporting and licence compliance.',
    `scope1_emissions_co2e_t` DECIMAL(18,2) COMMENT 'Direct greenhouse gas emissions from on-site combustion of natural gas or other fuels during the period in tonnes of CO₂ equivalent (tCO₂e). Supports carbon budget compliance and NGER/GRI reporting.',
    `scope2_emissions_co2e_t` DECIMAL(18,2) COMMENT 'Indirect greenhouse gas emissions from purchased electricity consumption during the period in tonnes of CO₂ equivalent (tCO₂e), calculated using applicable grid emission factors. Supports carbon budget compliance and GRI/NGER reporting.',
    `specific_energy_kwh_per_t` DECIMAL(18,2) COMMENT 'Electrical energy consumed per dry metric tonne of ore processed (kWh/t), calculated as electricity_consumption_kwh divided by tonnes_processed. Key comminution efficiency KPI benchmarked against LOM plan and AISC targets.',
    `specific_water_m3_per_t` DECIMAL(18,2) COMMENT 'Process water consumed per dry metric tonne of ore processed (m³/t). Key water efficiency metric benchmarked against LOM plan targets and water licence conditions.',
    `tonnes_processed` DECIMAL(18,2) COMMENT 'Dry metric tonnes of ore processed through the circuit during the period. Used as the denominator for calculating specific consumption rates (e.g., kWh/t, m³/t) for benchmarking and LOM plan variance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this utility consumption record was last modified. Tracks corrections, adjustments, and re-submissions for data lineage and audit compliance.',
    `water_cost_total` DECIMAL(18,2) COMMENT 'Total monetary cost of fresh water intake during the period in the reporting currency, including licence fees and supply charges. Posted to SAP S/4HANA CO cost centre for OPEX tracking.',
    CONSTRAINT pk_plant_utility_consumption PRIMARY KEY(`plant_utility_consumption_id`)
) COMMENT 'Transactional record of utility resource consumption per processing circuit per shift or accounting period. Covers electrical energy (kWh, kW peak demand, power factor, specific energy kWh/t), water balance (fresh water intake m³, recycled water m³, process water consumption m³/t, evaporation losses), compressed air, and other plant utilities. Captures circuit ID, shift date, consumption volumes, unit costs, and compliance metrics against water licence limits and carbon budgets. Supports OPEX tracking, environmental reporting (water stewardship, carbon footprint), energy efficiency benchmarking, and regulatory compliance against LOM plan targets.';

CREATE OR REPLACE TABLE `mining_ecm`.`processing`.`measurement_point` (
    `measurement_point_id` BIGINT COMMENT 'Primary key for measurement_point',
    `asset_id` BIGINT COMMENT 'Reference to the specific equipment or asset where the measurement instrument is installed (e.g., SAG mill, flotation cell, thickener).',
    `circuit_id` BIGINT COMMENT 'Foreign key linking to processing.circuit. Business justification: Measurement points (PI/SCADA sensors, flow meters, density gauges) are physically installed within specific processing circuits. Linking measurement_point to circuit enables circuit-level sensor inven',
    `grade_parameter_id` BIGINT COMMENT 'Foreign key linking to product.grade_parameter. Business justification: Measurement points in a processing plant measure specific grade parameters (e.g., a Cu grade analyzer measures the Cu grade parameter). Linking enables instrument-to-parameter traceability for LIMS in',
    `plant_id` BIGINT COMMENT 'Foreign key linking to processing.plant. Business justification: Measurement points are installed within a specific processing plant facility. A direct plant_id FK on measurement_point enables plant-level sensor inventory queries without requiring a join through ci',
    `pm_schedule_id` BIGINT COMMENT 'Foreign key linking to maintenance.pm_schedule. Business justification: Process measurement points (flow meters, density gauges, pH probes) have PM schedules governing calibration and inspection. Mining instrument technicians and reliability engineers manage calibration c',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.risk_assessment. Business justification: Critical control measurement points (is_critical_control_point=true) are defined through bow-tie risk assessments in mining process safety. Linking measurement_point to the risk_assessment that identi',
    `upstream_measurement_point_id` BIGINT COMMENT 'Self-referencing FK on measurement_point (upstream_measurement_point_id)',
    `accuracy` DECIMAL(18,2) COMMENT 'Specified accuracy or tolerance of the measurement instrument, typically expressed as a percentage of full scale or absolute value.',
    `alarm_high` DECIMAL(18,2) COMMENT 'Upper warning alarm threshold indicating the measurement is approaching critical limits.',
    `alarm_high_high` DECIMAL(18,2) COMMENT 'Critical upper alarm threshold that triggers immediate operator intervention when exceeded.',
    `alarm_low` DECIMAL(18,2) COMMENT 'Lower warning alarm threshold indicating the measurement is approaching critical limits.',
    `alarm_low_low` DECIMAL(18,2) COMMENT 'Critical lower alarm threshold that triggers immediate operator intervention when breached.',
    `calibration_frequency_days` STRING COMMENT 'Required interval in days between instrument calibration activities to maintain measurement accuracy and compliance.',
    `control_system_tag` STRING COMMENT 'Tag identifier used in the distributed control system or SCADA system to reference this measurement point for real-time monitoring and control.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this measurement point record was first created in the master data system.',
    `data_quality_flag` STRING COMMENT 'Indicator of the current data quality status from the control system, reflecting instrument health and signal validity.',
    `historian_tag` STRING COMMENT 'Tag identifier used in the process historian system (e.g., OSIsoft PI, Aspen IP.21) for time-series data storage and retrieval.',
    `installation_date` DATE COMMENT 'Date when the measurement instrument was physically installed and commissioned at this location.',
    `instrument_type` STRING COMMENT 'Classification of the measurement instrument or sensor technology used (e.g., magnetic flow meter, pressure transmitter, thermocouple, pH probe, laser particle size analyzer).',
    `is_critical_control_point` BOOLEAN COMMENT 'Indicates whether this measurement point is designated as a critical control point for process safety, environmental compliance, or production quality.',
    `is_kpi_input` BOOLEAN COMMENT 'Indicates whether this measurement point provides input data for calculating key performance indicators such as recovery rate, throughput, or product grade.',
    `last_calibration_date` DATE COMMENT 'Date when the instrument was last calibrated by maintenance or instrumentation technicians.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this measurement point record was most recently updated or modified.',
    `location_description` STRING COMMENT 'Detailed description of the physical location of the measurement point within the plant, including building, floor, and proximity references.',
    `manufacturer` STRING COMMENT 'Name of the manufacturer or vendor of the measurement instrument.',
    `measurement_point_name` STRING COMMENT 'Human-readable descriptive name of the measurement point indicating its location and purpose within the processing circuit.',
    `measurement_range_max` DECIMAL(18,2) COMMENT 'Upper bound of the instruments calibrated measurement range.',
    `measurement_range_min` DECIMAL(18,2) COMMENT 'Lower bound of the instruments calibrated measurement range.',
    `measurement_type` STRING COMMENT 'Category of physical or chemical property being measured at this point (e.g., flow, pressure, temperature, pH, density, particle size).',
    `model_number` STRING COMMENT 'Manufacturer model or part number of the measurement instrument.',
    `next_calibration_due_date` DATE COMMENT 'Scheduled date for the next required calibration activity based on the calibration frequency.',
    `notes` STRING COMMENT 'Free-text field for additional information, special considerations, or operational notes related to this measurement point.',
    `operational_status` STRING COMMENT 'Current operational state of the measurement point indicating whether it is actively collecting data, under maintenance, or out of service.',
    `responsible_department` STRING COMMENT 'Department or functional group responsible for maintaining and monitoring this measurement point (e.g., Process Control, Instrumentation, Metallurgy).',
    `sampling_frequency_seconds` STRING COMMENT 'Interval in seconds at which the measurement point captures and records data values.',
    `serial_number` STRING COMMENT 'Unique serial number assigned by the manufacturer to the specific instrument unit.',
    `tag_number` STRING COMMENT 'Unique alphanumeric tag identifier assigned to the measurement instrument following plant instrumentation standards (e.g., FT-SAG-001, PT-FLOT-205).',
    `target_value` DECIMAL(18,2) COMMENT 'Desired or optimal measurement value as defined by the process control strategy or Life of Mine (LOM) plan.',
    `unit_of_measure` STRING COMMENT 'Standard unit in which the measurement value is expressed (e.g., t/h, kPa, °C, %, g/L, µm, pH units).',
    CONSTRAINT pk_measurement_point PRIMARY KEY(`measurement_point_id`)
) COMMENT 'Master reference table for measurement_point. Referenced by measurement_point_id.';

